import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Não foi possível encontrar o elemento raiz para montar.");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ExtractedData {
  [key: string]: string | number | null;
}

export interface ProcessingResult {
  data: ExtractedData[];
  headers: string[];
  summary?: string;
}

export type FileType = 'pdf' | 'excel' | 'image' | 'text' | 'unknown';

export interface FileMetadata {
  name: string;
  size: number;
  type: FileType;
  raw: File;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ExtractedData, ProcessingResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const extractDataFromReport = async (
  prompt: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    Você é um especialista em extração e organização de dados de relatórios financeiros e administrativos.
    Sua tarefa é analisar o arquivo fornecido (PDF, Excel ou Imagem) e extrair os dados conforme as instruções do usuário.

    REGRAS CRÍTICAS:
    1. Retorne SEMPRE um objeto JSON com as chaves "data" (um array de objetos com os campos extraídos) e "summary" (uma breve descrição do que foi processado).
    2. Se o usuário pedir "nome e valor", crie chaves chamadas "Nome" e "Valor".
    3. Se o usuário pedir "CPF", crie uma chave chamada "CPF".
    4. Tente normalizar os dados (ex: remover símbolos de moeda se o valor for numérico, formatar CPF com pontos e traços).
    5. Se houver múltiplas páginas, processe todas elas para compor o array final.
    6. Se o arquivo for um Excel transformado em texto, entenda a estrutura tabular.
  `;

  const finalPrompt = `
    Instrução do Usuário: ${prompt}

    Conteúdo Adicional em Texto (se houver):
    ${textContent || 'Nenhum texto adicional.'}

    Por favor, extraia os dados agora.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: { 
        parts: [
          ...fileParts,
          { text: finalPrompt }
        ] 
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            data: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                // We use dynamic properties here
              }
            },
            summary: { type: Type.STRING }
          },
          required: ["data"]
        }
      }
    });

    const result = JSON.parse(response.text || '{}');
    const data: ExtractedData[] = result.data || [];

    // Extract headers from the first object
    const headers = data.length > 0 ? Object.keys(data[0]) : [];

    return {
      data,
      headers,
      summary: result.summary
    };
  } catch (error) {
    console.error("Erro ao processar com Gemini:", error);
    throw new Error("Falha ao processar o relatório. Verifique o arquivo e tente novamente.");
  }
};

import * as XLSX from 'xlsx';

export const fileToHash = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve(base64String);
    };
    reader.onerror = error => reject(error);
  });
};

export const parseExcel = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const data = new Uint8Array(e.target?.result as ArrayBuffer);
      const workbook = XLSX.read(data, { type: 'array' });
      let fullText = "";
      workbook.SheetNames.forEach(sheetName => {
        const worksheet = workbook.Sheets[sheetName];
        fullText += `\n--- Planilha: ${sheetName} ---\n`;
        fullText += XLSX.utils.sheet_to_txt(worksheet);
      });
      resolve(fullText);
    };
    reader.onerror = reject;
    reader.readAsArrayBuffer(file);
  });
};

// For PDF processing using pdf.js
export const pdfToImages = async (file: File): Promise<{ data: string; mimeType: string }[]> => {
  const arrayBuffer = await file.arrayBuffer();
  // @ts-ignore
  const pdfjsLib = window['pdfjs-dist/build/pdf'];
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';

  const pdf = await pdfjsLib.getDocument(arrayBuffer).promise;
  const imageParts: { data: string; mimeType: string }[] = [];

  // Limit to first 5 pages for performance and token limits
  const maxPages = Math.min(pdf.numPages, 5);

  for (let i = 1; i <= maxPages; i++) {
    const page = await pdf.getPage(i);
    const viewport = page.getViewport({ scale: 1.5 });
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    canvas.height = viewport.height;
    canvas.width = viewport.width;

    if (context) {
      await page.render({ canvasContext: context, viewport }).promise;
      const base64 = canvas.toDataURL('image/jpeg', 0.8).split(',')[1];
      imageParts.push({ data: base64, mimeType: 'image/jpeg' });
    }
  }

  return imageParts;
};

