import React, { useState, useCallback } from 'react';
import { 
  FileText, 
  Upload, 
  Search, 
  CheckCircle, 
  Download, 
  Trash2, 
  AlertCircle,
  Table as TableIcon,
  ChevronRight,
  FileSpreadsheet
} from 'lucide-react';
import * as XLSX from 'xlsx';

import { FileMetadata, ProcessingResult } from './types';
import { fileToBase64, parseExcel, pdfToImages } from './utils/fileUtils';
import { extractDataFromReport } from './services/geminiService';
import ProcessingAnimation from './components/ProcessingAnimation';

const App: React.FC = () => {
  const [file, setFile] = useState<FileMetadata | null>(null);
  const [instruction, setInstruction] = useState('Extrair nome e valor de cada item.');
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      let type: any = 'unknown';
      if (selectedFile.type.includes('pdf')) type = 'pdf';
      else if (selectedFile.type.includes('sheet') || selectedFile.name.endsWith('.xlsx') || selectedFile.name.endsWith('.xls')) type = 'excel';
      else if (selectedFile.type.includes('image')) type = 'image';
      else if (selectedFile.type.includes('text')) type = 'text';

      setFile({
        name: selectedFile.name,
        size: selectedFile.size,
        type,
        raw: selectedFile
      });
      setResult(null);
      setError(null);
    }
  };

  const handleProcess = async () => {
    if (!file) return;

    setIsProcessing(true);
    setError(null);

    try {
      let fileParts: { inlineData: { data: string; mimeType: string } }[] = [];
      let textContent = "";

      if (file.type === 'pdf') {
        fileParts = await pdfToImages(file.raw);
      } else if (file.type === 'excel') {
        textContent = await parseExcel(file.raw);
      } else if (file.type === 'image') {
        const base64 = await fileToBase64(file.raw);
        fileParts = [{ inlineData: { data: base64, mimeType: file.raw.type } }];
      } else if (file.type === 'text') {
        textContent = await file.raw.text();
      }

      const extractionResult = await extractDataFromReport(instruction, fileParts, textContent);
      setResult(extractionResult);
    } catch (err: any) {
      setError(err.message || 'Ocorreu um erro inesperado.');
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;
    const ws = XLSX.utils.json_to_sheet(result.data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Dados Extraídos");
    XLSX.writeFile(wb, `relatorio_organizado_${Date.now()}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center shadow-lg shadow-indigo-100">
              <TableIcon className="text-white w-6 h-6" />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">SmartReport</h1>
          </div>
          <div className="flex items-center gap-4">
             <span className="text-sm font-medium text-slate-500 bg-slate-100 px-3 py-1 rounded-full">
               IA Powerhouse
             </span>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-12">
        <section className="text-center mb-12">
          <h2 className="text-4xl font-extrabold text-slate-900 mb-4">
            Organize seus relatórios com IA
          </h2>
          <p className="text-lg text-slate-600 max-w-2xl mx-auto">
            Envie PDFs, planilhas ou fotos de documentos e diga o que você precisa extrair. 
            Nossa IA faz o trabalho pesado de organizar os dados para você.
          </p>
        </section>

        {/* Upload Zone */}
        {!result && !isProcessing && (
          <div className="grid grid-cols-1 md:grid-cols-1 gap-8">
            <div className="bg-white rounded-2xl shadow-xl shadow-slate-200 border border-slate-200 p-8">
              <div 
                className={`border-2 border-dashed rounded-xl p-10 flex flex-col items-center justify-center transition-all ${file ? 'border-green-400 bg-green-50' : 'border-slate-300 hover:border-indigo-400'}`}
              >
                {!file ? (
                  <>
                    <div className="w-16 h-16 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mb-4">
                      <Upload className="w-8 h-8" />
                    </div>
                    <p className="text-slate-800 font-semibold mb-1">Selecione seu relatório</p>
                    <p className="text-slate-500 text-sm mb-6">PDF, Excel ou Imagens (Máx. 5MB)</p>
                    <input 
                      type="file" 
                      className="hidden" 
                      id="file-upload" 
                      onChange={handleFileChange}
                      accept=".pdf,.xlsx,.xls,.png,.jpg,.jpeg"
                    />
                    <label 
                      htmlFor="file-upload" 
                      className="bg-indigo-600 text-white px-6 py-2.5 rounded-lg font-medium hover:bg-indigo-700 transition-colors cursor-pointer shadow-md"
                    >
                      Procurar Arquivo
                    </label>
                  </>
                ) : (
                  <div className="w-full flex items-center justify-between">
                    <div className="flex items-center gap-4">
                      <div className="w-12 h-12 bg-white rounded-lg border border-green-200 flex items-center justify-center text-green-600">
                        {file.type === 'pdf' ? <FileText /> : <FileSpreadsheet />}
                      </div>
                      <div className="text-left">
                        <p className="text-slate-900 font-bold line-clamp-1">{file.name}</p>
                        <p className="text-slate-500 text-xs uppercase tracking-widest">{file.type} • {(file.size / 1024).toFixed(1)} KB</p>
                      </div>
                    </div>
                    <button 
                      onClick={() => setFile(null)}
                      className="text-slate-400 hover:text-red-500 transition-colors p-2"
                    >
                      <Trash2 className="w-5 h-5" />
                    </button>
                  </div>
                )}
              </div>

              {file && (
                <div className="mt-8 space-y-4 animate-in fade-in slide-in-from-bottom-4">
                  <div className="text-left">
                    <label className="block text-sm font-bold text-slate-700 mb-2">
                      O que você quer extrair?
                    </label>
                    <textarea 
                      value={instruction}
                      onChange={(e) => setInstruction(e.target.value)}
                      placeholder="Ex: Deixar apenas nome, valor e CPF. Formatar valores como moeda brasileira."
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl p-4 text-slate-800 focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all outline-none min-h-[100px]"
                    />
                  </div>

                  <button 
                    onClick={handleProcess}
                    disabled={isProcessing}
                    className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold text-lg hover:bg-indigo-700 active:scale-[0.98] transition-all flex items-center justify-center gap-2 shadow-lg shadow-indigo-200"
                  >
                    Processar Relatório
                    <ChevronRight className="w-5 h-5" />
                  </button>
                </div>
              )}
            </div>
          </div>
        )}

        {isProcessing && <ProcessingAnimation />}

        {error && (
          <div className="bg-red-50 border border-red-200 rounded-xl p-6 flex items-start gap-4 text-red-700 mt-8">
            <AlertCircle className="w-6 h-6 shrink-0" />
            <div>
              <p className="font-bold">Ops! Algo deu errado.</p>
              <p className="text-sm opacity-90">{error}</p>
              <button 
                onClick={() => setIsProcessing(false)}
                className="mt-4 text-sm font-bold underline"
              >
                Tentar novamente
              </button>
            </div>
          </div>
        )}

        {/* Results Section */}
        {result && (
          <div className="space-y-6 animate-in fade-in zoom-in-95">
            <div className="flex items-center justify-between">
              <div>
                <h3 className="text-2xl font-bold text-slate-900">Relatório Organizado</h3>
                <p className="text-slate-500 text-sm">Dados extraídos com base na sua instrução.</p>
              </div>
              <div className="flex gap-2">
                <button 
                  onClick={() => {setResult(null); setError(null);}}
                  className="bg-white border border-slate-200 text-slate-600 px-4 py-2 rounded-lg font-medium hover:bg-slate-50 transition-colors flex items-center gap-2"
                >
                  Limpar
                </button>
                <button 
                  onClick={downloadExcel}
                  className="bg-green-600 text-white px-4 py-2 rounded-lg font-medium hover:bg-green-700 transition-colors flex items-center gap-2 shadow-md"
                >
                  <Download className="w-4 h-4" />
                  Baixar Excel
                </button>
              </div>
            </div>

            {result.summary && (
              <div className="bg-indigo-50 border border-indigo-100 rounded-xl p-4 text-indigo-800 text-sm italic">
                <strong>Resumo:</strong> {result.summary}
              </div>
            )}

            <div className="bg-white border border-slate-200 rounded-2xl shadow-xl overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse">
                  <thead>
                    <tr className="bg-slate-50 border-b border-slate-200">
                      {result.headers.map((header) => (
                        <th key={header} className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">
                          {header}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {result.data.map((row, idx) => (
                      <tr key={idx} className="hover:bg-slate-50 transition-colors">
                        {result.headers.map((header) => (
                          <td key={`${idx}-${header}`} className="px-6 py-4 text-sm text-slate-700 whitespace-nowrap">
                            {row[header]?.toString() || '-'}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
              {result.data.length === 0 && (
                <div className="p-12 text-center">
                  <Search className="w-12 h-12 text-slate-300 mx-auto mb-4" />
                  <p className="text-slate-500 font-medium">Nenhum dado encontrado com os critérios fornecidos.</p>
                </div>
              )}
            </div>

            <div className="text-center pt-8">
              <button 
                onClick={() => {setResult(null); setFile(null);}}
                className="text-indigo-600 font-bold hover:underline"
              >
                ← Carregar outro arquivo
              </button>
            </div>
          </div>
        )}
      </main>

      {/* Benefits Footer */}
      {!result && !isProcessing && (
        <section className="max-w-4xl mx-auto px-4 mt-24">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
            <div className="p-6">
              <div className="w-12 h-12 bg-blue-100 text-blue-600 rounded-xl flex items-center justify-center mb-4">
                <CheckCircle className="w-6 h-6" />
              </div>
              <h4 className="font-bold text-slate-900 mb-2">Extração Inteligente</h4>
              <p className="text-sm text-slate-500 leading-relaxed">Não perca tempo copiando e colando. Deixe que a IA identifique campos complexos como CNPJ, CPF e moedas.</p>
            </div>
            <div className="p-6">
              <div className="w-12 h-12 bg-green-100 text-green-600 rounded-xl flex items-center justify-center mb-4">
                <FileText className="w-6 h-6" />
              </div>
              <h4 className="font-bold text-slate-900 mb-2">Suporte Multiformato</h4>
              <p className="text-sm text-slate-500 leading-relaxed">Funciona com PDFs de qualquer origem, planilhas bagunçadas ou até fotos de recibos e notas fiscais.</p>
            </div>
            <div className="p-6">
              <div className="w-12 h-12 bg-purple-100 text-purple-600 rounded-xl flex items-center justify-center mb-4">
                <Download className="w-6 h-6" />
              </div>
              <h4 className="font-bold text-slate-900 mb-2">Exportação Direta</h4>
              <p className="text-sm text-slate-500 leading-relaxed">Gere um arquivo Excel limpo e pronto para ser usado no seu sistema ou para apresentações em segundos.</p>
            </div>
          </div>
        </section>
      )}
    </div>
  );
};

export default App;

