import { FileMetadata, ProcessingResult } from './types';
import { fileToBase64, parseExcel, pdfToImages } from './utils/fileUtils';
import { extractDataFromReport } from './services/geminiService';
import ProcessingAnimation from './components/ProcessingAnimation';

const COMMON_FIELDS = [
  { label: 'Nome', value: 'Nome' },
  { label: 'Valor', value: 'Valor' },
  { label: 'CPF', value: 'CPF' },
  { label: 'CNPJ', value: 'CNPJ' },
  { label: 'Data', value: 'Data' },
  { label: 'Endereço', value: 'Endereço' },
  { label: 'E-mail', value: 'E-mail' },
  { label: 'Telefone', value: 'Telefone' },
];

const App: React.FC = () => {
  const [file, setFile] = useState<FileMetadata | null>(null);
  const [instruction, setInstruction] = useState('Extrair nome e valor de cada item.');
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      let type: any = 'unknown';
      if (selectedFile.type.includes('pdf')) type = 'pdf';
      else if (selectedFile.type.includes('sheet') || selectedFile.name.endsWith('.xlsx') || selectedFile.name.endsWith('.xls')) type = 'excel';
      else if (selectedFile.type.includes('image')) type = 'image';
      else if (selectedFile.type.includes('text')) type = 'text';

      setFile({
        name: selectedFile.name,
        size: selectedFile.size,
        type,
        raw: selectedFile
      });
      setResult(null);
      setError(null);
    }
  };

  const addFieldToInstruction = (field: string) => {
    setInstruction(prev => {
      if (prev.toLowerCase().includes(field.toLowerCase())) return prev;
      const separator = prev.endsWith('.') ? ' ' : prev.length > 0 ? ', ' : '';
      return `${prev}${separator}${field}`;
    });
  };

  const handleProcess = async () => {
    if (!file) return;

    setIsProcessing(true);
    setError(null);

    try {
      let fileParts: { inlineData: { data: string; mimeType: string } }[] = [];
      let textContent = "";

      if (file.type === 'pdf') {
        fileParts = await pdfToImages(file.raw);
      } else if (file.type === 'excel') {
        textContent = await parseExcel(file.raw);
      } else if (file.type === 'image') {
        const base64 = await fileToBase64(file.raw);
        fileParts = [{ inlineData: { data: base64, mimeType: file.raw.type } }];
      } else if (file.type === 'text') {
        textContent = await file.raw.text();
      }

      const extractionResult = await extractDataFromReport(instruction, fileParts, textContent);
      setResult(extractionResult);
    } catch (err: any) {
      setError(err.message || 'Ocorreu um erro inesperado.');
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;
    const ws = XLSX.utils.json_to_sheet(result.data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Dados Extraídos");
    XLSX.writeFile(wb, `relatorio_organizado_${Date.now()}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
