// Always use named parameter for apiKey and use process.env.API_KEY directly.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const extractDataFromReport = async (
  prompt: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    Você é um especialista em extração e organização de dados de relatórios complexos.
    Sua tarefa é analisar o arquivo fornecido (PDF, Excel ou Imagem) e extrair EXATAMENTE as colunas de dados que o usuário solicitar.

    DIRETRIZES DE EXTRAÇÃO:
    1. Identifique os campos solicitados pelo usuário (ex: Nome, Valor, CPF, Data, etc).
    2. Se o usuário pedir múltiplos campos (ex: "nome, valor e cpf"), crie um objeto JSON para cada linha do relatório contendo essas chaves exatas.
    3. Retorne SEMPRE um objeto JSON com:
       - "data": Um array de objetos, onde cada objeto representa uma linha do relatório com as chaves solicitadas.
       - "summary": Uma breve descrição técnica do que foi extraído e quantos itens foram encontrados.
    4. NORMALIZAÇÃO DE DADOS:
       - Valores: Converta para números ou strings limpas (ex: "R$ 1.200,50" -> "1200.50").
       - CPF/CNPJ: Formate com pontos e traços se possível, ou mantenha apenas números conforme o padrão detectado.
       - Datas: Tente padronizar para DD/MM/AAAA ou AAAA-MM-DD.
    5. Se os dados estiverem em tabelas espalhadas por várias páginas, consolide tudo no array "data".
    6. Se o arquivo for uma imagem ou PDF escaneado, use OCR de alta precisão para não perder caracteres.
  `;

  const finalPrompt = `
    INSTRUÇÃO DE EXTRAÇÃO DO USUÁRIO: ${prompt}

    CONTEÚDO ADICIONAL EXTRAÍDO (SE HOUVER):
    ${textContent || 'Nenhum conteúdo de texto adicional fornecido. Extraia diretamente das partes de mídia anexadas.'}

    Gere o JSON estruturado agora.
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { 
        parts: [
          ...fileParts,
          { text: finalPrompt }
        ] 
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
      }
    });

    const responseText = response.text || '{}';
    const result = JSON.parse(responseText);
    const data: ExtractedData[] = result.data || [];

    // Extract headers from the first object found in data
    const headers = data.length > 0 ? Object.keys(data[0]) : [];

    return {
      data,
      headers,
      summary: result.summary
    };
  } catch (error) {
    console.error("Erro ao processar com Gemini:", error);
    throw new Error("Falha ao processar o relatório. Verifique se o arquivo está legível e se a instrução está clara.");
  }
};

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
