const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const extractDataFromReport = async (
  prompt: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  // Mudando para o Pro para lidar com tarefas complexas e contextos maiores
  const model = 'gemini-3-pro-preview';

  const systemInstruction = `
    Você é um extrator de dados de alta precisão. Sua missão é ler documentos INTEIROS e transformar em JSON.

    DIRETRIZES CRÍTICAS DE COMPLETUDE:
    1. EXAUSTIVIDADE: Não pule NENHUMA linha ou registro. Se o documento tem 100 itens, extraia os 100 itens.
    2. FIDELIDADE: Extraia exatamente os campos solicitados pelo usuário (ex: Nome, Valor, CPF, Data).
    3. FORMATO DE SAÍDA: Retorne um objeto JSON estritamente com:
       - "data": Um array de objetos (um para cada linha/registro encontrado).
       - "summary": Um resumo estatístico (ex: "Processadas 45 linhas encontradas em 12 páginas").
    4. MULTIPÁGINAS: O conteúdo enviado pode conter várias imagens que representam páginas sequenciais. Mantenha a ordem e não ignore as páginas do meio ou do fim.
    5. LIMPEZA: Remova cabeçalhos repetidos de páginas e rodapés, focando apenas nos dados úteis.
    6. NORMALIZAÇÃO:
       - Valores: Ponto como separador decimal (ex: 1250.50).
       - Datas: Padrão ISO ou DD/MM/AAAA.
  `;

  const finalPrompt = `
    INSTRUÇÃO ESPECÍFICA DO USUÁRIO: ${prompt}

    POR FAVOR, ANALISE TODO O CONTEÚDO FORNECIDO ABAIXO E NÃO DEIXE NADA DE FORA.

    ${textContent ? `TEXTO EXTRAÍDO DO DOCUMENTO:\n${textContent}` : 'EXTRAIA OS DADOS DIRETAMENTE DAS IMAGENS/ANEXOS FORNECIDOS.'}
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { 
        parts: [
          ...fileParts,
          { text: finalPrompt }
        ] 
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        // Aumentando a temperatura levemente para melhor detecção, 
        // mas mantendo baixa para evitar alucinações.
        temperature: 0.1,
      }
    });

    const responseText = response.text || '{}';
    const result = JSON.parse(responseText);
    const data: ExtractedData[] = result.data || [];

    const headers = data.length > 0 ? Object.keys(data[0]) : [];

    return {
      data,
      headers,
      summary: result.summary
    };
  } catch (error) {
    console.error("Erro ao processar com Gemini Pro:", error);
    throw new Error("O documento é muito grande ou complexo. Tente especificar melhor as colunas ou enviar partes menores se o erro persistir.");
  }
};

import * as XLSX from 'xlsx';

export const fileToHash = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve(base64String);
    };
    reader.onerror = error => reject(error);
  });
};

export const parseExcel = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const data = new Uint8Array(e.target?.result as ArrayBuffer);
      const workbook = XLSX.read(data, { type: 'array' });
      let fullText = "";
      workbook.SheetNames.forEach(sheetName => {
        const worksheet = workbook.Sheets[sheetName];
        fullText += `\n--- Planilha: ${sheetName} ---\n`;
        fullText += XLSX.utils.sheet_to_txt(worksheet);
      });
      resolve(fullText);
    };
    reader.onerror = reject;
    reader.readAsArrayBuffer(file);
  });
};

export const pdfToImages = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }[]> => {
  const arrayBuffer = await file.arrayBuffer();
  // @ts-ignore
  const pdfjsLib = window['pdfjs-dist/build/pdf'];
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';

  const pdf = await pdfjsLib.getDocument(arrayBuffer).promise;
  const imageParts: { inlineData: { data: string; mimeType: string } }[] = [];

  // Aumentado para 25 páginas para cobrir relatórios mais extensos
  const maxPages = Math.min(pdf.numPages, 25);

  for (let i = 1; i <= maxPages; i++) {
    const page = await pdf.getPage(i);
    // Usando uma escala um pouco menor para economizar tokens, mas manter legibilidade (1.2x)
    const viewport = page.getViewport({ scale: 1.2 });
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    canvas.height = viewport.height;
    canvas.width = viewport.width;

    if (context) {
      await page.render({ canvasContext: context, viewport }).promise;
      // JPEG com qualidade 0.7 para otimizar o tamanho do payload sem perder muita definição
      const base64 = canvas.toDataURL('image/jpeg', 0.7).split(',')[1];
      imageParts.push({ inlineData: { data: base64, mimeType: 'image/jpeg' } });
    }
  }

  return imageParts;
};

