  { label: 'Valor', value: 'Valor' },
  { label: 'CPF', value: 'CPF' },
  { label: 'CNPJ', value: 'CNPJ' },
  { label: 'Data', value: 'Data' },
  { label: 'Vencimento', value: 'Vencimento' },
  { label: 'Status', value: 'Status' },
