  const handleProcess = async () => {
    if (!file) return;

    setIsProcessing(true);
    setError(null);

    try {
      let fileParts: { inlineData: { data: string; mimeType: string } }[] = [];
      let textContent = "";

      if (file.type === 'pdf') {
        fileParts = await pdfToImages(file.raw);
      } else if (file.type === 'excel') {
        textContent = await parseExcel(file.raw);
      } else if (file.type === 'image') {
        const base64 = await fileToBase64(file.raw);
        fileParts = [{ inlineData: { data: base64, mimeType: file.raw.type } }];
      } else if (file.type === 'text') {
        textContent = await file.raw.text();
      }

      const extractionResult = await extractDataFromReport(instruction, fileParts, textContent);
      setResult(extractionResult);
    } catch (err: any) {
      setError(err.message || 'Ocorreu um erro ao processar o arquivo completo.');
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;
    const ws = XLSX.utils.json_to_sheet(result.data);
    const wb = XLSX.utils.book_new();
