import * as XLSX from 'xlsx';

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const base64String = (reader.result as string).split(',')[1];
      resolve(base64String);
    };
    reader.onerror = error => reject(error);
  });
};

export const parseExcel = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const data = new Uint8Array(e.target?.result as ArrayBuffer);
      const workbook = XLSX.read(data, { type: 'array' });
      let fullText = "";
      workbook.SheetNames.forEach(sheetName => {
        const worksheet = workbook.Sheets[sheetName];
        fullText += `\n--- Planilha: ${sheetName} ---\n`;
        fullText += XLSX.utils.sheet_to_txt(worksheet);
      });
      resolve(fullText);
    };
    reader.onerror = reject;
    reader.readAsArrayBuffer(file);
  });
};

/**
 * Extrai texto de um PDF em lotes para suportar documentos massivos.
 */
export const extractPdfTextInChunks = async (
  file: File, 
  pageSize: number = 50,
  onProgress?: (current: number, total: number) => void
): Promise<string[]> => {
  const arrayBuffer = await file.arrayBuffer();
  // @ts-ignore
  const pdfjsLib = window['pdfjs-dist/build/pdf'];
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';

  const pdf = await pdfjsLib.getDocument(arrayBuffer).promise;
  const numPages = pdf.numPages;
  const chunks: string[] = [];
  let currentChunkText = "";

  for (let i = 1; i <= numPages; i++) {
    const page = await pdf.getPage(i);
    const textContent = await page.getTextContent();
    const pageText = textContent.items.map((item: any) => item.str).join(" ");

    currentChunkText += `\n--- PÁGINA ${i} ---\n${pageText}`;

    if (i % pageSize === 0 || i === numPages) {
      chunks.push(currentChunkText);
      currentChunkText = "";
      if (onProgress) onProgress(i, numPages);
    }
  }

  return chunks;
};

/**
 * Mantemos a conversão para imagem apenas para arquivos pequenos (OCR de alta qualidade)
 */
export const pdfToImages = async (file: File, maxPages: number = 10): Promise<{ inlineData: { data: string; mimeType: string } }[]> => {
  const arrayBuffer = await file.arrayBuffer();
  // @ts-ignore
  const pdfjsLib = window['pdfjs-dist/build/pdf'];
  const pdf = await pdfjsLib.getDocument(arrayBuffer).promise;
  const imageParts: { inlineData: { data: string; mimeType: string } }[] = [];
  const pagesToProcess = Math.min(pdf.numPages, maxPages);

  for (let i = 1; i <= pagesToProcess; i++) {
    const page = await pdf.getPage(i);
    const viewport = page.getViewport({ scale: 1.2 });
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    canvas.height = viewport.height;
    canvas.width = viewport.width;
    if (context) {
      await page.render({ canvasContext: context, viewport }).promise;
      const base64 = canvas.toDataURL('image/jpeg', 0.7).split(',')[1];
      imageParts.push({ inlineData: { data: base64, mimeType: 'image/jpeg' } });
    }
  }
  return imageParts;
};

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ExtractedData, ProcessingResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const extractDataFromReport = async (
  prompt: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  const model = 'gemini-3-pro-preview';

  const systemInstruction = `
    Você é um motor de extração de dados tabulares.
    OBJETIVO: Extrair dados estruturados de um fragmento de documento e retornar em JSON.

    REGRAS DE OURO:
    1. Responda APENAS com o JSON.
    2. Estrutura do JSON:
       {
         "data": [ {"Campo1": "Valor", "Campo2": "Valor"}, ... ],
         "summary": "Texto curto descrevendo o que foi encontrado neste fragmento."
       }
    3. Se não encontrar dados no fragmento, retorne "data": [].
    4. Limpe os dados: remova R$, formate datas para DD/MM/AAAA, normalize CPFs.
    5. Não invente dados. Extraia apenas o que está no texto/imagem.
  `;

  const finalPrompt = `
    INSTRUÇÃO DO USUÁRIO: ${prompt}

    CONTEÚDO PARA ANÁLISE:
    ${textContent ? textContent : 'Analise as imagens anexadas.'}
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { 
        parts: [
          ...fileParts,
          { text: finalPrompt }
        ] 
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        temperature: 0.1,
      }
    });

    const result = JSON.parse(response.text || '{"data":[]}');
    return {
      data: result.data || [],
      headers: result.data?.length > 0 ? Object.keys(result.data[0]) : [],
      summary: result.summary
    };
  } catch (error) {
    console.error("Erro no lote:", error);
    return { data: [], headers: [], summary: "Erro no processamento deste lote." };
  }
};

import React, { useState } from 'react';
import { 
  FileText, 
  Upload, 
  Search, 
  CheckCircle, 
  Download, 
  Trash2, 
  AlertCircle,
  Table as TableIcon,
  ChevronRight,
  FileSpreadsheet,
  Plus,
  Loader2
} from 'lucide-react';
import * as XLSX from 'xlsx';

import { FileMetadata, ProcessingResult, ExtractedData } from './types';
import { fileToBase64, parseExcel, extractPdfTextInChunks, pdfToImages } from './utils/fileUtils';
import { extractDataFromReport } from './services/geminiService';

const COMMON_FIELDS = [
  { label: 'Nome', value: 'Nome' },
  { label: 'Valor', value: 'Valor' },
  { label: 'CPF', value: 'CPF' },
  { label: 'CNPJ', value: 'CNPJ' },
  { label: 'Data', value: 'Data' },
  { label: 'Descrição', value: 'Descrição' },
];

const App: React.FC = () => {
  const [file, setFile] = useState<FileMetadata | null>(null);
  const [instruction, setInstruction] = useState('Extrair nome, valor, data e CPF de todos os registros.');
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, phase: '' });
  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      let type: any = 'unknown';
      if (selectedFile.type.includes('pdf')) type = 'pdf';
      else if (selectedFile.type.includes('sheet') || selectedFile.name.endsWith('.xlsx')) type = 'excel';
      else if (selectedFile.type.includes('image')) type = 'image';

      setFile({ name: selectedFile.name, size: selectedFile.size, type, raw: selectedFile });
      setResult(null);
      setError(null);
    }
  };

  const handleProcess = async () => {
    if (!file) return;
    setIsProcessing(true);
    setResult(null);
    setError(null);

    let allData: ExtractedData[] = [];
    let consolidatedHeaders: string[] = [];

    try {
      if (file.type === 'pdf') {
        setProgress({ current: 0, total: 100, phase: 'Lendo páginas do PDF...' });
        const chunks = await extractPdfTextInChunks(file.raw, 50, (curr, tot) => {
          setProgress({ current: curr, total: tot, phase: `Extraindo texto (${curr}/${tot} páginas)...` });
        });

        for (let i = 0; i < chunks.length; i++) {
          setProgress({ current: i + 1, total: chunks.length, phase: `Analisando lote ${i + 1} de ${chunks.length} com IA...` });
          const batchRes = await extractDataFromReport(instruction, [], chunks[i]);
          allData = [...allData, ...batchRes.data];
          if (consolidatedHeaders.length === 0) consolidatedHeaders = batchRes.headers;
        }
      } else if (file.type === 'excel') {
        setProgress({ current: 50, total: 100, phase: 'Analisando planilha...' });
        const text = await parseExcel(file.raw);
        const res = await extractDataFromReport(instruction, [], text);
        allData = res.data;
        consolidatedHeaders = res.headers;
      } else if (file.type === 'image') {
        setProgress({ current: 50, total: 100, phase: 'Lendo imagem...' });
        const b64 = await fileToBase64(file.raw);
        const res = await extractDataFromReport(instruction, [{ inlineData: { data: b64, mimeType: file.raw.type } }]);
        allData = res.data;
        consolidatedHeaders = res.headers;
      }

      setResult({
        data: allData,
        headers: consolidatedHeaders,
        summary: `Sucesso! Foram processados ${allData.length} registros no total.`
      });
    } catch (err: any) {
      setError(err.message || "Erro durante o processamento em massa.");
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;
    const ws = XLSX.utils.json_to_sheet(result.data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Resultados");
    XLSX.writeFile(wb, `extracao_completa_${Date.now()}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10 p-4">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="p-2 bg-indigo-600 rounded-lg text-white"><TableIcon /></div>
            <h1 className="text-xl font-bold">SmartReport <span className="text-indigo-600">Ultra</span></h1>
          </div>
          <div className="text-xs font-bold text-slate-400 uppercase tracking-widest">Capacidade: 1000+ Páginas</div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-10">
        {!result && !isProcessing && (
          <div className="bg-white rounded-3xl shadow-2xl p-8 border border-slate-200">
            <div className="text-center mb-8">
              <h2 className="text-3xl font-black text-slate-900 mb-2">Processador de Larga Escala</h2>
              <p className="text-slate-500">Envie relatórios massivos e deixe a IA organizar tudo.</p>
            </div>

            <div className={`border-4 border-dashed rounded-2xl p-12 flex flex-col items-center justify-center transition-all ${file ? 'border-indigo-400 bg-indigo-50' : 'border-slate-200 hover:border-indigo-300'}`}>
              {!file ? (
                <>
                  <Upload className="w-16 h-16 text-indigo-200 mb-4" />
                  <input type="file" id="file-input" className="hidden" onChange={handleFileChange} accept=".pdf,.xlsx" />
                  <label htmlFor="file-input" className="bg-indigo-600 text-white px-10 py-4 rounded-xl font-bold cursor-pointer hover:bg-indigo-700 shadow-xl transition-all">Selecionar Arquivo Gigante</label>
                  <p className="mt-4 text-slate-400 text-sm">PDF ou Excel até 1000 páginas</p>
                </>
              ) : (
                <div className="flex items-center justify-between w-full">
                  <div className="flex items-center gap-4">
                    <FileText className="w-10 h-10 text-indigo-600" />
                    <div className="text-left">
                      <p className="font-bold text-slate-800">{file.name}</p>
                      <p className="text-xs text-slate-400 uppercase">{(file.size / (1024 * 1024)).toFixed(2)} MB</p>
                    </div>
                  </div>
                  <button onClick={() => setFile(null)} className="p-2 hover:bg-red-50 text-red-500 rounded-full"><Trash2 /></button>
                </div>
              )}
            </div>

