import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ExtractedData, ProcessingResult } from "../types";

// Usando a chave de API do ambiente conforme as diretrizes
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const extractDataFromReport = async (
  prompt: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  // Modelo Flash Lite para ultra velocidade e baixa latência
  const model = 'gemini-2.5-flash-lite-latest';

  const systemInstruction = `
    Você é um motor de extração de dados tabulares ultra-rápido.
    OBJETIVO: Extrair e organizar dados estruturados de um ou mais fragmentos de documentos.

    COMPORTAMENTO PARA MÚLTIPLOS DOCUMENTOS:
    1. Se houver informações em documentos diferentes (ex: nomes no Doc 1 e valores no Doc 2), tente CRUZAR os dados usando campos comuns (como ID, Nome ou CPF) se o usuário solicitar "juntar" ou "mesclar".
    2. Caso contrário, liste todos os registros encontrados de forma consolidada.

    REGRAS DE OURO:
    1. Responda APENAS com o JSON.
    2. Estrutura do JSON:
       {
         "data": [ {"Campo1": "Valor", "Campo2": "Valor"}, ... ],
         "summary": "Resumo ultra-rápido do que foi processado."
       }
    3. Limpeza: remova símbolos monetários para cálculos, formate datas (DD/MM/AAAA) e CPFs.
    4. Se não houver dados, retorne "data": [].
  `;

  const finalPrompt = `
    INSTRUÇÃO DO USUÁRIO: ${prompt}

    CONTEÚDO PARA ANÁLISE (Pode conter múltiplos documentos):
    ${textContent ? textContent : 'Analise os anexos fornecidos.'}
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { 
        parts: [
          ...fileParts,
          { text: finalPrompt }
        ] 
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        temperature: 0.1,
      }
    });

    const result = JSON.parse(response.text || '{"data":[]}');
    return {
      data: result.data || [],
      headers: result.data?.length > 0 ? Object.keys(result.data[0]) : [],
      summary: result.summary
    };
  } catch (error) {
    console.error("Erro na extração rápida:", error);
    return { data: [], headers: [], summary: "Erro no processamento rápido." };
  }
};

import React, { useState } from 'react';
import { 
  FileText, 
  Upload, 
  Search, 
  CheckCircle, 
  Download, 
  Trash2, 
  AlertCircle,
  Table as TableIcon,
  ChevronRight,
  FileSpreadsheet,
  Plus,
  Loader2,
  Zap,
  Layers,
  X
} from 'lucide-react';
import * as XLSX from 'xlsx';

import { FileMetadata, ProcessingResult, ExtractedData } from './types';
import { fileToBase64, parseExcel, extractPdfTextInChunks } from './utils/fileUtils';
import { extractDataFromReport } from './services/geminiService';

const COMMON_FIELDS = [
  { label: 'Nome', value: 'Nome' },
  { label: 'Valor', value: 'Valor' },
  { label: 'CPF', value: 'CPF' },
  { label: 'CNPJ', value: 'CNPJ' },
  { label: 'Data', value: 'Data' },
  { label: 'ID/Código', value: 'ID' },
];

const App: React.FC = () => {
  const [files, setFiles] = useState<FileMetadata[]>([]);
  const [instruction, setInstruction] = useState('Extrair nome, valor e CPF. Se houver dados em arquivos diferentes, junte-os pelo campo comum.');
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, phase: '' });
  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFiles = e.target.files;
    if (selectedFiles) {
      const newFiles: FileMetadata[] = Array.from(selectedFiles).map(f => {
        let type: any = 'unknown';
        if (f.type.includes('pdf')) type = 'pdf';
        else if (f.type.includes('sheet') || f.name.endsWith('.xlsx')) type = 'excel';
        else if (f.type.includes('image')) type = 'image';
        return { name: f.name, size: f.size, type, raw: f };
      });
      setFiles(prev => [...prev, ...newFiles]);
      setResult(null);
      setError(null);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
    if (files.length <= 1) setResult(null);
  };

  const handleProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setResult(null);
    setError(null);

    let allExtractedText = "";
    let imageParts: { inlineData: { data: string; mimeType: string } }[] = [];

    try {
      for (let idx = 0; idx < files.length; idx++) {
        const file = files[idx];
        const docPrefix = `\n--- DOCUMENTO ${idx + 1}: ${file.name} ---\n`;

        setProgress({ current: idx + 1, total: files.length, phase: `Lendo ${file.name}...` });

        if (file.type === 'pdf') {
          const chunks = await extractPdfTextInChunks(file.raw, 100);
          allExtractedText += docPrefix + chunks.join("\n");
        } else if (file.type === 'excel') {
          const text = await parseExcel(file.raw);
          allExtractedText += docPrefix + text;
        } else if (file.type === 'image') {
          const b64 = await fileToBase64(file.raw);
          imageParts.push({ inlineData: { data: b64, mimeType: file.raw.type } });
          allExtractedText += docPrefix + "[Conteúdo em Imagem]";
        }
      }

      setProgress({ current: 100, total: 100, phase: 'IA Flash Lite processando...' });

      // Processamento único consolidado para permitir cruzamento de dados
      const extractionResult = await extractDataFromReport(instruction, imageParts, allExtractedText);

      setResult(extractionResult);
    } catch (err: any) {
      setError(err.message || "Erro durante o processamento multi-arquivo.");
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;
    const ws = XLSX.utils.json_to_sheet(result.data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Dados Consolidados");
    XLSX.writeFile(wb, `relatorio_mesclado_${Date.now()}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 font-sans selection:bg-indigo-100">
      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-10 p-4">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2.5 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl text-white shadow-lg shadow-indigo-200">
              <Zap className="w-5 h-5 fill-current" />
            </div>
            <h1 className="text-xl font-bold tracking-tight text-slate-800">
              SmartReport <span className="text-indigo-600">Flash</span>
            </h1>
          </div>
          <div className="flex items-center gap-2 px-3 py-1 bg-amber-50 border border-amber-100 rounded-full">
            <div className="w-2 h-2 bg-amber-400 rounded-full animate-pulse"></div>
            <span className="text-[10px] font-black text-amber-700 uppercase tracking-widest">Baixa Latência Ativa</span>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-10">
        {!result && !isProcessing && (
          <div className="space-y-8">
            <div className="text-center">
              <h2 className="text-4xl font-black text-slate-900 mb-3 tracking-tight">Organizador Multi-Relatórios</h2>
              <p className="text-slate-500 text-lg">Suba um ou mais arquivos e peça para a IA cruzar as informações.</p>
            </div>

            <div className="bg-white rounded-3xl shadow-2xl p-8 border border-slate-200">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
                {/* Upload Area */}
                <div className="border-4 border-dashed border-slate-100 hover:border-indigo-300 rounded-2xl p-8 flex flex-col items-center justify-center transition-all bg-slate-50/50 group">
                  <Upload className="w-12 h-12 text-slate-300 group-hover:text-indigo-400 mb-4 transition-colors" />
                  <input type="file" id="file-input" className="hidden" multiple onChange={handleFileChange} accept=".pdf,.xlsx,.png,.jpg" />
                  <label htmlFor="file-input" className="bg-white border-2 border-indigo-600 text-indigo-600 px-6 py-2.5 rounded-xl font-bold cursor-pointer hover:bg-indigo-600 hover:text-white transition-all shadow-sm">
                    Adicionar Arquivos
                  </label>
                  <p className="mt-3 text-slate-400 text-[10px] uppercase font-bold tracking-tighter">PDF, Excel ou Fotos</p>
                </div>

                {/* File List */}
                <div className="bg-slate-50/50 rounded-2xl p-4 border border-slate-100 min-h-[160px]">
                  <h3 className="text-xs font-black text-slate-400 uppercase mb-3 px-2">Arquivos na Fila ({files.length})</h3>
                  <div className="space-y-2 max-h-[200px] overflow-y-auto pr-2 custom-scrollbar">
                    {files.length === 0 ? (
                      <div className="h-24 flex items-center justify-center text-slate-300 italic text-sm">Nenhum arquivo selecionado</div>
                    ) : (
                      files.map((f, i) => (
                        <div key={i} className="flex items-center justify-between bg-white p-3 rounded-xl border border-slate-100 shadow-sm animate-in slide-in-from-right-2">
                          <div className="flex items-center gap-3 overflow-hidden">
                            {f.type === 'pdf' ? <FileText className="w-5 h-5 text-red-500 shrink-0" /> : <FileSpreadsheet className="w-5 h-5 text-green-500 shrink-0" />}
                            <span className="text-sm font-bold text-slate-700 truncate">{f.name}</span>
                          </div>
                          <button onClick={() => removeFile(i)} className="p-1.5 hover:bg-red-50 text-slate-300 hover:text-red-500 rounded-lg transition-colors">
                            <X className="w-4 h-4" />
                          </button>
                        </div>
                      ))
                    )}
                  </div>
                </div>
              </div>

              {files.length > 0 && (
                <div className="space-y-6 animate-in fade-in duration-500">
                  <div className="p-5 bg-indigo-50/50 border border-indigo-100 rounded-2xl">
                    <div className="flex items-center gap-2 mb-4">
                      <Layers className="w-4 h-4 text-indigo-600" />
                      <label className="text-sm font-black text-slate-700 uppercase">Instruções de Extração e União</label>
                    </div>
                    <div className="flex flex-wrap gap-2 mb-4">
                      {COMMON_FIELDS.map(f => (
                        <button key={f.value} onClick={() => setInstruction(i => i.includes(f.value) ? i : `${i} ${f.value},`)} className="px-3 py-1.5 bg-white hover:bg-indigo-600 hover:text-white border border-indigo-100 rounded-full text-xs font-bold transition-all shadow-sm">
                          + {f.label}
                        </button>
                      ))}
                    </div>
                    <textarea 
                      value={instruction} 
                      onChange={e => setInstruction(e.target.value)} 
                      className="w-full bg-white border border-indigo-100 rounded-xl p-4 min-h-[100px] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all font-medium text-slate-700 shadow-inner" 
                    />
                    <p className="mt-2 text-[10px] text-indigo-400 font-medium">Dica: Peça para "mesclar dados entre arquivos" se houver informações complementares.</p>
                  </div>

                  <button 
                    onClick={handleProcess} 
                    className="w-full bg-gradient-to-r from-indigo-600 to-purple-600 text-white py-5 rounded-2xl font-black text-xl hover:shadow-2xl hover:shadow-indigo-200 active:scale-[0.99] transition-all flex items-center justify-center gap-3 group"
                  >
                    Processar {files.length} {files.length === 1 ? 'Arquivo' : 'Arquivos'}
                    <ChevronRight className="w-6 h-6 group-hover:translate-x-1 transition-transform" />
                  </button>
                </div>
              )}
            </div>
          </div>
        )}

        {isProcessing && (
          <div className="bg-white rounded-3xl shadow-2xl p-12 text-center space-y-8 animate-in zoom-in-95">
            <div className="relative w-40 h-40 mx-auto">
              <div className="absolute inset-0 border-[12px] border-slate-100 rounded-full"></div>
              <div 
                className="absolute inset-0 border-[12px] border-indigo-600 rounded-full border-t-transparent animate-spin"
                style={{ clipPath: 'polygon(0 0, 100% 0, 100% 100%, 0 100%)' }}
              ></div>
              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <Zap className="w-8 h-8 text-indigo-600 fill-current mb-1" />
                <span className="text-2xl font-black text-slate-800">FAST</span>
              </div>
            </div>
            <div>
              <h3 className="text-2xl font-black text-slate-900 tracking-tight">{progress.phase}</h3>
              <p className="text-slate-400 mt-2 font-medium">Utilizando motor Flash Lite para velocidade máxima.</p>
            </div>
          </div>
        )}

        {result && (
          <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
              <div>
                <div className="flex items-center gap-2 mb-1">
                  <span className="px-2 py-0.5 bg-green-100 text-green-700 text-[10px] font-black uppercase rounded tracking-widest">Sucesso</span>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">Dados Consolidados</h2>
                </div>
                <p className="text-slate-500 font-medium">{result.data.length} itens extraídos e organizados.</p>
              </div>
              <div className="flex gap-3">
                <button onClick={() => {setResult(null); setFiles([]);}} className="px-6 py-3 bg-white border border-slate-200 font-bold rounded-xl hover:bg-slate-50 transition-all text-slate-600">Reiniciar</button>
                <button onClick={downloadExcel} className="px-6 py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 shadow-xl flex items-center gap-2 transition-all active:scale-95">
                  <Download className="w-5 h-5" /> Exportar Tudo
                </button>
              </div>
            </div>

            <div className="bg-white border border-slate-200 rounded-3xl overflow-hidden shadow-2xl border-t-8 border-t-indigo-600">
              <div className="max-h-[500px] overflow-auto custom-scrollbar">
                <table className="w-full text-left border-collapse">
                  <thead className="sticky top-0 bg-white z-10 shadow-sm">
                    <tr>
                      {result.headers.map(h => (
                        <th key={h} className="px-6 py-5 text-[10px] font-black uppercase text-slate-400 border-b border-slate-100 tracking-widest">
                          {h}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {result.data.map((row, i) => (
                      <tr key={i} className="hover:bg-indigo-50/40 transition-colors group">
                        {result.headers.map(h => (
                          <td key={`${i}-${h}`} className="px-6 py-4 text-sm font-semibold text-slate-600 group-hover:text-indigo-900">
                            {row[h] || '-'}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            {result.summary && (
              <div className="bg-slate-900 text-slate-300 p-6 rounded-2xl shadow-lg flex gap-4">
                <Search className="w-6 h-6 text-indigo-400 shrink-0" />
                <p className="text-sm leading-relaxed"><strong className="text-white">Análise do Motor Flash:</strong> {result.summary}</p>
              </div>
            )}
          </div>
        )}

        {error && (
          <div className="bg-red-50 border border-red-100 p-8 rounded-3xl flex gap-5 text-red-700 mt-10 shadow-lg animate-in shake">
            <AlertCircle className="w-10 h-10 shrink-0" />
            <div>
              <p className="text-xl font-black mb-1">Erro na Extração</p>
              <p className="font-medium opacity-80">{error}</p>
              <button onClick={() => setIsProcessing(false)} className="mt-6 bg-red-600 text-white px-6 py-2 rounded-xl font-bold hover:bg-red-700 transition-all shadow-md">Tentar novamente</button>
            </div>
          </div>
        )}
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; height: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #cbd5e1; }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-5px); }
          75% { transform: translateX(5px); }
        }
        .shake { animation: shake 0.3s ease-in-out; }
      `}</style>
    </div>
  );
};

