import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ExtractedData, ProcessingResult } from "../types";

// Usando a chave de API do ambiente conforme as diretrizes
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const extractDataFromReport = async (
  prompt: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  // Modelo Flash Lite para ultra velocidade e baixa latência
  const model = 'gemini-flash-lite-latest';

  const systemInstruction = `
    Você é um motor de extração de dados tabulares ultra-rápido e preciso.
    OBJETIVO: Extrair e organizar dados estruturados de um ou mais fragmentos de documentos.

    REGRAS DE FORMATAÇÃO (ESTRITAMENTE OBRIGATÓRIAS):
    1. VALORES MONETÁRIOS: Sempre formate no padrão brasileiro. Exemplo: "R$ 1.250,50". Use vírgula para decimais e ponto para milhares.
    2. DATAS: Use o formato DD/MM/AAAA.
    3. DOCUMENTOS MÚLTIPLOS: Se o usuário pedir para "juntar" ou "mesclar", use campos comuns (como Nome ou CPF) para consolidar linhas de arquivos diferentes em um único registro.

    SAÍDA:
    - Responda APENAS com o JSON.
    - Estrutura: { "data": [ {"Campo": "Valor"}, ... ], "summary": "Resumo da operação" }
    - Se não houver dados, retorne "data": [].
  `;

  const finalPrompt = `
    INSTRUÇÃO DO USUÁRIO: ${prompt}

    CONTEÚDO PARA ANÁLISE:
    ${textContent ? textContent : 'Analise os anexos fornecidos.'}
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { 
        parts: [
          ...fileParts,
          { text: finalPrompt }
        ] 
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        temperature: 0.1,
      }
    });

    const result = JSON.parse(response.text || '{"data":[]}');
    return {
      data: result.data || [],
      headers: result.data?.length > 0 ? Object.keys(result.data[0]) : [],
      summary: result.summary
    };
  } catch (error) {
    console.error("Erro na extração rápida:", error);
    return { data: [], headers: [], summary: "Erro no processamento rápido." };
  }
};

