          const text = await parseCsv(file.raw);
          allExtractedText += `\n--- DOC CSV: ${file.name} ---\n` + text;
        } else if (file.type === 'image') {
          const b64 = await fileToBase64(file.raw);
          imageParts.push({ inlineData: { data: b64, mimeType: file.raw.type } });
          allExtractedText += `\n--- DOC IMAGEM: ${file.name} (Anexado) ---\n`;
