import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ExtractedData, ProcessingResult } from "../types";

// Usando a chave de API do ambiente conforme as diretrizes
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const extractDataFromReport = async (
  prompt: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  // Modelo Flash Lite para ultra velocidade e baixa latência
  const model = 'gemini-flash-lite-latest';

  const systemInstruction = `
    Você é um motor de processamento de relatórios especializado em CONSOLIDAÇÃO e ENRIQUECIMENTO de dados.

    LÓGICA DE PROCESSAMENTO (MUITO IMPORTANTE):
    1. DOCUMENTO 1 (MESTRE): Este é o arquivo base. Você deve extrair TODOS os registros e TODOS os campos originais deste documento. Não oculte nenhuma informação dele.
    2. DOCUMENTOS ADICIONAIS (2, 3, etc.): São fontes de enriquecimento. 
       - Procure por correspondências no Documento 1 usando Nome Completo ou CPF.
       - Quando encontrar um match, adicione a informação solicitada pelo usuário em uma NOVA COLUNA específica (ex: "Valor (Relatório 2)").
       - Se não houver correspondência, apenas ignore esse dado extra ou crie uma linha nova se fizer sentido no contexto, mas priorize manter a estrutura do Documento 1.

    REGRAS DE FORMATAÇÃO:
    - VALORES: Sempre "R$ 1.250,00" (vírgula decimal, ponto milhar).
    - DATAS: DD/MM/AAAA.
    - NOMES: Mantenha em caixa alta para padronização.

    SAÍDA:
    - Responda APENAS com o JSON.
    - Estrutura: { "data": [ {"NOME": "...", "VALOR (RELATÓRIO 1)": "...", "VALOR (RELATÓRIO 2)": "...", "CPF": "..."} ], "summary": "Explicação curta do que foi mesclado" }
  `;

  const finalPrompt = `
    INSTRUÇÃO ESPECÍFICA DO USUÁRIO: ${prompt}

    TEXTO DOS DOCUMENTOS (O DOC 1 É O PRINCIPAL):
    ${textContent ? textContent : 'Analise os anexos fornecidos.'}
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { 
        parts: [
          ...fileParts,
          { text: finalPrompt }
        ] 
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        temperature: 0.1,
      }
    });

    const textResponse = response.text || '{"data":[]}';
    const result = JSON.parse(textResponse);

    return {
      data: result.data || [],
      headers: result.data?.length > 0 ? Object.keys(result.data[0]) : [],
      summary: result.summary
    };
  } catch (error) {
    console.error("Erro na extração rápida:", error);
    return { data: [], headers: [], summary: "Erro no processamento rápido de consolidação." };
  }
};

import React, { useState } from 'react';
import { 
  FileText, 
  Upload, 
  Search, 
  CheckCircle, 
  Download, 
  Trash2, 
  AlertCircle,
  Table as TableIcon,
  ChevronRight,
  FileSpreadsheet,
  Plus,
  Loader2,
  Zap,
  X,
  UploadCloud,
  FileJson,
  Image as ImageIcon,
  FileCode,
  Info
} from 'lucide-react';
import * as XLSX from 'xlsx';

import { FileMetadata, ProcessingResult, ExtractedData, FileType } from './types';
import { fileToBase64, parseExcel, parseCsv, extractPdfTextInChunks } from './utils/fileUtils';
import { extractDataFromReport } from './services/geminiService';

const COMMON_FIELDS = [
  { label: 'Nome', value: 'Nome' },
  { label: 'Valor (R$)', value: 'Valor' },
  { label: 'CPF', value: 'CPF' },
  { label: 'Data', value: 'Data' },
  { label: 'Mesclar por CPF', value: 'junte as informações usando o CPF como chave' },
  { label: 'Mesclar por Nome', value: 'junte as informações usando o Nome como chave' },
];

const App: React.FC = () => {
  const [files, setFiles] = useState<FileMetadata[]>([]);
  const [instruction, setInstruction] = useState('Manter todos os dados do Relatório 1. Do Relatório 2, buscar o Valor correspondente por CPF/Nome e adicionar em uma nova coluna "Valor (Relatório 2)". Formatar tudo em R$.');
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, phase: '' });
  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFiles = e.target.files;
    if (selectedFiles) {
      const newFiles: FileMetadata[] = Array.from(selectedFiles).map((f: File) => {
        let detectedType: FileType = 'unknown';
        const name = f.name.toLowerCase();
        if (name.endsWith('.pdf')) detectedType = 'pdf';
        else if (name.endsWith('.xlsx') || name.endsWith('.xls')) detectedType = 'excel';
        else if (name.endsWith('.csv')) detectedType = 'text';
        else if (f.type.includes('image')) detectedType = 'image';
        else if (f.type.includes('text') || name.endsWith('.txt')) detectedType = 'text';

        return { name: f.name, size: f.size, type: detectedType, raw: f };
      });
      setFiles(prev => [...prev, ...newFiles]);
      setResult(null);
      setError(null);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const handleProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setResult(null);
    setError(null);

    let allExtractedText = "";
    let imageParts: { inlineData: { data: string; mimeType: string } }[] = [];

    try {
      for (let idx = 0; idx < files.length; idx++) {
        const file = files[idx];
        const docLabel = idx === 0 ? "RELATÓRIO 1 (MESTRE)" : `RELATÓRIO ${idx + 1}`;
        setProgress({ current: idx + 1, total: files.length, phase: `Processando ${docLabel}...` });

        let fileText = "";
        if (file.type === 'pdf') {
          const chunks = await extractPdfTextInChunks(file.raw, 100);
          fileText = chunks.join("\n");
        } else if (file.type === 'excel') {
          fileText = await parseExcel(file.raw);
        } else if (file.raw.name.toLowerCase().endsWith('.csv')) {
          fileText = await parseCsv(file.raw);
        } else if (file.type === 'image') {
          const b64 = await fileToBase64(file.raw);
          imageParts.push({ inlineData: { data: b64, mimeType: file.raw.type } });
          fileText = "[Conteúdo em Imagem Anexada]";
        } else if (file.type === 'text') {
          fileText = await file.raw.text();
        }

        allExtractedText += `\n\n=== INÍCIO DO ${docLabel} ===\n${fileText}\n=== FIM DO ${docLabel} ===\n`;
      }

      setProgress({ current: 100, total: 100, phase: 'IA consolidando informações mestre...' });
      const extractionResult = await extractDataFromReport(instruction, imageParts, allExtractedText);
      setResult(extractionResult);
    } catch (err: any) {
      setError(err.message || "Erro ao tentar mesclar os documentos.");
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;
    const ws = XLSX.utils.json_to_sheet(result.data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Dados Consolidados");
    XLSX.writeFile(wb, `consolidacao_mestre_${Date.now()}.xlsx`);
  };

  const getFileIcon = (type: string, name: string) => {
    const ext = name.toLowerCase().split('.').pop();
    if (ext === 'pdf') return <FileText className="text-red-500 w-5 h-5" />;
    if (ext === 'xlsx' || ext === 'xls') return <FileSpreadsheet className="text-green-600 w-5 h-5" />;
    return <FileJson className="text-slate-400 w-5 h-5" />;
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20 font-sans">
      <header className="bg-white border-b border-slate-200 p-4 sticky top-0 z-20 shadow-sm">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-[#4f46e5] rounded-xl text-white shadow-lg shadow-indigo-100"><Zap className="w-5 h-5 fill-current" /></div>
            <h1 className="text-xl font-bold tracking-tight text-slate-900">SmartReport <span className="text-[#4f46e5]">Pro</span></h1>
          </div>
          <div className="hidden sm:flex items-center gap-2 px-4 py-1.5 bg-indigo-50 border border-indigo-100 rounded-full">
            <div className="w-2 h-2 bg-[#4f46e5] rounded-full animate-pulse"></div>
            <span className="text-[10px] font-black text-[#4f46e5] uppercase tracking-widest">Multi-Relatórios Mestre</span>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-12">
        {!result && !isProcessing && (
          <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 p-10 md:p-14 animate-in fade-in zoom-in-95 duration-500">
            <div className="text-center mb-10">
              <h2 className="text-4xl font-black text-slate-900 mb-2 tracking-tight">Processador de Larga Escala</h2>
              <p className="text-slate-500 text-lg font-medium">Junte relatórios diferentes mantendo um como base principal.</p>
            </div>

            <div className="border-[3px] border-dashed border-slate-100 rounded-[2rem] p-12 flex flex-col items-center justify-center bg-slate-50/40 hover:bg-slate-50/80 transition-all group">
              <UploadCloud className="w-20 h-20 text-[#4f46e5] mb-6 group-hover:scale-110 transition-transform" />
              <input type="file" id="multi-file" className="hidden" multiple onChange={handleFileChange} accept=".pdf,.xlsx,.xls,.csv,.txt,.png,.jpg,.jpeg,.webp" />
              <label 
                htmlFor="multi-file" 
                className="bg-[#4f46e5] text-white px-12 py-5 rounded-[1.25rem] font-bold text-xl cursor-pointer hover:bg-[#4338ca] shadow-2xl transition-all mb-4"
              >
                Selecionar Relatórios
              </label>
              <p className="text-slate-400 font-bold uppercase text-[11px] tracking-widest">PDF, Excel ou Imagens</p>
            </div>

            {files.length > 0 && (
              <div className="mt-12 space-y-8 animate-in slide-in-from-bottom-6">
                <div className="bg-slate-50/80 rounded-[1.5rem] p-6 border border-slate-100">
                  <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4 px-2">Documentos Carregados</h3>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 max-h-[250px] overflow-y-auto pr-2 custom-scrollbar">
                    {files.map((f, i) => (
                      <div key={i} className={`flex items-center justify-between p-4 rounded-2xl border bg-white shadow-sm transition-all ${i === 0 ? 'border-indigo-500 ring-2 ring-indigo-50' : 'border-slate-100'}`}>
                        <div className="flex items-center gap-3 overflow-hidden">
                          <div className="relative">
                            {getFileIcon(f.type, f.name)}
                            {i === 0 && (
                              <div className="absolute -top-2 -left-2 bg-indigo-600 text-white text-[8px] px-1.5 py-0.5 rounded-full font-black uppercase">Mestre</div>
                            )}
                          </div>
                          <div className="flex flex-col overflow-hidden">
                            <span className="text-sm font-bold text-slate-700 truncate">{f.name}</span>
                            <span className="text-[10px] text-slate-400 font-black uppercase">{i === 0 ? 'Documento Base' : `Fonte de Dados ${i}`}</span>
                          </div>
                        </div>
                        <button onClick={() => removeFile(i)} className="p-2 text-slate-300 hover:text-red-500 transition-all"><X className="w-4 h-4" /></button>
                      </div>
                    ))}
                  </div>
                  {files.length > 1 && (
                    <div className="mt-4 flex items-center gap-2 px-3 py-2 bg-indigo-50 text-indigo-700 rounded-xl text-[10px] font-bold uppercase tracking-widest">
                      <Info className="w-3 h-3" />
                      Dica: O primeiro arquivo carregado será usado como a base de dados principal.
                    </div>
                  )}
                </div>

                <div className="space-y-6">
                  <div className="flex flex-col gap-2">
                    <label className="text-sm font-black text-slate-700 uppercase tracking-widest px-1">O que extrair do Relatório 2?</label>
                    <div className="flex flex-wrap gap-2">
                      {COMMON_FIELDS.map(f => (
                        <button 
                          key={f.value} 
                          onClick={() => setInstruction(i => `${i} ${f.value},`)}
                          className="px-4 py-2 bg-white border border-slate-200 hover:border-[#4f46e5] rounded-full text-[11px] font-black uppercase tracking-tighter transition-all"
                        >
                          + {f.label}
                        </button>
                      ))}
                    </div>
                  </div>
                  <textarea 
                    value={instruction} 
                    onChange={e => setInstruction(e.target.value)}
                    className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-6 min-h-[120px] focus:border-[#4f46e5] outline-none transition-all font-semibold text-slate-700"
                  />
                  <button 
                    onClick={handleProcess}
                    className="w-full bg-[#4f46e5] text-white py-6 rounded-2xl font-black text-2xl hover:bg-[#4338ca] shadow-2xl flex items-center justify-center gap-4 transition-all active:scale-[0.98]"
                  >
                    Consolidar Relatórios <ChevronRight className="w-8 h-8" />
                  </button>
                </div>
              </div>
            )}
          </div>
        )}

        {isProcessing && (
          <div className="bg-white rounded-[2.5rem] shadow-2xl p-16 text-center space-y-10">
            <div className="relative w-48 h-48 mx-auto">
              <div className="absolute inset-0 border-[14px] border-slate-50 rounded-full"></div>
