import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ExtractedData, ProcessingResult } from "../types";

// Usando a chave de API do ambiente conforme as diretrizes
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const extractDataFromReport = async (
  prompt: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  // Modelo Flash Lite para ultra velocidade e baixa latência
  const model = 'gemini-flash-lite-latest';

  const systemInstruction = `
    Você é um motor de processamento de dados especializado em CONSOLIDAÇÃO MESTRE.

    ESTRATÉGIA DE EXECUÇÃO (OBRIGATÓRIA):
    1. O DOCUMENTO 1 é o seu MESTRE. Você deve manter 100% dos dados, linhas e colunas originais dele. NUNCA remova uma coluna que exista no Documento 1.
    2. O DOCUMENTO 2 (e seguintes) serve apenas para ENRIQUECIMENTO.
    3. Para cada linha do DOCUMENTO 1, tente encontrar o correspondente no DOCUMENTO 2 usando o CPF ou Nome Completo.
    4. Se encontrar, extraia a informação solicitada (ex: Valor) e coloque em uma NOVA COLUNA rotulada claramente, como "VALOR (RELATÓRIO 2)".
    5. Se NÃO encontrar correspondência no DOCUMENTO 2, deixe o campo como vazio ou "-" (NUNCA coloque "0" ou "0,00" se o dado não existir, pois isso altera o relatório).

    REGRAS DE FORMATAÇÃO:
    - VALORES: Mantenha o formato "R$ 1.250,50". Use vírgula para decimais.
    - INTEGRIDADE: Se o Documento 1 tem 10 colunas, o resultado final deve ter pelo menos essas 10 colunas, mais as novas colunas extraídas dos outros documentos.

    SAÍDA:
    - Responda APENAS com o JSON estruturado.
    - Formato: { "data": [ { "CAMPO_ORIGINAL_1": "...", "CAMPO_ORIGINAL_2": "...", "VALOR (RELATÓRIO 2)": "..." } ], "summary": "Resumo técnico da mesclagem" }
  `;

  const finalPrompt = `
    DETERMINAÇÃO DO USUÁRIO: ${prompt}

    CONTEXTO DOS ARQUIVOS:
    O texto abaixo contém os dados dos documentos. O "DOCUMENTO 1" deve ter todas as suas informações preservadas integralmente.

    ${textContent ? textContent : 'Analise os anexos fornecidos.'}
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { 
        parts: [
          ...fileParts,
          { text: finalPrompt }
        ] 
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        temperature: 0.1,
      }
    });

    const textResponse = response.text || '{"data":[]}';
    const result = JSON.parse(textResponse);

    return {
      data: result.data || [],
      headers: result.data?.length > 0 ? Object.keys(result.data[0]) : [],
      summary: result.summary
    };
  } catch (error) {
    console.error("Erro na extração mestre:", error);
    return { data: [], headers: [], summary: "Erro no processamento de consolidação mestre." };
  }
};

import React, { useState, useEffect } from 'react';
import { 
  FileText, 
  Upload, 
  Search, 
  CheckCircle, 
  Download, 
  Trash2, 
  AlertCircle,
  Table as TableIcon,
  ChevronRight,
  FileSpreadsheet,
  Plus,
  Loader2,
  Zap,
  X,
  UploadCloud,
  FileJson,
  Image as ImageIcon,
  FileCode,
  Info,
  Settings2,
  Eye,
  EyeOff,
  Database
} from 'lucide-react';
import * as XLSX from 'xlsx';

import { FileMetadata, ProcessingResult, ExtractedData, FileType } from './types';
import { fileToBase64, parseExcel, parseCsv, extractPdfTextInChunks } from './utils/fileUtils';
import { extractDataFromReport } from './services/geminiService';

const COMMON_FIELDS = [
  { label: 'Nome', value: 'Nome' },
  { label: 'Valor (R$)', value: 'Valor' },
  { label: 'CPF', value: 'CPF' },
  { label: 'Tudo do Relatório 1', value: 'Mantenha ABSOLUTAMENTE TODAS as colunas e linhas do Relatório 1 sem alterações.' },
  { label: 'Mesclar por CPF', value: 'Busque no Relatório 2 usando o CPF como chave única.' },
];

const App: React.FC = () => {
  const [files, setFiles] = useState<FileMetadata[]>([]);
  const [instruction, setInstruction] = useState('Copie TODOS os campos do Relatório 1 para o resultado. Em seguida, localize cada pessoa no Relatório 2 pelo CPF ou Nome e adicione o Valor dele em uma nova coluna chamada "VALOR (RELATÓRIO 2)". Não apague nada do 1 e não coloque zeros se não encontrar correspondência.');
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, phase: '' });
  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [visibleColumns, setVisibleColumns] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [showColumnSettings, setShowColumnSettings] = useState(false);

  useEffect(() => {
    if (result) {
      setVisibleColumns(result.headers);
    }
  }, [result]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFiles = e.target.files;
    if (selectedFiles) {
      const newFiles: FileMetadata[] = Array.from(selectedFiles).map((f: File) => {
        let detectedType: FileType = 'unknown';
        const name = f.name.toLowerCase();
        if (name.endsWith('.pdf')) detectedType = 'pdf';
        else if (name.endsWith('.xlsx') || name.endsWith('.xls')) detectedType = 'excel';
        else if (name.endsWith('.csv')) detectedType = 'text';
        else if (f.type.includes('image')) detectedType = 'image';
        else if (f.type.includes('text') || name.endsWith('.txt')) detectedType = 'text';

        return { name: f.name, size: f.size, type: detectedType, raw: f };
      });
      setFiles(prev => [...prev, ...newFiles]);
      setResult(null);
      setError(null);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const toggleColumn = (col: string) => {
    setVisibleColumns(prev => 
      prev.includes(col) ? prev.filter(c => c !== col) : [...prev, col]
    );
  };

  const handleProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setResult(null);
    setError(null);
    setShowColumnSettings(false);

    let allExtractedText = "";
    let imageParts: { inlineData: { data: string; mimeType: string } }[] = [];

    try {
      for (let idx = 0; idx < files.length; idx++) {
        const file = files[idx];
        const docTitle = idx === 0 ? "DOCUMENTO 1 (BASE MESTRE - NÃO ALTERAR)" : `DOCUMENTO ${idx + 1} (FONTE DE ENRIQUECIMENTO)`;
        setProgress({ current: idx + 1, total: files.length, phase: `Analisando ${docTitle}...` });

        let fileText = "";
        if (file.type === 'pdf') {
          const chunks = await extractPdfTextInChunks(file.raw, 100);
          fileText = chunks.join("\n");
        } else if (file.type === 'excel') {
          fileText = await parseExcel(file.raw);
        } else if (file.raw.name.toLowerCase().endsWith('.csv')) {
          fileText = await parseCsv(file.raw);
        } else if (file.type === 'image') {
          const b64 = await fileToBase64(file.raw);
          imageParts.push({ inlineData: { data: b64, mimeType: file.raw.type } });
          fileText = "[Ver Imagem em Anexo]";
        } else if (file.type === 'text') {
          fileText = await file.raw.text();
        }

        allExtractedText += `\n\n#########################################\n# INÍCIO DO ${docTitle}\n#########################################\n${fileText}\n#########################################\n# FIM DO ${docTitle}\n#########################################\n`;
      }

      setProgress({ current: 100, total: 100, phase: 'IA preservando dados mestre e mesclando...' });
      const extractionResult = await extractDataFromReport(instruction, imageParts, allExtractedText);
      setResult(extractionResult);
    } catch (err: any) {
      setError(err.message || "Erro crítico na consolidação dos dados.");
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;
    const filteredData = result.data.map(row => {
      const filteredRow: any = {};
      visibleColumns.forEach(col => {
        filteredRow[col] = row[col];
      });
      return filteredRow;
    });
    const ws = XLSX.utils.json_to_sheet(filteredData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Relatório Consolidado");
    XLSX.writeFile(wb, `relatorio_mestre_final_${Date.now()}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20 font-sans">
      <header className="bg-white border-b border-slate-200 p-4 sticky top-0 z-20 shadow-sm">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-[#4f46e5] rounded-xl text-white shadow-lg shadow-indigo-100"><Zap className="w-5 h-5 fill-current" /></div>
            <h1 className="text-xl font-bold tracking-tight text-slate-900">SmartReport <span className="text-[#4f46e5]">Mestre</span></h1>
          </div>
          <div className="hidden sm:flex items-center gap-2 px-4 py-1.5 bg-green-50 border border-green-100 rounded-full">
            <Database className="w-3 h-3 text-green-600" />
            <span className="text-[10px] font-black text-green-700 uppercase tracking-widest">Preservação de Dados Ativa</span>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-12">
        {!result && !isProcessing && (
          <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 p-10 md:p-14 animate-in fade-in zoom-in-95 duration-500">
            <div className="text-center mb-10">
              <h2 className="text-4xl font-black text-slate-900 mb-2 tracking-tight">Consolidador Inteligente</h2>
              <p className="text-slate-500 text-lg font-medium">Use o primeiro arquivo como base e complete com os outros.</p>
            </div>

            <div className="border-[3px] border-dashed border-slate-100 rounded-[2rem] p-12 flex flex-col items-center justify-center bg-slate-50/40 hover:bg-slate-50/80 transition-all group">
              <UploadCloud className="w-20 h-20 text-[#4f46e5] mb-6 group-hover:scale-110 transition-transform" />
              <input type="file" id="multi-file" className="hidden" multiple onChange={handleFileChange} accept=".pdf,.xlsx,.xls,.csv,.txt,.png,.jpg,.jpeg,.webp" />
              <label 
                htmlFor="multi-file" 
                className="bg-[#4f46e5] text-white px-12 py-5 rounded-[1.25rem] font-bold text-xl cursor-pointer hover:bg-[#4338ca] shadow-2xl transition-all mb-4"
              >
                Selecionar Relatórios
              </label>
              <p className="text-slate-400 font-bold uppercase text-[11px] tracking-widest">O primeiro será o arquivo base</p>
            </div>

            {files.length > 0 && (
              <div className="mt-12 space-y-8 animate-in slide-in-from-bottom-6">
                <div className="bg-slate-50/80 rounded-[1.5rem] p-6 border border-slate-100">
                  <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4 px-2">Estrutura de Arquivos</h3>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    {files.map((f, i) => (
                      <div key={i} className={`flex items-center justify-between p-4 rounded-2xl border bg-white shadow-sm transition-all ${i === 0 ? 'border-indigo-500 ring-2 ring-indigo-50 bg-indigo-50/10' : 'border-slate-100'}`}>
                        <div className="flex items-center gap-3 overflow-hidden">
                          <div className="relative">
                            {f.type === 'pdf' ? <FileText className="text-red-500 w-5 h-5" /> : <FileSpreadsheet className="text-green-600 w-5 h-5" />}
                            {i === 0 && <div className="absolute -top-2 -left-2 bg-indigo-600 text-white text-[8px] px-1.5 py-0.5 rounded-full font-black">MESTRE</div>}
                          </div>
                          <div className="flex flex-col overflow-hidden">
                            <span className="text-sm font-bold text-slate-700 truncate">{f.name}</span>
                            <span className="text-[9px] text-slate-400 font-black uppercase">{i === 0 ? 'Documento Base (Manter Tudo)' : `Documento ${i+1} (Completa o 1)`}</span>
                          </div>
                        </div>
                        <button onClick={() => removeFile(i)} className="p-2 text-slate-300 hover:text-red-500 transition-all"><X className="w-4 h-4" /></button>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="space-y-6">
                  <div className="flex flex-col gap-2">
                    <label className="text-sm font-black text-slate-700 uppercase tracking-widest px-1">Instruções para a IA</label>
                    <div className="flex flex-wrap gap-2">
                      {COMMON_FIELDS.map(f => (
                        <button 
                          key={f.label} 
                          onClick={() => setInstruction(i => `${i} ${f.value}`)}
                          className="px-4 py-2 bg-white border border-slate-200 hover:border-[#4f46e5] rounded-full text-[11px] font-black uppercase tracking-tighter transition-all"
                        >
                          + {f.label}
                        </button>
                      ))}
                    </div>
                  </div>
                  <textarea 
                    value={instruction} 
                    onChange={e => setInstruction(e.target.value)}
                    className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-6 min-h-[140px] focus:border-[#4f46e5] outline-none transition-all font-semibold text-slate-700 shadow-inner"
                  />
                  <button 
                    onClick={handleProcess}
                    className="w-full bg-[#4f46e5] text-white py-6 rounded-2xl font-black text-2xl hover:bg-[#4338ca] shadow-2xl flex items-center justify-center gap-4 transition-all active:scale-[0.98]"
                  >
                    Gerar Relatório Consolidado <ChevronRight className="w-8 h-8" />
                  </button>
                </div>
              </div>
            )}
          </div>
        )}

        {isProcessing && (
          <div className="bg-white rounded-[2.5rem] shadow-2xl p-16 text-center space-y-10">
            <div className="relative w-48 h-48 mx-auto">
              <div className="absolute inset-0 border-[14px] border-slate-50 rounded-full"></div>
              <div className="absolute inset-0 border-[14px] border-[#4f46e5] rounded-full border-t-transparent animate-spin"></div>
              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <Loader2 className="w-12 h-12 text-[#4f46e5] animate-pulse" />
                <span className="text-3xl font-black text-slate-900">{Math.round((progress.current / progress.total) * 100) || 0}%</span>
              </div>
            </div>
            <h3 className="text-3xl font-black text-slate-900 tracking-tight">{progress.phase}</h3>
            <p className="text-slate-400 font-medium">Isso pode levar alguns segundos dependendo do tamanho dos arquivos.</p>
          </div>
        )}

        {result && (
          <div className="space-y-8 animate-in fade-in duration-700">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
              <div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tight">Relatório Mestre Gerado</h2>
                <div className="flex items-center gap-3 mt-2">
                  <div className="px-3 py-1 bg-green-50 border border-green-100 rounded-lg flex items-center gap-2">
                    <CheckCircle className="w-4 h-4 text-green-600" />
                    <span className="text-xs font-black text-green-700 uppercase tracking-widest">{result.data.length} Linhas Processadas</span>
                  </div>
                  <div className="px-3 py-1 bg-indigo-50 border border-indigo-100 rounded-lg text-indigo-700 text-[10px] font-black uppercase tracking-widest">
                    Formatação R$ BRL
                  </div>
                </div>
              </div>
              <div className="flex gap-3">
                <button onClick={() => setShowColumnSettings(!showColumnSettings)} className={`px-6 py-4 border-2 font-bold rounded-2xl transition-all flex items-center gap-2 ${showColumnSettings ? 'bg-[#4f46e5] border-[#4f46e5] text-white' : 'bg-white border-slate-100 text-slate-500'}`}><Settings2 className="w-5 h-5" /> Colunas</button>
                <button onClick={() => {setResult(null); setFiles([]);}} className="px-6 py-4 bg-white border-2 border-slate-100 font-bold rounded-2xl text-slate-400 hover:bg-slate-50 transition-all">Limpar</button>
                <button onClick={downloadExcel} className="px-8 py-4 bg-green-600 text-white font-black rounded-2xl hover:bg-green-700 shadow-xl flex items-center gap-3 text-lg transition-all active:scale-95"><Download className="w-6 h-6" /> Exportar Planilha</button>
              </div>
            </div>

            {showColumnSettings && (
              <div className="bg-white p-6 rounded-[2rem] border-2 border-indigo-100 shadow-xl animate-in slide-in-from-top-4 duration-300">
                <h3 className="text-xs font-black text-slate-700 uppercase tracking-widest mb-4">Gerenciar Colunas Visíveis</h3>
                <div className="flex flex-wrap gap-2">
                  {result.headers.map(h => (
                    <button
                      key={h}
                      onClick={() => toggleColumn(h)}
                      className={`px-4 py-2 rounded-xl text-[11px] font-black uppercase transition-all flex items-center gap-2 border-2 ${visibleColumns.includes(h) ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'bg-slate-50 border-slate-100 text-slate-400 opacity-60'}`}
                    >
                      {visibleColumns.includes(h) ? <CheckCircle className="w-3 h-3" /> : <EyeOff className="w-3 h-3" />}
                      {h}
                    </button>
                  ))}
                </div>
              </div>
            )}

            <div className="bg-white border-2 border-slate-100 rounded-[2.5rem] overflow-hidden shadow-2xl">
              <div className="max-h-[650px] overflow-auto custom-scrollbar">
                <table className="w-full text-left border-collapse">
                  <thead className="sticky top-0 bg-[#0f172a] text-white z-10">
                    <tr>
                      {result.headers.filter(h => visibleColumns.includes(h)).map(h => (
                        <th key={h} className="px-8 py-6 text-[10px] font-black uppercase tracking-[0.2em] border-r border-white/5 whitespace-nowrap">
                          {h}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {result.data.map((row, i) => (
                      <tr key={i} className="hover:bg-indigo-50/20 transition-colors group">
                        {result.headers.filter(h => visibleColumns.includes(h)).map(h => (
                          <td key={`${i}-${h}`} className="px-8 py-5 text-[14px] font-bold text-slate-600 group-hover:text-[#4f46e5] whitespace-nowrap">
                            {row[h] === null || row[h] === undefined || row[h] === "" ? "-" : row[h]}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            {result.summary && (
              <div className="bg-[#0f172a] text-slate-100 p-10 rounded-[2rem] shadow-2xl">
                <div className="flex items-center gap-3 mb-4">
                  <Search className="w-6 h-6 text-indigo-400" />
                  <span className="text-xs font-black uppercase tracking-[0.3em] text-indigo-300">Resumo da Inteligência Artificial</span>
                </div>
                <p className="text-lg leading-relaxed font-semibold opacity-90 italic">"{result.summary}"</p>
              </div>
            )}
          </div>
        )}

        {error && (
          <div className="bg-red-50 border-2 border-red-100 p-10 rounded-[2rem] text-center md:text-left text-red-700 mt-10 shadow-lg">
            <AlertCircle className="w-16 h-16 mx-auto md:mx-0 mb-4 opacity-80" />
            <p className="text-2xl font-black mb-2">Erro na Consolidação</p>
            <p className="font-bold opacity-70 mb-6 leading-tight">{error}</p>
            <button onClick={() => setIsProcessing(false)} className="bg-red-600 text-white px-10 py-3 rounded-xl font-black uppercase tracking-widest shadow-xl">Tentar Novamente</button>
          </div>
        )}
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 8px; height: 8px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #f1f5f9; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 20px; border: 2px solid #f1f5f9; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #94a3b8; }
      `}</style>
    </div>
  );
};

