import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ExtractedData, ProcessingResult } from "../types";

// Usando a chave de API do ambiente conforme as diretrizes
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Limpa a resposta da IA removendo blocos de código Markdown se existirem.
 */
const cleanJsonResponse = (text: string): string => {
  let cleaned = text.trim();
  // Remove ```json ... ``` ou ``` ... ```
  cleaned = cleaned.replace(/^```json\s*/i, "").replace(/^```\s*/i, "");
  cleaned = cleaned.replace(/\s*```$/i, "");
  return cleaned;
};

export const extractDataFromReport = async (
  prompt: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  // Mudando para o modelo Gemini 3 Flash para maior capacidade de raciocínio em consolidação
  const model = 'gemini-3-flash-preview';

  const systemInstruction = `
    Você é um especialista em PROCESSAMENTO DE DADOS e CONSOLIDAÇÃO MESTRE.
    Sua tarefa é unir informações de múltiplos documentos sem perder nada do arquivo principal.

    REGRAS CRÍTICAS:
    1. O "DOCUMENTO 1" é sagrado. Você deve extrair TODAS as linhas e TODAS as colunas dele. Não remova, não oculte e não resuma.
    2. O "DOCUMENTO 2" (e outros) serve para adicionar colunas extras. Procure por CPF ou NOME para dar "match".
    3. Se encontrar o match, crie colunas como "VALOR (RELATÓRIO 2)".
    4. Se NÃO encontrar correspondência, o campo deve ser null ou "-" (NUNCA coloque 0 se o dado não existir).
    5. Formate VALORES como "R$ 0.000,00" (padrão BRL).

    SAÍDA:
    Retorne APENAS um objeto JSON puro. Não escreva textos explicativos antes ou depois.
    Formato: { "data": [ { "Campo1": "...", "Campo2": "...", "Extra": "..." } ], "summary": "Texto curto do que foi feito" }
  `;

  const finalPrompt = `
    INSTRUÇÃO DO USUÁRIO: ${prompt}

    DADOS DOS DOCUMENTOS (PRIORIZE A ESTRUTURA DO DOCUMENTO 1):
    ${textContent ? textContent : 'Analise os anexos fornecidos.'}
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { 
        parts: [
          ...fileParts,
          { text: finalPrompt }
        ] 
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        temperature: 0.1,
      }
    });

    const rawText = response.text || "";
    const cleanedText = cleanJsonResponse(rawText);

    try {
      const result = JSON.parse(cleanedText);

      // Validação básica dos dados retornados
      if (!result.data || !Array.isArray(result.data)) {
        throw new Error("Formato de dados inválido retornado pela IA.");
      }

      return {
        data: result.data,
        headers: result.data.length > 0 ? Object.keys(result.data[0]) : [],
        summary: result.summary || "Processamento concluído com sucesso."
      };
    } catch (parseError) {
      console.error("Erro ao parsear JSON da IA:", parseError, "Texto bruto:", rawText);
      return { 
        data: [], 
        headers: [], 
        summary: "A IA gerou uma resposta em formato inválido. Tente simplificar a instrução." 
      };
    }
  } catch (error) {
    console.error("Erro na chamada da API Gemini:", error);
    return { 
      data: [], 
      headers: [], 
      summary: "Erro na comunicação com a Inteligência Artificial. Verifique o tamanho dos arquivos." 
    };
  }
};

import React, { useState, useEffect } from 'react';
import { 
  FileText, 
  Upload, 
  Search, 
  CheckCircle, 
  Download, 
  Trash2, 
  AlertCircle,
  Table as TableIcon,
  ChevronRight,
  FileSpreadsheet,
  Plus,
  Loader2,
  Zap,
  X,
  UploadCloud,
  FileJson,
  Image as ImageIcon,
  FileCode,
  Info,
  Settings2,
  Eye,
  EyeOff,
  Database
} from 'lucide-react';
import * as XLSX from 'xlsx';

import { FileMetadata, ProcessingResult, ExtractedData, FileType } from './types';
import { fileToBase64, parseExcel, parseCsv, extractPdfTextInChunks } from './utils/fileUtils';
import { extractDataFromReport } from './services/geminiService';

const COMMON_FIELDS = [
  { label: 'Nome', value: 'Nome' },
  { label: 'Valor (R$)', value: 'Valor em Reais' },
  { label: 'CPF', value: 'CPF completo' },
  { label: 'Tudo do Relatório 1', value: 'Manter todas as colunas originais do Relatório 1.' },
  { label: 'Cruzamento por CPF', value: 'Localizar dados no Relatório 2 usando o CPF.' },
];

const App: React.FC = () => {
  const [files, setFiles] = useState<FileMetadata[]>([]);
  const [instruction, setInstruction] = useState('Extraia todas as colunas do Relatório 1. Do Relatório 2, busque apenas o Valor e coloque em uma nova coluna "Valor (Relatório 2)", cruzando pelo CPF ou Nome. Formate tudo em BRL (R$).');
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, phase: '' });
  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [visibleColumns, setVisibleColumns] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [showColumnSettings, setShowColumnSettings] = useState(false);

  useEffect(() => {
    if (result && result.data.length > 0) {
      setVisibleColumns(result.headers);
    }
  }, [result]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFiles = e.target.files;
    if (selectedFiles) {
      const newFiles: FileMetadata[] = Array.from(selectedFiles).map((f: File) => {
        let detectedType: FileType = 'unknown';
        const name = f.name.toLowerCase();
        if (name.endsWith('.pdf')) detectedType = 'pdf';
        else if (name.endsWith('.xlsx') || name.endsWith('.xls')) detectedType = 'excel';
        else if (name.endsWith('.csv')) detectedType = 'text';
        else if (f.type.includes('image')) detectedType = 'image';
        else if (f.type.includes('text') || name.endsWith('.txt')) detectedType = 'text';

        return { name: f.name, size: f.size, type: detectedType, raw: f };
      });
      setFiles(prev => [...prev, ...newFiles]);
      setResult(null);
      setError(null);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const toggleColumn = (col: string) => {
    setVisibleColumns(prev => 
      prev.includes(col) ? prev.filter(c => c !== col) : [...prev, col]
    );
  };

  const handleProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setResult(null);
    setError(null);
    setShowColumnSettings(false);

    let allExtractedText = "";
    let imageParts: { inlineData: { data: string; mimeType: string } }[] = [];

    try {
      for (let idx = 0; idx < files.length; idx++) {
        const file = files[idx];
        const label = idx === 0 ? "MASTER_RELATORIO_1" : `ENRICHMENT_RELATORIO_${idx + 1}`;
        setProgress({ current: idx + 1, total: files.length, phase: `Lendo ${file.name}...` });

        let fileText = "";
        if (file.type === 'pdf') {
          const chunks = await extractPdfTextInChunks(file.raw, 100);
          fileText = chunks.join("\n");
        } else if (file.type === 'excel') {
          fileText = await parseExcel(file.raw);
        } else if (file.raw.name.toLowerCase().endsWith('.csv')) {
          fileText = await parseCsv(file.raw);
        } else if (file.type === 'image') {
          const b64 = await fileToBase64(file.raw);
          imageParts.push({ inlineData: { data: b64, mimeType: file.raw.type } });
          fileText = `[IMAGEM PROCESSADA: ${file.name}]`;
        } else if (file.type === 'text') {
          fileText = await file.raw.text();
        }

        allExtractedText += `\n\n--- INÍCIO DO DOCUMENTO: ${label} ---\n${fileText}\n--- FIM DO DOCUMENTO: ${label} ---\n`;
      }

      setProgress({ current: 100, total: 100, phase: 'IA consolidando dados mestre...' });
      const extractionResult = await extractDataFromReport(instruction, imageParts, allExtractedText);

      if (extractionResult.data.length === 0) {
        throw new Error("A IA não conseguiu extrair dados válidos. Verifique se os arquivos contêm tabelas legíveis.");
      }

      setResult(extractionResult);
    } catch (err: any) {
      setError(err.message || "Erro desconhecido no processamento.");
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;
    const filteredData = result.data.map(row => {
      const filteredRow: any = {};
      visibleColumns.forEach(col => {
        filteredRow[col] = row[col];
      });
      return filteredRow;
    });
    const ws = XLSX.utils.json_to_sheet(filteredData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Consolidado");
    XLSX.writeFile(wb, `relatorio_final_${Date.now()}.xlsx`);
  };

  return (
