import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ExtractedData, ProcessingResult } from "../types";

// Usando a chave de API do ambiente conforme as diretrizes
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Limpa a resposta da IA removendo blocos de código Markdown se existirem.
 */
const cleanJsonResponse = (text: string): string => {
  let cleaned = text.trim();
  // Remove blocos de código markdown (ex: ```json ... ```)
  cleaned = cleaned.replace(/^```[a-zA-Z]*\n?/gm, "").replace(/```$/gm, "");
  return cleaned.trim();
};

export const extractDataFromReport = async (
  userInstruction: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  // Mudando para o modelo Pro para tarefas de raciocínio complexo e consolidação de dados
  const model = 'gemini-3-pro-preview';

  const systemInstruction = `
    Você é um Assistente de Organização de Dados especializado em extração e consolidação de relatórios.
    Sua missão é ler o conteúdo dos documentos fornecidos e transformá-los em uma tabela JSON seguindo RIGOROSAMENTE as instruções do usuário.

    REGRAS DE OURO:
    1. Se houver múltiplos documentos, o "Relatório 1" (MASTER) é a base. Mantenha todos os dados dele, a menos que o usuário peça para filtrar.
    2. Use as instruções do usuário para decidir quais colunas criar e como cruzar os dados entre os arquivos (geralmente por Nome ou CPF).
    3. Se um dado solicitado não for encontrado em um dos relatórios, use null ou "-" em vez de 0.
    4. Formate todos os campos de valores financeiros para o padrão brasileiro: "R$ 1.250,00".
    5. Padronize CPFs para o formato 000.000.000-00 e Nomes para CAIXA ALTA.

    SAÍDA OBRIGATÓRIA:
    Retorne APENAS um objeto JSON válido. Não inclua conversas, explicações ou markdown fora do objeto.
    Estrutura: { "data": [ { "Coluna1": "...", "Coluna2": "..." } ], "summary": "Breve explicação do que foi feito" }
  `;

  const finalPrompt = `
    INSTRUÇÕES ESPECÍFICAS DO USUÁRIO: 
    ${userInstruction}

    CONTEÚDO DOS DOCUMENTOS PARA PROCESSAMENTO:
    ${textContent ? textContent : 'Analise os dados contidos nos arquivos anexados (imagens/PDFs).'}
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { 
        parts: [
          ...fileParts,
          { text: finalPrompt }
        ] 
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        temperature: 0.1, // Baixa temperatura para manter a extração fiel aos dados
      }
    });

    const rawText = response.text || "";
    const cleanedText = cleanJsonResponse(rawText);

    try {
      const result = JSON.parse(cleanedText);

      if (!result.data || !Array.isArray(result.data)) {
        console.error("Dados retornados não são uma lista:", result);
        return { data: [], headers: [], summary: "Ocorreu um erro na estruturação dos dados." };
      }

      const headers = result.data.length > 0 ? Object.keys(result.data[0]) : [];

      return {
        data: result.data,
        headers,
        summary: result.summary || "Processamento concluído."
      };
    } catch (parseError) {
      console.error("Falha ao parsear JSON:", cleanedText);
      return { 
        data: [], 
        headers: [], 
        summary: "A IA não conseguiu gerar uma tabela válida. Tente ser mais específico na descrição." 
      };
    }
  } catch (error) {
    console.error("Erro na API Gemini:", error);
    return { 
      data: [], 
      headers: [], 
      summary: "Erro na comunicação com a IA. Pode ser que o volume de dados seja muito grande." 
    };
  }
};

import React, { useState, useEffect } from 'react';
import { 
  FileText, 
  Upload, 
  Search, 
  CheckCircle, 
  Download, 
  Trash2, 
  AlertCircle,
  Table as TableIcon,
  ChevronRight,
  FileSpreadsheet,
  Plus,
  Loader2,
  Zap,
  X,
  UploadCloud,
  FileJson,
  Image as ImageIcon,
  FileCode,
  Info,
  Settings2,
  Eye,
  EyeOff,
  Database
} from 'lucide-react';
import * as XLSX from 'xlsx';

import { FileMetadata, ProcessingResult, ExtractedData, FileType } from './types';
import { fileToBase64, parseExcel, parseCsv, extractPdfTextInChunks } from './utils/fileUtils';
import { extractDataFromReport } from './services/geminiService';

const COMMON_FIELDS = [
  { label: 'Nome', value: 'Exibir nome em caixa alta.' },
  { label: 'Valor (R$)', value: 'Formatar valores como R$ 0,00.' },
  { label: 'CPF', value: 'Incluir coluna de CPF formatado.' },
  { label: 'Unir Arquivos', value: 'Procurar dados correspondentes entre os arquivos usando Nome ou CPF.' },
  { label: 'Tudo do Relatório 1', value: 'Manter todas as colunas originais do Relatório 1 no resultado final.' },
];

const App: React.FC = () => {
  const [files, setFiles] = useState<FileMetadata[]>([]);
  const [instruction, setInstruction] = useState('Use o Relatório 1 como base mestre. Do Relatório 2, encontre o "Valor" correspondente de cada pessoa (usando Nome ou CPF) e adicione em uma nova coluna chamada "VALOR_RELATORIO_2". Mantenha todos os outros dados do Relatório 1 intactos.');
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, phase: '' });
  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [visibleColumns, setVisibleColumns] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [showColumnSettings, setShowColumnSettings] = useState(false);

  useEffect(() => {
    if (result && result.data.length > 0) {
      setVisibleColumns(result.headers);
    }
  }, [result]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFiles = e.target.files;
    if (selectedFiles) {
      const newFiles: FileMetadata[] = Array.from(selectedFiles).map((f: File) => {
        let detectedType: FileType = 'unknown';
        const name = f.name.toLowerCase();
        if (name.endsWith('.pdf')) detectedType = 'pdf';
        else if (name.endsWith('.xlsx') || name.endsWith('.xls')) detectedType = 'excel';
        else if (name.endsWith('.csv')) detectedType = 'text';
        else if (f.type.includes('image')) detectedType = 'image';
        else if (f.type.includes('text') || name.endsWith('.txt')) detectedType = 'text';

        return { name: f.name, size: f.size, type: detectedType, raw: f };
      });
      setFiles(prev => [...prev, ...newFiles]);
      setResult(null);
      setError(null);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const toggleColumn = (col: string) => {
    setVisibleColumns(prev => 
      prev.includes(col) ? prev.filter(c => c !== col) : [...prev, col]
    );
  };

  const handleProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setResult(null);
    setError(null);
    setShowColumnSettings(false);

    let allExtractedText = "";
    let imageParts: { inlineData: { data: string; mimeType: string } }[] = [];

    try {
      for (let idx = 0; idx < files.length; idx++) {
        const file = files[idx];
        const label = `RELATÓRIO_${idx + 1}`;
        setProgress({ current: idx + 1, total: files.length, phase: `Lendo ${file.name}...` });

        let fileText = "";
        if (file.type === 'pdf') {
          const chunks = await extractPdfTextInChunks(file.raw, 100);
          fileText = chunks.join("\n");
        } else if (file.type === 'excel') {
          fileText = await parseExcel(file.raw);
        } else if (file.raw.name.toLowerCase().endsWith('.csv')) {
          fileText = await parseCsv(file.raw);
        } else if (file.type === 'image') {
          const b64 = await fileToBase64(file.raw);
          imageParts.push({ inlineData: { data: b64, mimeType: file.raw.type } });
          fileText = `[DADOS CONTIDOS NA IMAGEM: ${file.name}]`;
        } else if (file.type === 'text') {
          fileText = await file.raw.text();
        }

        allExtractedText += `\n\n--- INÍCIO DO ${label} (${file.name}) ---\n${fileText}\n--- FIM DO ${label} ---\n`;
      }

      setProgress({ current: 100, total: 100, phase: 'IA analisando e organizando dados...' });
      const extractionResult = await extractDataFromReport(instruction, imageParts, allExtractedText);

      if (extractionResult.data.length === 0) {
        throw new Error("A IA não conseguiu extrair dados válidos com as instruções atuais. Tente descrever de outra forma.");
      }

      setResult(extractionResult);
    } catch (err: any) {
      setError(err.message || "Erro no processamento dos arquivos.");
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;
    const filteredData = result.data.map(row => {
      const filteredRow: any = {};
      visibleColumns.forEach(col => {
        filteredRow[col] = row[col];
      });
      return filteredRow;
    });
    const ws = XLSX.utils.json_to_sheet(filteredData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Dados Consolidados");
    XLSX.writeFile(wb, `relatorio_organizado_${Date.now()}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20 font-sans selection:bg-indigo-100">
      <header className="bg-white border-b border-slate-200 p-4 sticky top-0 z-30 shadow-sm">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-[#4f46e5] rounded-xl text-white shadow-lg"><Zap className="w-5 h-5 fill-current" /></div>
            <h1 className="text-xl font-bold tracking-tight">SmartReport <span className="text-[#4f46e5]">Pro</span></h1>
          </div>
          <div className="hidden sm:flex items-center gap-2 px-4 py-1.5 bg-green-50 border border-green-100 rounded-full">
            <Database className="w-3 h-3 text-green-600" />
            <span className="text-[10px] font-black text-green-700 uppercase tracking-widest">IA Gemini 3 Pro Ativa</span>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-12">
        {!result && !isProcessing && (
          <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 p-10 md:p-14 animate-in fade-in duration-500">
            <div className="text-center mb-10">
              <h2 className="text-4xl font-black text-slate-900 mb-2 tracking-tight">Organizador Inteligente</h2>
              <p className="text-slate-500 text-lg font-medium leading-relaxed">Arraste seus relatórios e descreva como deseja uni-los.</p>
            </div>

            <div className="border-[3px] border-dashed border-slate-100 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50/40 hover:bg-slate-50 transition-all group">
              <UploadCloud className="w-16 h-16 text-indigo-200 mb-6 group-hover:scale-110 group-hover:text-[#4f46e5] transition-all" />
              <input type="file" id="multi-file" className="hidden" multiple onChange={handleFileChange} accept=".pdf,.xlsx,.xls,.csv,.txt,.png,.jpg,.jpeg,.webp" />
              <label 
                htmlFor="multi-file" 
                className="bg-[#4f46e5] text-white px-10 py-4 rounded-2xl font-bold text-lg cursor-pointer hover:bg-[#4338ca] shadow-xl transition-all mb-4 active:scale-95"
              >
                Selecionar Arquivos
              </label>
              <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest text-center">
                PDF, Excel, CSV ou Imagens (O Relatório 1 será o Master)
              </p>
            </div>

            {files.length > 0 && (
              <div className="mt-12 space-y-8 animate-in slide-in-from-bottom-6">
