                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            {result.summary && (
              <div className="bg-[#0f172a] text-slate-100 p-10 rounded-[2.5rem] shadow-2xl relative overflow-hidden">
