                    <span className="text-xs font-black uppercase tracking-[0.3em] text-indigo-300">Análise de IA</span>
                  </div>
                  <p className="text-lg leading-relaxed font-semibold opacity-90 italic">"{result.summary}"</p>
                </div>
              </div>
            )}
          </div>
        )}

        {error && (
          <div className="bg-red-50 border-2 border-red-100 p-10 rounded-[2.5rem] flex flex-col md:flex-row gap-8 items-center text-red-700 mt-10 shadow-2xl">
            <AlertCircle className="w-20 h-20 shrink-0 opacity-80 animate-bounce" />
            <div className="text-center md:text-left">
