import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ExtractedData, ProcessingResult } from "../types";

// Usando a chave de API do ambiente conforme as diretrizes
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Limpa a resposta da IA removendo blocos de código Markdown se existirem.
 */
const cleanJsonResponse = (text: string): string => {
  let cleaned = text.trim();
  // Remove blocos de código markdown (ex: ```json ... ```)
  cleaned = cleaned.replace(/^```[a-zA-Z]*\n?/gm, "").replace(/```$/gm, "");
  return cleaned.trim();
};

export const extractDataFromReport = async (
  userInstruction: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  // Modelo Gemini 3 Pro para tarefas de raciocínio complexo e consolidação de dados
  const model = 'gemini-3-pro-preview';

  const systemInstruction = `
    Você é um Assistente de Organização de Dados de alta precisão. Sua tarefa é consolidar relatórios seguindo regras rígidas de união (JOIN).

    REGRAS DE UNIÃO (JOINING LOGIC):
    1. PRIORIDADE DE CHAVE: Ao unir o Relatório 1 com outros documentos:
       - 1ª Prioridade: Use o campo 'CPF'. Se o CPF existir em ambos os documentos, ele é a única chave que importa.
       - 2ª Prioridade (Fallback): Se o CPF estiver ausente em UM dos documentos para um registro específico, utilize o 'NOME' como chave de comparação.
    2. INTEGRIDADE MESTRE: O Relatório 1 é a BASE. Mantenha 100% das suas linhas e colunas. Não remova registros dele.
    3. ENRIQUECIMENTO: Adicione as colunas solicitadas dos outros relatórios apenas quando houver um match (CPF ou Nome).
    4. NÃO INVENTE DADOS: Se não houver match pelo CPF E nem pelo Nome, deixe a coluna extra como null ou "-". NUNCA coloque "0" ou "0,00" para valores não encontrados.

    PADRONIZAÇÃO:
    - Nomes: Sempre em CAIXA ALTA.
    - CPFs: Formato 000.000.000-00.
    - Valores: Formato Moeda Brasileira "R$ 1.250,50".
    - Datas: DD/MM/AAAA.

    SAÍDA OBRIGATÓRIA:
    Retorne APENAS um objeto JSON. Sem textos antes ou depois.
    Estrutura: { "data": [ { "ColunaOriginal": "...", "NovaColuna": "..." } ], "summary": "Resumo detalhado da lógica de união aplicada" }
  `;

  const finalPrompt = `
    INSTRUÇÕES DO USUÁRIO: 
    ${userInstruction}

    CONTEÚDO DOS DOCUMENTOS:
    ${textContent ? textContent : 'Analise os arquivos anexados.'}
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { 
        parts: [
          ...fileParts,
          { text: finalPrompt }
        ] 
      },
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        temperature: 0.1,
      }
    });

    const rawText = response.text || "";
    const cleanedText = cleanJsonResponse(rawText);

    try {
      const result = JSON.parse(cleanedText);

      if (!result.data || !Array.isArray(result.data)) {
        return { data: [], headers: [], summary: "Erro: A IA não retornou uma lista de dados." };
      }

      const headers = result.data.length > 0 ? Object.keys(result.data[0]) : [];

      return {
        data: result.data,
        headers,
        summary: result.summary || "Processamento concluído com sucesso."
      };
    } catch (parseError) {
      return { 
        data: [], 
        headers: [], 
        summary: "Erro crítico ao processar a tabela gerada. Tente reduzir o número de páginas ou ser mais claro na instrução." 
      };
    }
  } catch (error) {
    console.error("Erro API:", error);
    return { 
      data: [], 
      headers: [], 
      summary: "A conexão com a inteligência artificial falhou. Tente novamente em instantes." 
    };
  }
};

import React, { useState, useEffect } from 'react';
import { 
  FileText, 
  Upload, 
  Search, 
  CheckCircle, 
  Download, 
  Trash2, 
  AlertCircle,
  Table as TableIcon,
  ChevronRight,
  FileSpreadsheet,
  Plus,
  Loader2,
  Zap,
  X,
  UploadCloud,
  FileJson,
  Image as ImageIcon,
  FileCode,
  Info,
  Settings2,
  Eye,
  EyeOff,
  Database,
  ArrowRightLeft
} from 'lucide-react';
import * as XLSX from 'xlsx';

import { FileMetadata, ProcessingResult, ExtractedData, FileType } from './types';
import { fileToBase64, parseExcel, parseCsv, extractPdfTextInChunks } from './utils/fileUtils';
import { extractDataFromReport } from './services/geminiService';

const COMMON_FIELDS = [
  { label: 'Priorizar CPF', value: 'Cruzar dados priorizando o CPF. Se o CPF faltar, usar o Nome como chave secundária.' },
  { label: 'Manter Mestre', value: 'Manter todas as colunas e linhas originais do Relatório 1 intactas.' },
  { label: 'Formatar Moeda', value: 'Garantir que todos os valores financeiros estejam no formato R$ 0.000,00.' },
  { label: 'Nomes em Alta', value: 'Converter todos os nomes para CAIXA ALTA.' },
  { label: 'CPF Mascarado', value: 'Formatar CPFs no padrão 000.000.000-00.' },
];

const App: React.FC = () => {
  const [files, setFiles] = useState<FileMetadata[]>([]);
  const [instruction, setInstruction] = useState('Consolide os relatórios usando o Relatório 1 como base. Para enriquecer com dados dos outros arquivos, tente dar match primeiro pelo CPF. Se o CPF não estiver disponível, tente pelo Nome Completo. Adicione os valores encontrados em novas colunas específicas. Não altere os dados originais do Relatório 1.');
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, phase: '' });
  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [visibleColumns, setVisibleColumns] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [showColumnSettings, setShowColumnSettings] = useState(false);

  useEffect(() => {
    if (result && result.data.length > 0) {
      setVisibleColumns(result.headers);
    }
  }, [result]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFiles = e.target.files;
    if (selectedFiles) {
      const newFiles: FileMetadata[] = Array.from(selectedFiles).map((f: File) => {
        let detectedType: FileType = 'unknown';
        const name = f.name.toLowerCase();
        if (name.endsWith('.pdf')) detectedType = 'pdf';
        else if (name.endsWith('.xlsx') || name.endsWith('.xls')) detectedType = 'excel';
        else if (name.endsWith('.csv')) detectedType = 'text';
        else if (f.type.includes('image')) detectedType = 'image';
        else if (f.type.includes('text') || name.endsWith('.txt')) detectedType = 'text';

        return { name: f.name, size: f.size, type: detectedType, raw: f };
      });
      setFiles(prev => [...prev, ...newFiles]);
      setResult(null);
      setError(null);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const toggleColumn = (col: string) => {
    setVisibleColumns(prev => 
      prev.includes(col) ? prev.filter(c => c !== col) : [...prev, col]
    );
  };

  const handleProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setResult(null);
    setError(null);
    setShowColumnSettings(false);

    let allExtractedText = "";
    let imageParts: { inlineData: { data: string; mimeType: string } }[] = [];

    try {
      for (let idx = 0; idx < files.length; idx++) {
        const file = files[idx];
        const label = `RELATORIO_${idx + 1}`;
        setProgress({ current: idx + 1, total: files.length, phase: `Processando ${file.name}...` });

        let fileText = "";
        if (file.type === 'pdf') {
          const chunks = await extractPdfTextInChunks(file.raw, 100);
          fileText = chunks.join("\n");
        } else if (file.type === 'excel') {
          fileText = await parseExcel(file.raw);
        } else if (file.raw.name.toLowerCase().endsWith('.csv')) {
          fileText = await parseCsv(file.raw);
        } else if (file.type === 'image') {
          const b64 = await fileToBase64(file.raw);
          imageParts.push({ inlineData: { data: b64, mimeType: file.raw.type } });
          fileText = `[DADOS DE IMAGEM: ${file.name}]`;
        } else if (file.type === 'text') {
          fileText = await file.raw.text();
        }

        allExtractedText += `\n\n=== INÍCIO DO ${label} (ORIGEM: ${file.name}) ===\n${fileText}\n=== FIM DO ${label} ===\n`;
      }

      setProgress({ current: 100, total: 100, phase: 'IA aplicando lógica de cruzamento CPF/Nome...' });
      const extractionResult = await extractDataFromReport(instruction, imageParts, allExtractedText);

      if (extractionResult.data.length === 0) {
        throw new Error("Não foi possível consolidar os dados. Certifique-se de que os arquivos possuem colunas identificáveis (Nome/CPF).");
      }

      setResult(extractionResult);
    } catch (err: any) {
      setError(err.message || "Erro inesperado ao organizar o relatório.");
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;
    const filteredData = result.data.map(row => {
      const filteredRow: any = {};
      visibleColumns.forEach(col => {
        filteredRow[col] = row[col];
      });
      return filteredRow;
    });
    const ws = XLSX.utils.json_to_sheet(filteredData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Relatório Consolidado");
    XLSX.writeFile(wb, `relatorio_consolidado_${Date.now()}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20 font-sans selection:bg-indigo-100">
      <header className="bg-white border-b border-slate-200 p-4 sticky top-0 z-30 shadow-sm">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-[#4f46e5] rounded-xl text-white shadow-lg"><Zap className="w-5 h-5 fill-current" /></div>
            <h1 className="text-xl font-bold tracking-tight">SmartReport <span className="text-[#4f46e5]">Pro</span></h1>
          </div>
          <div className="hidden sm:flex items-center gap-2 px-4 py-1.5 bg-indigo-50 border border-indigo-100 rounded-full">
            <ArrowRightLeft className="w-3 h-3 text-[#4f46e5]" />
            <span className="text-[10px] font-black text-[#4f46e5] uppercase tracking-widest">Lógica de União CPF/Nome Ativa</span>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-12">
        {!result && !isProcessing && (
          <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 p-10 md:p-14 animate-in fade-in duration-500">
            <div className="text-center mb-10">
              <h2 className="text-4xl font-black text-slate-900 mb-2 tracking-tight">Organizador Mestre</h2>
              <p className="text-slate-500 text-lg font-medium leading-relaxed">Combine relatórios cruzando dados por CPF e Nome com IA.</p>
            </div>

            <div className="border-[3px] border-dashed border-slate-100 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50/40 hover:bg-slate-50 transition-all group">
              <UploadCloud className="w-16 h-16 text-indigo-200 mb-6 group-hover:scale-110 group-hover:text-[#4f46e5] transition-all" />
              <input type="file" id="multi-file" className="hidden" multiple onChange={handleFileChange} accept=".pdf,.xlsx,.xls,.csv,.txt,.png,.jpg,.jpeg,.webp" />
              <label 
                htmlFor="multi-file" 
                className="bg-[#4f46e5] text-white px-10 py-4 rounded-2xl font-bold text-lg cursor-pointer hover:bg-[#4338ca] shadow-xl transition-all mb-4 active:scale-95"
              >
                Carregar Documentos
              </label>
              <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest text-center">
                DICA: O PRIMEIRO ARQUIVO SERÁ USADO COMO BASE PRINCIPAL
              </p>
            </div>

            {files.length > 0 && (
              <div className="mt-12 space-y-8 animate-in slide-in-from-bottom-6">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {files.map((f, i) => (
                    <div key={i} className={`flex items-center justify-between p-5 rounded-2xl border bg-white shadow-sm transition-all ${i === 0 ? 'border-indigo-500 ring-4 ring-indigo-50 shadow-indigo-50' : 'border-slate-100'}`}>
                      <div className="flex items-center gap-3 overflow-hidden">
                        <div className="relative">
                          {f.type === 'pdf' ? <FileText className="text-red-500 w-6 h-6" /> : <FileSpreadsheet className="text-green-600 w-6 h-6" />}
                          {i === 0 && <div className="absolute -top-3 -left-3 bg-indigo-600 text-white text-[9px] px-2 py-0.5 rounded-full font-black shadow-md uppercase">Base</div>}
                        </div>
                        <div className="flex flex-col overflow-hidden">
                          <span className="text-sm font-bold text-slate-700 truncate">{f.name}</span>
                          <span className="text-[10px] text-slate-400 font-black uppercase">{i === 0 ? 'Relatório Master' : `Fonte de Enriquecimento`}</span>
                        </div>
                      </div>
                      <button onClick={() => removeFile(i)} className="p-2 text-slate-300 hover:text-red-500 transition-all hover:bg-red-50 rounded-lg"><X className="w-5 h-5" /></button>
                    </div>
                  ))}
                </div>

                <div className="space-y-6">
                  <div className="flex flex-col gap-2">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest px-1">Lógica de Processamento</label>
                    <div className="flex flex-wrap gap-2">
                      {COMMON_FIELDS.map(f => (
                        <button key={f.label} onClick={() => setInstruction(i => `${i} ${f.value}`)} className="px-3 py-1.5 bg-slate-50 border border-slate-200 hover:border-[#4f46e5] hover:text-[#4f46e5] rounded-full text-[10px] font-black uppercase transition-all shadow-sm">
                          + {f.label}
                        </button>
