import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ExtractedData, ProcessingResult, ComparisonResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const cleanJsonResponse = (text: string): string => {
  let cleaned = text.trim();
  cleaned = cleaned.replace(/^```[a-zA-Z]*\n?/gm, "").replace(/```$/gm, "");
  return cleaned.trim();
};

export const extractDataFromReport = async (
  userInstruction: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  const model = 'gemini-3-pro-preview';

  const systemInstruction = `
    Você é um Assistente de Organização de Dados de alta precisão. 
    REGRAS DE UNIÃO:
    1. PRIORIDADE: CPF primeiro, Nome como fallback.
    2. INTEGRIDADE: Relatório 1 é o Master.
    3. PADRONIZAÇÃO: Nomes CAIXA ALTA, CPF 000.000.000-00, Moeda R$ 1.250,50.
    SAÍDA: JSON puro { "data": [...], "summary": "..." }
  `;

  const finalPrompt = `
    INSTRUÇÕES DO USUÁRIO: ${userInstruction}
    CONTEÚDO: ${textContent || 'Analise os anexos.'}
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { parts: [...fileParts, { text: finalPrompt }] },
      config: { systemInstruction, responseMimeType: "application/json", temperature: 0.1 }
    });

    const cleanedText = cleanJsonResponse(response.text || "");
    const result = JSON.parse(cleanedText);
    return {
      data: result.data || [],
      headers: result.data?.length > 0 ? Object.keys(result.data[0]) : [],
      summary: result.summary
    };
  } catch (error) {
    console.error("Erro API:", error);
    return { data: [], headers: [], summary: "Erro no processamento." };
  }
};

export const compareReports = async (
  fileAParts: { inlineData: { data: string; mimeType: string } }[],
  fileBParts: { inlineData: { data: string; mimeType: string } }[],
  textA: string,
  textB: string,
  nameA: string,
  nameB: string
): Promise<ComparisonResult> => {
  const model = 'gemini-3-pro-preview';

  const systemInstruction = `
    Você é um especialista em AUDITORIA de dados. Sua tarefa é comparar dois relatórios (A e B) e identificar divergências.

    LÓGICA DE COMPARAÇÃO:
    1. Identifique os registros comuns usando CPF ou Nome.
    2. Para cada registro, compare campos equivalentes (ex: Valores, Datas, Status).
    3. Retorne uma lista de diferenças.

    SAÍDA JSON:
    {
      "data": [
        {
          "key": "Identificador (CPF ou Nome)",
          "field": "Nome do Campo Comparado",
          "valueA": "Valor no Relatório A",
          "valueB": "Valor no Relatório B",
          "isDifferent": true/false
        }
      ],
      "summary": "Resumo das principais divergências encontradas"
    }
  `;

  const prompt = `
    RELATÓRIO A (${nameA}):
    ${textA}

    RELATÓRIO B (${nameB}):
    ${textB}

    Compare os dois documentos. Foque em valores financeiros e datas. Identifique onde os dados não batem.
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { parts: [...fileAParts, ...fileBParts, { text: prompt }] },
      config: { systemInstruction, responseMimeType: "application/json", temperature: 0.1 }
    });

    const cleanedText = cleanJsonResponse(response.text || "");
    const result = JSON.parse(cleanedText);
    return {
      data: result.data || [],
      headers: ['key', 'field', 'valueA', 'valueB', 'isDifferent'],
      summary: result.summary
    };
  } catch (error) {
    console.error("Erro Comparação:", error);
    return { data: [], headers: [], summary: "Erro na comparação." };
  }
};

import React, { useState, useEffect } from 'react';
import { 
  FileText, 
  Upload, 
  Search, 
  CheckCircle, 
  Download, 
  Trash2, 
  AlertCircle,
  Table as TableIcon,
  ChevronRight,
  FileSpreadsheet,
  Plus,
  Loader2,
  Zap,
  X,
  UploadCloud,
  FileJson,
  Image as ImageIcon,
  FileCode,
  Info,
  Settings2,
  Eye,
  EyeOff,
  Database,
  ArrowRightLeft,
  Copy,
  Split,
  AlertTriangle
} from 'lucide-react';
import * as XLSX from 'xlsx';

import { FileMetadata, ProcessingResult, ExtractedData, FileType, ComparisonResult } from './types';
import { fileToBase64, parseExcel, parseCsv, extractPdfTextInChunks } from './utils/fileUtils';
import { extractDataFromReport, compareReports } from './services/geminiService';

const COMMON_FIELDS = [
  { label: 'Priorizar CPF', value: 'Cruzar dados priorizando o CPF. Se o CPF faltar, usar o Nome como chave secundária.' },
  { label: 'Manter Mestre', value: 'Manter todas as colunas e linhas originais do Relatório 1 intactas.' },
  { label: 'Formatar Moeda', value: 'Garantir que todos os valores financeiros estejam no formato R$ 0.000,00.' },
  { label: 'Nomes em Alta', value: 'Converter todos os nomes para CAIXA ALTA.' },
  { label: 'CPF Mascarado', value: 'Formatar CPFs no padrão 000.000.000-00.' },
];

const App: React.FC = () => {
  const [files, setFiles] = useState<FileMetadata[]>([]);
  const [instruction, setInstruction] = useState('Consolide os relatórios usando o Relatório 1 como base. Para enriquecer com dados dos outros arquivos, tente dar match primeiro pelo CPF. Se o CPF não estiver disponível, tente pelo Nome Completo. Adicione os valores encontrados em novas colunas específicas. Não altere os dados originais do Relatório 1.');
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, phase: '' });

  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [comparisonResult, setComparisonResult] = useState<ComparisonResult | null>(null);

  const [visibleColumns, setVisibleColumns] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [showColumnSettings, setShowColumnSettings] = useState(false);

  const [isCompareMode, setIsCompareMode] = useState(false);
  const [selectedForCompare, setSelectedForCompare] = useState<number[]>([]);

  useEffect(() => {
    if (result && result.data.length > 0) {
      setVisibleColumns(result.headers);
    }
  }, [result]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFiles = e.target.files;
    if (selectedFiles) {
      const newFiles: FileMetadata[] = Array.from(selectedFiles).map((f: File) => {
        let detectedType: FileType = 'unknown';
        const name = f.name.toLowerCase();
        if (name.endsWith('.pdf')) detectedType = 'pdf';
        else if (name.endsWith('.xlsx') || name.endsWith('.xls')) detectedType = 'excel';
        else if (name.endsWith('.csv')) detectedType = 'text';
        else if (f.type.includes('image')) detectedType = 'image';
        else if (f.type.includes('text') || name.endsWith('.txt')) detectedType = 'text';

        return { name: f.name, size: f.size, type: detectedType, raw: f };
      });
      setFiles(prev => [...prev, ...newFiles]);
      setResult(null);
      setComparisonResult(null);
      setError(null);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
    setSelectedForCompare(prev => prev.filter(i => i !== index));
  };

  const toggleColumn = (col: string) => {
    setVisibleColumns(prev => 
      prev.includes(col) ? prev.filter(c => c !== col) : [...prev, col]
    );
  };

  const toggleFileSelection = (index: number) => {
    setSelectedForCompare(prev => {
      if (prev.includes(index)) return prev.filter(i => i !== index);
      if (prev.length < 2) return [...prev, index];
      return [prev[1], index];
    });
  };

  const handleProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setResult(null);
    setComparisonResult(null);
    setError(null);
    setShowColumnSettings(false);

    try {
      if (isCompareMode && selectedForCompare.length === 2) {
        const fileA = files[selectedForCompare[0]];
        const fileB = files[selectedForCompare[1]];

        setProgress({ current: 1, total: 2, phase: `Lendo ${fileA.name}...` });
        const textA = fileA.type === 'pdf' ? (await extractPdfTextInChunks(fileA.raw)).join('\n') : await fileA.raw.text();

        setProgress({ current: 2, total: 2, phase: `Lendo ${fileB.name}...` });
        const textB = fileB.type === 'pdf' ? (await extractPdfTextInChunks(fileB.raw)).join('\n') : await fileB.raw.text();

        setProgress({ current: 2, total: 2, phase: 'IA auditando divergências...' });
        const res = await compareReports([], [], textA, textB, fileA.name, fileB.name);
        setComparisonResult(res);
      } else {
        let allExtractedText = "";
        let imageParts: { inlineData: { data: string; mimeType: string } }[] = [];

        for (let idx = 0; idx < files.length; idx++) {
          const file = files[idx];
          const label = `RELATORIO_${idx + 1}`;
          setProgress({ current: idx + 1, total: files.length, phase: `Processando ${file.name}...` });

          let fileText = "";
          if (file.type === 'pdf') {
            const chunks = await extractPdfTextInChunks(file.raw, 100);
            fileText = chunks.join("\n");
          } else if (file.type === 'excel') {
            fileText = await parseExcel(file.raw);
          } else if (file.type === 'image') {
            const b64 = await fileToBase64(file.raw);
            imageParts.push({ inlineData: { data: b64, mimeType: file.raw.type } });
            fileText = `[IMAGEM: ${file.name}]`;
          } else {
            fileText = await file.raw.text();
          }
          allExtractedText += `\n\n=== INÍCIO DO ${label} (${file.name}) ===\n${fileText}\n=== FIM DO ${label} ===\n`;
        }

        setProgress({ current: 100, total: 100, phase: 'IA consolidando dados mestre...' });
        const extractionResult = await extractDataFromReport(instruction, imageParts, allExtractedText);

        if (extractionResult.data.length === 0) throw new Error("Falha na extração de dados.");
        setResult(extractionResult);
      }
    } catch (err: any) {
      setError(err.message || "Erro no processamento.");
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadExcel = () => {
    if (!result && !comparisonResult) return;
    const data = result ? result.data : comparisonResult!.data;
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Resultado");
    XLSX.writeFile(wb, `relatorio_${Date.now()}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20 font-sans selection:bg-indigo-100">
      <header className="bg-white border-b border-slate-200 p-4 sticky top-0 z-30 shadow-sm">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-[#4f46e5] rounded-xl text-white shadow-lg"><Zap className="w-5 h-5 fill-current" /></div>
            <h1 className="text-xl font-bold tracking-tight">SmartReport <span className="text-[#4f46e5]">Pro</span></h1>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={() => { setIsCompareMode(!isCompareMode); setResult(null); setComparisonResult(null); }}
              className={`flex items-center gap-2 px-4 py-1.5 rounded-full transition-all text-[10px] font-black uppercase tracking-widest ${isCompareMode ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}
            >
              <Split className="w-3 h-3" />
              {isCompareMode ? 'Modo Comparação Ativo' : 'Ativar Comparação'}
            </button>
            <div className="hidden sm:flex items-center gap-2 px-4 py-1.5 bg-indigo-50 border border-indigo-100 rounded-full">
              <Database className="w-3 h-3 text-[#4f46e5]" />
              <span className="text-[10px] font-black text-[#4f46e5] uppercase tracking-widest">IA Gemini 3 Pro Ativa</span>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-12">
        {!result && !comparisonResult && !isProcessing && (
          <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 p-10 md:p-14 animate-in fade-in duration-500">
            <div className="text-center mb-10">
              <h2 className="text-4xl font-black text-slate-900 mb-2 tracking-tight">
                {isCompareMode ? 'Comparador de Auditoria' : 'Organizador Mestre'}
              </h2>
              <p className="text-slate-500 text-lg font-medium leading-relaxed">
                {isCompareMode ? 'Selecione dois arquivos para identificar divergências e inconsistências.' : 'Arraste seus relatórios e descreva como deseja uni-los.'}
              </p>
            </div>

            <div className="border-[3px] border-dashed border-slate-100 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50/40 hover:bg-slate-50 transition-all group">
              <UploadCloud className="w-16 h-16 text-indigo-200 mb-6 group-hover:scale-110 group-hover:text-[#4f46e5] transition-all" />
              <input type="file" id="multi-file" className="hidden" multiple onChange={handleFileChange} accept=".pdf,.xlsx,.xls,.csv,.txt,.png,.jpg,.jpeg,.webp" />
              <label 
                htmlFor="multi-file" 
                className="bg-[#4f46e5] text-white px-10 py-4 rounded-2xl font-bold text-lg cursor-pointer hover:bg-[#4338ca] shadow-xl transition-all mb-4 active:scale-95"
              >
                Carregar Documentos
              </label>
            </div>

            {files.length > 0 && (
              <div className="mt-12 space-y-8 animate-in slide-in-from-bottom-6">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {files.map((f, i) => (
                    <div 
                      key={i} 
                      onClick={() => isCompareMode && toggleFileSelection(i)}
                      className={`flex items-center justify-between p-5 rounded-2xl border bg-white shadow-sm transition-all cursor-pointer ${
                        isCompareMode 
                        ? (selectedForCompare.includes(i) ? 'border-indigo-600 ring-4 ring-indigo-50' : 'border-slate-100 hover:border-indigo-200')
                        : (i === 0 ? 'border-indigo-500 ring-4 ring-indigo-50' : 'border-slate-100')
                      }`}
                    >
                      <div className="flex items-center gap-3 overflow-hidden">
                        <div className="relative">
                          {f.type === 'pdf' ? <FileText className="text-red-500 w-6 h-6" /> : <FileSpreadsheet className="text-green-600 w-6 h-6" />}
                          {!isCompareMode && i === 0 && <div className="absolute -top-3 -left-3 bg-indigo-600 text-white text-[9px] px-2 py-0.5 rounded-full font-black shadow-md uppercase">Base</div>}
                          {isCompareMode && selectedForCompare.includes(i) && (
                            <div className="absolute -top-3 -left-3 bg-indigo-600 text-white text-[9px] px-2 py-0.5 rounded-full font-black shadow-md uppercase">
                              {selectedForCompare.indexOf(i) === 0 ? 'Relatório A' : 'Relatório B'}
                            </div>
                          )}
                        </div>
                        <div className="flex flex-col overflow-hidden">
                          <span className="text-sm font-bold text-slate-700 truncate">{f.name}</span>
                          <span className="text-[10px] text-slate-400 font-black uppercase">
                            {isCompareMode ? 'Clique para selecionar' : (i === 0 ? 'Relatório Master' : 'Fonte de Enriquecimento')}
                          </span>
