import React, { useState, useEffect } from 'react';
import { 
  FileText, 
  Upload, 
  Search, 
  CheckCircle, 
  Download, 
  Trash2, 
  AlertCircle,
  Table as TableIcon,
  ChevronRight,
  FileSpreadsheet,
  Plus,
  Loader2,
  Zap,
  X,
  UploadCloud,
  FileJson,
  Image as ImageIcon,
  FileCode,
  Info,
  Settings2,
  Eye,
  EyeOff,
  Database,
  ArrowRightLeft,
  Copy,
  Split,
  AlertTriangle,
  ShieldCheck,
  ShieldAlert,
  Ghost,
  HelpCircle
} from 'lucide-react';
import * as XLSX from 'xlsx';

import { FileMetadata, ProcessingResult, ExtractedData, FileType, ComparisonResult } from './types';
import { fileToBase64, parseExcel, parseCsv, extractPdfTextInChunks } from './utils/fileUtils';
import { extractDataFromReport, compareReports } from './services/geminiService';

const COMMON_FIELDS = [
  { label: 'Priorizar CPF', value: 'Cruzar dados priorizando o CPF. Se o CPF faltar, usar o Nome como chave secundária.' },
  { label: 'Fórmula Comissão', value: 'Implementar cálculo: COMISSAO = VALOR_RELATORIO_GERAL - FOLHA - DSR.' },
  { label: 'Registros Órfãos', value: 'Listar separadamente indivíduos que não foram encontrados em todos os relatórios.' },
  { label: 'Formatar Moeda', value: 'Garantir que todos os valores financeiros estejam no formato R$ 0.000,00.' },
];

const App: React.FC = () => {
  const [files, setFiles] = useState<FileMetadata[]>([]);
  const [instruction, setInstruction] = useState('Consolide os relatórios usando o Relatório 1 como base. Calcule a COMISSAO subtraindo FOLHA e DSR do VALOR_RELATORIO_GERAL. Se um funcionário não for encontrado no cruzamento, liste-o nos registros não encontrados com o motivo.');
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, phase: '' });

  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [comparisonResult, setComparisonResult] = useState<ComparisonResult | null>(null);

  const [visibleColumns, setVisibleColumns] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [showColumnSettings, setShowColumnSettings] = useState(false);

  const [isCompareMode, setIsCompareMode] = useState(false);
  const [selectedForCompare, setSelectedForCompare] = useState<number[]>([]);

  useEffect(() => {
    if (result && result.data.length > 0) {
      setVisibleColumns(result.headers);
    }
  }, [result]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFiles = e.target.files;
    if (selectedFiles) {
      const newFiles: FileMetadata[] = Array.from(selectedFiles).map((f: File) => {
        let detectedType: FileType = 'unknown';
        const name = f.name.toLowerCase();
        if (name.endsWith('.pdf')) detectedType = 'pdf';
        else if (name.endsWith('.xlsx') || name.endsWith('.xls')) detectedType = 'excel';
        else if (name.endsWith('.csv')) detectedType = 'text';
        else if (f.type.includes('image')) detectedType = 'image';
        else if (f.type.includes('text') || name.endsWith('.txt')) detectedType = 'text';
        return { name: f.name, size: f.size, type: detectedType, raw: f };
      });
      setFiles(prev => [...prev, ...newFiles]);
      setResult(null);
      setComparisonResult(null);
      setError(null);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
    setSelectedForCompare(prev => prev.filter(i => i !== index));
  };

  const toggleColumn = (col: string) => {
    setVisibleColumns(prev => 
      prev.includes(col) ? prev.filter(c => c !== col) : [...prev, col]
    );
  };

  const handleProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setResult(null);
    setComparisonResult(null);
    setError(null);

    try {
      if (isCompareMode && selectedForCompare.length === 2) {
        const fileA = files[selectedForCompare[0]];
        const fileB = files[selectedForCompare[1]];
        setProgress({ current: 1, total: 2, phase: `Lendo ${fileA.name}...` });
        const textA = fileA.type === 'pdf' ? (await extractPdfTextInChunks(fileA.raw)).join('\n') : await fileA.raw.text();
        setProgress({ current: 2, total: 2, phase: `Lendo ${fileB.name}...` });
        const textB = fileB.type === 'pdf' ? (await extractPdfTextInChunks(fileB.raw)).join('\n') : await fileB.raw.text();
        setProgress({ current: 2, total: 2, phase: 'IA auditando divergências...' });
        const res = await compareReports([], [], textA, textB, fileA.name, fileB.name);
        setComparisonResult(res);
      } else {
        let allExtractedText = "";
        let imageParts: { inlineData: { data: string; mimeType: string } }[] = [];
        for (let idx = 0; idx < files.length; idx++) {
          const file = files[idx];
          const label = `RELATORIO_${idx + 1}`;
          setProgress({ current: idx + 1, total: files.length, phase: `Processando ${file.name}...` });
          let fileText = "";
          if (file.type === 'pdf') {
            const chunks = await extractPdfTextInChunks(file.raw, 100);
            fileText = chunks.join("\n");
          } else if (file.type === 'excel') {
            fileText = await parseExcel(file.raw);
          } else if (file.type === 'image') {
            const b64 = await fileToBase64(file.raw);
            imageParts.push({ inlineData: { data: b64, mimeType: file.raw.type } });
            fileText = `[IMAGEM: ${file.name}]`;
          } else {
            fileText = await file.raw.text();
          }
          allExtractedText += `\n\n=== INÍCIO DO ${label} (${file.name}) ===\n${fileText}\n=== FIM DO ${label} ===\n`;
        }
        setProgress({ current: 100, total: 100, phase: 'IA consolidando e calculando fórmulas...' });
        const extractionResult = await extractDataFromReport(instruction, imageParts, allExtractedText);
        setResult(extractionResult);
      }
    } catch (err: any) {
      setError(err.message || "Erro no processamento.");
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;

    // Preparar dados para o SheetJS
    const headers = result.headers;
    const ws_data = [headers];

    // Adicionar linhas de dados
    result.data.forEach(row => {
      ws_data.push(headers.map(h => row[h] as any));
    });

    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.aoa_to_sheet(ws_data);

    // Aplicar Fórmulas se existirem
    if (result.formulas) {
      Object.entries(result.formulas).forEach(([colName, formulaTemplate]) => {
        const colIdx = headers.indexOf(colName);
        if (colIdx !== -1) {
          const colLetter = XLSX.utils.encode_col(colIdx);

          // Mapear nomes de colunas na fórmula para letras
          // Fix: Explicitly cast formulaTemplate to string to avoid 'unknown' type error in replace calls
          let finalFormulaTemplate = formulaTemplate as string;
          headers.forEach((h, idx) => {
            const letter = XLSX.utils.encode_col(idx);
            finalFormulaTemplate = finalFormulaTemplate.replace(new RegExp(`\\b${h}\\b`, 'g'), letter);
          });

          // Aplicar a cada linha de dados (começando da linha 2)
          for (let rowIdx = 2; rowIdx <= result.data.length + 1; rowIdx++) {
            const cellRef = `${colLetter}${rowIdx}`;
            // Fix: finalFormulaTemplate is now typed correctly for the replace method
            const rowFormula = finalFormulaTemplate.replace(/([A-Z]+)/g, `$1${rowIdx}`);

            if (!ws[cellRef]) ws[cellRef] = { t: 'n', v: 0 };
            ws[cellRef].f = rowFormula;
          }
        }
      });
    }

    // Adicionar registros não encontrados como apêndice
    if (result.unmatchedRecords && result.unmatchedRecords.length > 0) {
      const startRow = result.data.length + 4;
      XLSX.utils.sheet_add_aoa(ws, [["--- REGISTROS NÃO CONCILIADOS ---"]], { origin: `A${startRow}` });
      XLSX.utils.sheet_add_aoa(ws, [["Nome", "CPF", "Motivo da Falha", "Origem"]], { origin: `A${startRow + 1}` });

      result.unmatchedRecords.forEach((rec, idx) => {
        XLSX.utils.sheet_add_aoa(ws, [[rec.name || "-", rec.cpf || "-", rec.reason, rec.source]], { origin: `A${startRow + 2 + idx}` });
      });
    }

    XLSX.utils.book_append_sheet(wb, ws, "Consolidado");
    XLSX.writeFile(wb, `relatorio_inteligente_${Date.now()}.xlsx`);
  };

  const getCellError = (row: ExtractedData, header: string): string | null => {
    const metadata = (row as any)._metadata;
    return (metadata && metadata.errors && metadata.errors[header]) || null;
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20 font-sans">
      <header className="bg-white border-b border-slate-200 p-4 sticky top-0 z-30 shadow-sm">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-[#4f46e5] rounded-xl text-white shadow-lg"><Zap className="w-5 h-5 fill-current" /></div>
            <h1 className="text-xl font-bold tracking-tight">SmartReport <span className="text-[#4f46e5]">Excel+</span></h1>
          </div>
          <div className="flex items-center gap-4">
            <button 
              onClick={() => { setIsCompareMode(!isCompareMode); setResult(null); setComparisonResult(null); }}
              className={`flex items-center gap-2 px-4 py-1.5 rounded-full transition-all text-[10px] font-black uppercase tracking-widest ${isCompareMode ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-500'}`}
            >
              <Split className="w-3 h-3" /> {isCompareMode ? 'Modo Auditoria' : 'Comparar'}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 mt-12">
        {!result && !comparisonResult && !isProcessing && (
          <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 p-10 md:p-14 animate-in fade-in duration-500">
            <div className="text-center mb-10">
              <h2 className="text-4xl font-black text-slate-900 mb-2 tracking-tight">Consolidador com Fórmulas</h2>
              <p className="text-slate-500 text-lg font-medium">Extraia dados e gere planilhas com cálculos automáticos e rastreio de erros.</p>
            </div>

            <div className="border-[3px] border-dashed border-slate-100 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50/40 hover:bg-slate-50 transition-all group">
              <UploadCloud className="w-16 h-16 text-indigo-200 mb-6 group-hover:scale-110 group-hover:text-[#4f46e5]" />
              <input type="file" id="multi-file" className="hidden" multiple onChange={handleFileChange} accept=".pdf,.xlsx,.xls,.csv,.txt,.png,.jpg,.jpeg,.webp" />
              <label htmlFor="multi-file" className="bg-[#4f46e5] text-white px-10 py-4 rounded-2xl font-bold text-lg cursor-pointer hover:bg-[#4338ca] shadow-xl transition-all mb-4 active:scale-95">Anexar Relatórios</label>
              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Suporta PDF, Excel e Imagens</p>
            </div>

            {files.length > 0 && (
              <div className="mt-12 space-y-8 animate-in slide-in-from-bottom-6">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {files.map((f, i) => (
                    <div key={i} className={`flex items-center justify-between p-5 rounded-2xl border bg-white shadow-sm ${i === 0 ? 'border-indigo-500 ring-4 ring-indigo-50' : 'border-slate-100'}`}>
                      <div className="flex items-center gap-3 overflow-hidden">
                        {f.type === 'pdf' ? <FileText className="text-red-500 w-6 h-6" /> : <FileSpreadsheet className="text-green-600 w-6 h-6" />}
                        <div className="flex flex-col overflow-hidden">
                          <span className="text-sm font-bold text-slate-700 truncate">{f.name}</span>
                          <span className="text-[10px] text-slate-400 font-black uppercase">{i === 0 ? 'Relatório Master' : 'Anexo de Dados'}</span>
                        </div>
                      </div>
                      <button onClick={() => removeFile(i)} className="p-2 text-slate-300 hover:text-red-500"><X className="w-5 h-5" /></button>
                    </div>
                  ))}
                </div>

                <div className="space-y-6">
                  <div className="flex flex-col gap-2">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-widest px-1">Atalhos de Lógica</label>
                    <div className="flex flex-wrap gap-2">
                      {COMMON_FIELDS.map(f => (
                        <button key={f.label} onClick={() => setInstruction(i => `${i} ${f.value}`)} className="px-3 py-1.5 bg-slate-50 border border-slate-200 hover:border-[#4f46e5] hover:text-[#4f46e5] rounded-full text-[10px] font-black uppercase transition-all">
                          + {f.label}
                        </button>
                      ))}
                    </div>
                  </div>
                  <textarea 
                    value={instruction} 
                    onChange={e => setInstruction(e.target.value)}
                    className="w-full bg-slate-50 border-2 border-slate-100 rounded-3xl p-6 min-h-[140px] focus:border-[#4f46e5] focus:bg-white outline-none transition-all font-semibold text-slate-700 shadow-inner"
                  />
                  <button onClick={handleProcess} className="w-full bg-[#4f46e5] text-white py-5 rounded-2xl font-black text-xl hover:bg-[#4338ca] shadow-2xl flex items-center justify-center gap-3">
                    Consolidar Arquivos <ChevronRight className="w-6 h-6" />
                  </button>
                </div>
              </div>
            )}
          </div>
        )}

        {isProcessing && (
          <div className="bg-white rounded-[2.5rem] shadow-2xl p-16 text-center space-y-10 border border-indigo-50">
            <div className="relative w-48 h-48 mx-auto">
              <div className="absolute inset-0 border-[14px] border-slate-50 rounded-full"></div>
              <div className="absolute inset-0 border-[14px] border-[#4f46e5] rounded-full border-t-transparent animate-spin"></div>
              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <Loader2 className="w-12 h-12 text-[#4f46e5] animate-pulse" />
                <span className="text-3xl font-black text-slate-900 mt-2">{Math.round((progress.current / progress.total) * 100) || 0}%</span>
              </div>
            </div>
            <h3 className="text-2xl font-black text-slate-900 tracking-tight">{progress.phase}</h3>
          </div>
        )}

        {result && (
          <div className="space-y-8 animate-in fade-in duration-700">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
              <div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tight">Planilha Gerada</h2>
                <p className="text-slate-500 font-bold uppercase text-[10px] tracking-widest mt-1">Cálculos de Comissão e Auditoria Aplicados</p>
              </div>
              <div className="flex gap-3">
                <button onClick={() => setShowColumnSettings(!showColumnSettings)} className="px-6 py-4 border-2 border-slate-100 bg-white font-bold rounded-2xl text-slate-500 hover:bg-slate-50"><Settings2 className="w-5 h-5" /></button>
                <button onClick={downloadExcel} className="px-8 py-4 bg-green-600 text-white font-black rounded-2xl hover:bg-green-700 shadow-xl flex items-center gap-3 text-lg"><Download className="w-6 h-6" /> Exportar Excel</button>
              </div>
            </div>

            {/* Tabela de Dados Principais */}
            <div className="bg-white border-2 border-slate-100 rounded-[2.5rem] overflow-hidden shadow-2xl">
              <div className="max-h-[500px] overflow-auto custom-scrollbar">
                <table className="w-full text-left border-collapse">
                  <thead className="sticky top-0 bg-[#0f172a] text-white z-10 shadow-lg">
                    <tr>
                      {result.headers.filter(h => visibleColumns.includes(h)).map(h => (
                        <th key={h} className="px-8 py-6 text-[10px] font-black uppercase tracking-widest">{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {result.data.map((row, i) => (
                      <tr key={i} className="hover:bg-indigo-50/10">
                        {result.headers.filter(h => visibleColumns.includes(h)).map(h => (
                          <td key={`${i}-${h}`} className={`px-8 py-5 text-[14px] font-bold ${getCellError(row, h) ? 'bg-orange-50 text-orange-700' : 'text-slate-600'}`}>
                            {row[h] || "-"}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            {/* Registros Não Conciliados */}
            {result.unmatchedRecords && result.unmatchedRecords.length > 0 && (
              <div className="space-y-4">
                <div className="flex items-center gap-3">
                  <Ghost className="text-slate-400 w-6 h-6" />
                  <h3 className="text-xl font-black text-slate-900 tracking-tight">Registros Não Conciliados</h3>
                </div>
                <div className="bg-white border-2 border-red-100 rounded-[2rem] p-8 shadow-xl">
                  <div className="space-y-6">
                    {result.unmatchedRecords.map((rec, i) => (
                      <div key={i} className="flex flex-col md:flex-row md:items-center justify-between gap-4 p-4 rounded-2xl bg-red-50/50 border border-red-100/50">
                        <div>
                          <p className="font-black text-slate-900">{rec.name || "Identificador Ausente"}</p>
                          <p className="text-xs font-bold text-slate-400">{rec.cpf || "Sem CPF"}</p>
                        </div>
                        <div className="flex items-center gap-3 bg-white px-4 py-2 rounded-xl shadow-sm border border-red-200">
                          <AlertTriangle className="w-4 h-4 text-red-500" />
                          <div>
                            <p className="text-[10px] font-black uppercase text-slate-400">Motivo</p>
                            <p className="text-xs font-bold text-red-700">{rec.reason}</p>
                          </div>
                        </div>
                        <div className="text-right">
                          <p className="text-[10px] font-black uppercase text-slate-400">Origem</p>
                          <p className="text-xs font-bold text-slate-600">{rec.source}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}

            {result.summary && (
              <div className="bg-[#0f172a] text-slate-100 p-10 rounded-[2.5rem] shadow-2xl">
                <div className="flex items-center gap-3 mb-4">
                  <Info className="w-6 h-6 text-indigo-400" />
                  <span className="text-xs font-black uppercase tracking-widest text-indigo-300">Análise de Auditoria</span>
                </div>
                <p className="text-lg leading-relaxed font-semibold italic opacity-90">"{result.summary}"</p>
              </div>
            )}
          </div>
        )}
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 8px; height: 8px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #f8fafc; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 20px; border: 3px solid #f8fafc; }
      `}</style>
    </div>
  );
};

export default App;

