import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ExtractedData, ProcessingResult, ComparisonResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const cleanJsonResponse = (text: string): string => {
  let cleaned = text.trim();
  cleaned = cleaned.replace(/^```[a-zA-Z]*\n?/gm, "").replace(/```$/gm, "");
  return cleaned.trim();
};

export const extractDataFromReport = async (
  userInstruction: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  const model = 'gemini-3-pro-preview';

  const systemInstruction = `
    Você é um Assistente de Auditoria e Consolidação de Dados de alta precisão.
    Sua missão é extrair e cruzar informações entre múltiplos documentos de forma ESTRITA.

    PRINCÍPIOS DE EXTRAÇÃO:
    1. FOCO TOTAL: Busque apenas as informações explicitamente pedidas pelo usuário, priorizando sempre Nome, CPF e Valores Financeiros.
    2. CHAVE DE CRUZAMENTO: Use o CPF como identificador único principal. Se ausente, use o Nome completo.
    3. RELATÓRIO MESTRE: O "Relatório 1" (primeiro documento) define a lista base de indivíduos. Busque os valores correspondentes nos outros documentos.

    CÁLCULOS (SE SOLICITADO):
    - Se o usuário pedir cálculos como comissão, aplique a lógica: COMISSAO = VALOR_RELATORIO_GERAL - FOLHA - DSR.
    - Identifique fórmulas e retorne-as no campo "formulas" do JSON.

    TRATAMENTO DE DADOS:
    - Formate CPFs como 000.000.000-00.
    - Formate Valores como R$ 0.000,00 ou números decimais consistentes.
    - Se um indivíduo do mestre não for encontrado em um anexo, registre-o em "unmatchedRecords" com o motivo específico.

    SAÍDA JSON OBRIGATÓRIA:
    {
      "data": [
        { 
          "Nome": "...", 
          "CPF": "...", 
          "VALOR_A": ..., 
          "VALOR_B": ...,
          "_metadata": { "errors": {} } 
        }
      ],
      "unmatchedRecords": [
        { "name": "...", "cpf": "...", "reason": "Não encontrado no arquivo X", "source": "Relatório Y" }
      ],
      "formulas": {
        "NOME_COLUNA": "Fórmula simplificada (ex: A-B-C)"
      },
      "headers": ["Nome", "CPF", "Coluna1", "Coluna2", "..."],
      "summary": "Resumo detalhado do processamento e validações realizadas."
    }
  `;

  const finalPrompt = `
    INSTRUÇÕES DO USUÁRIO: ${userInstruction}

    CONTEXTO TÉCNICO: O usuário deseja uma consolidação focada em Nome, CPF e Valores. 
    Verifique se há lógica de fórmulas (ex: COMISSAO = VALOR_RELATORIO_GERAL - FOLHA - DSR).

    CONTEÚDO DOS ARQUIVOS:
    ${textContent || 'Analise os anexos fornecidos.'}
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { parts: [...fileParts, { text: finalPrompt }] },
      config: { systemInstruction, responseMimeType: "application/json", temperature: 0.1 }
    });

    const cleanedText = cleanJsonResponse(response.text || "");
    const result = JSON.parse(cleanedText);

    const allHeaders = result.headers || (result.data?.length > 0 ? Object.keys(result.data[0]) : []);
    const headers = allHeaders.filter((h: string) => h !== '_metadata');

    return {
      data: result.data || [],
      headers: headers,
      summary: result.summary,
      unmatchedRecords: result.unmatchedRecords || [],
      formulas: result.formulas || {}
    };
  } catch (error) {
    console.error("Erro API:", error);
    return { data: [], headers: [], summary: "Erro no processamento da IA. Verifique os arquivos e tente novamente." };
  }
};

export const compareReports = async (
  fileAParts: { inlineData: { data: string; mimeType: string } }[],
  fileBParts: { inlineData: { data: string; mimeType: string } }[],
  textA: string,
  textB: string,
  nameA: string,
  nameB: string
): Promise<ComparisonResult> => {
  const model = 'gemini-3-pro-preview';
  const systemInstruction = `Você é um Auditor. Compare os dados entre Relatório A e B. Identifique divergências usando CPF/Nome. Retorne apenas JSON { "data": [], "summary": "" }.`;
  const prompt = `AUDITORIA:\nRelatório A (${nameA}):\n${textA}\n\nRelatório B (${nameB}):\n${textB}`;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { parts: [...fileAParts, ...fileBParts, { text: prompt }] },
      config: { systemInstruction, responseMimeType: "application/json", temperature: 0.1 }
    });
    const result = JSON.parse(cleanJsonResponse(response.text || ""));
    return { data: result.data || [], headers: ['key', 'field', 'valueA', 'valueB', 'isDifferent'], summary: result.summary };
  } catch (error) {
    return { data: [], headers: [], summary: "Falha na comparação." };
  }
};

