const App: React.FC = () => {
  const [activeStep, setActiveStep] = useState<'start' | 'config' | 'processing' | 'result'>('start');
  const [files, setFiles] = useState<FileMetadata[]>([]);
  const [instruction, setInstruction] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, phase: '' });

  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [comparisonResult, setComparisonResult] = useState<ComparisonResult | null>(null);

  const [visibleColumns, setVisibleColumns] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [showColumnSettings, setShowColumnSettings] = useState(false);

  const [isCompareMode, setIsCompareMode] = useState(false);
  const [selectedForCompare, setSelectedForCompare] = useState<number[]>([]);

  useEffect(() => {
    if (result && result.data.length > 0) {
      setVisibleColumns(result.headers);
    }
  }, [result]);

  const selectAction = (action: typeof QUICK_ACTIONS[0]) => {
    setIsCompareMode(!!action.isCompare);
    setInstruction(action.instruction || '');
    setActiveStep('config');
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFiles = e.target.files;
    if (selectedFiles) {
      const newFiles: FileMetadata[] = Array.from(selectedFiles).map((f: File) => {
        let detectedType: FileType = 'unknown';
        const name = f.name.toLowerCase();
        if (name.endsWith('.pdf')) detectedType = 'pdf';
        else if (name.endsWith('.xlsx') || name.endsWith('.xls')) detectedType = 'excel';
        else if (name.endsWith('.csv')) detectedType = 'text';
        else if (f.type.includes('image')) detectedType = 'image';
        else if (f.type.includes('text') || name.endsWith('.txt')) detectedType = 'text';
        return { name: f.name, size: f.size, type: detectedType, raw: f };
      });
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
    setSelectedForCompare(prev => prev.filter(i => i !== index));
  };

  const toggleFileSelection = (index: number) => {
    setSelectedForCompare(prev => {
      if (prev.includes(index)) return prev.filter(i => i !== index);
      if (prev.length < 2) return [...prev, index];
      return [prev[1], index];
    });
  };

  const toggleColumn = (column: string) => {
    setVisibleColumns(prev => 
      prev.includes(column) 
        ? prev.filter(c => c !== column) 
        : [...prev, column]
    );
  };

  const getCellError = (row: ExtractedData, column: string): string | null => {
    const anyRow = row as any;
    if (anyRow._metadata?.errors && anyRow._metadata.errors[column]) {
      return anyRow._metadata.errors[column];
    }
    return null;
  };

  const handleProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setActiveStep('processing');
    setResult(null);
    setComparisonResult(null);
    setError(null);

    try {
      if (isCompareMode && selectedForCompare.length === 2) {
        const fileA = files[selectedForCompare[0]];
        const fileB = files[selectedForCompare[1]];
        setProgress({ current: 1, total: 2, phase: `Lendo ${fileA.name}...` });
        const textA = fileA.type === 'pdf' ? (await extractPdfTextInChunks(fileA.raw)).join('\n') : await fileA.raw.text();
        setProgress({ current: 2, total: 2, phase: `Lendo ${fileB.name}...` });
        const textB = fileB.type === 'pdf' ? (await extractPdfTextInChunks(fileB.raw)).join('\n') : await fileB.raw.text();
        setProgress({ current: 2, total: 2, phase: 'IA auditando divergências...' });
        const res = await compareReports([], [], textA, textB, fileA.name, fileB.name);
        setComparisonResult(res);
      } else {
        let allExtractedText = "";
        let imageParts: { inlineData: { data: string; mimeType: string } }[] = [];
        for (let idx = 0; idx < files.length; idx++) {
          const file = files[idx];
          const label = `RELATORIO_${idx + 1}`;
          setProgress({ current: idx + 1, total: files.length, phase: `Lendo ${file.name}...` });
          let fileText = "";
          if (file.type === 'pdf') {
            const chunks = await extractPdfTextInChunks(file.raw, 100);
            fileText = chunks.join("\n");
          } else if (file.type === 'excel') {
            fileText = await parseExcel(file.raw);
          } else if (file.type === 'image') {
            const b64 = await fileToBase64(file.raw);
            imageParts.push({ inlineData: { data: b64, mimeType: file.raw.type } });
            fileText = `[IMAGEM: ${file.name}]`;
          } else {
            fileText = await file.raw.text();
          }
          allExtractedText += `\n\n=== INÍCIO DO ${label} (${file.name}) ===\n${fileText}\n=== FIM DO ${label} ===\n`;
        }
        setProgress({ current: 100, total: 100, phase: 'IA buscando Nome, CPF e Valores...' });
        const extractionResult = await extractDataFromReport(instruction, imageParts, allExtractedText);
        setResult(extractionResult);
      }
      setActiveStep('result');
    } catch (err: any) {
      setError(err.message || "Erro no processamento.");
      setActiveStep('config');
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;
    const headers = result.headers;
    const ws_data = [headers];
    result.data.forEach(row => ws_data.push(headers.map(h => row[h] as any)));
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.aoa_to_sheet(ws_data);
    if (result.formulas) {
      Object.entries(result.formulas).forEach(([colName, formulaTemplate]) => {
        const colIdx = headers.indexOf(colName);
        if (colIdx !== -1) {
          const colLetter = XLSX.utils.encode_col(colIdx);
          let finalFormulaTemplate = formulaTemplate as string;
          headers.forEach((h, idx) => {
            const letter = XLSX.utils.encode_col(idx);
            finalFormulaTemplate = finalFormulaTemplate.replace(new RegExp(`\\b${h}\\b`, 'g'), letter);
          });
          for (let rowIdx = 2; rowIdx <= result.data.length + 1; rowIdx++) {
            const cellRef = `${colLetter}${rowIdx}`;
            const rowFormula = finalFormulaTemplate.replace(/([A-Z]+)/g, `$1${rowIdx}`);
            if (!ws[cellRef]) ws[cellRef] = { t: 'n', v: 0 };
            ws[cellRef].f = rowFormula;
          }
        }
      });
    }
    if (result.unmatchedRecords && result.unmatchedRecords.length > 0) {
      const startRow = result.data.length + 4;
      XLSX.utils.sheet_add_aoa(ws, [["--- REGISTROS NÃO CONCILIADOS ---"]], { origin: `A${startRow}` });
      result.unmatchedRecords.forEach((rec, idx) => {
        XLSX.utils.sheet_add_aoa(ws, [[rec.name || "-", rec.cpf || "-", rec.reason, rec.source]], { origin: `A${startRow + 2 + idx}` });
      });
    }
    XLSX.utils.book_append_sheet(wb, ws, "Consolidado");
    XLSX.writeFile(wb, `smart_report_${Date.now()}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20 font-sans selection:bg-indigo-100">
      <header className="bg-white border-b border-slate-200 p-4 sticky top-0 z-30 shadow-sm">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setActiveStep('start')}>
            <div className="p-2 bg-[#4f46e5] rounded-xl text-white shadow-lg"><Zap className="w-5 h-5 fill-current" /></div>
            <h1 className="text-xl font-bold tracking-tight">SmartReport <span className="text-[#4f46e5]">Pro</span></h1>
          </div>
          {activeStep !== 'start' && (
            <button 
              onClick={() => setActiveStep('start')}
              className="flex items-center gap-2 px-4 py-2 text-sm font-bold text-slate-500 hover:text-slate-800 transition-all bg-slate-50 rounded-xl"
            >
              <ArrowLeft className="w-4 h-4" /> Início
            </button>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 mt-12">
        {/* PASSO 1: TELA DE START COM CARDS */}
        {activeStep === 'start' && (
          <div className="animate-in fade-in duration-700 slide-in-from-bottom-4">
            <div className="text-center max-w-2xl mx-auto mb-16">
              <h2 className="text-5xl font-black text-slate-900 mb-6 tracking-tight leading-tight">
                Tudo o que você precisa para dominar seus <span className="text-[#4f46e5]">relatórios</span>.
              </h2>
              <p className="text-slate-500 text-xl font-medium">
                Ferramenta online e inteligente para consolidar, auditar e validar dados sem esforço manual.
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {QUICK_ACTIONS.map(action => (
                <div 
                  key={action.id}
                  onClick={() => selectAction(action)}
                  className="group cursor-pointer bg-white border border-slate-100 rounded-[2.5rem] p-8 shadow-sm hover:shadow-2xl hover:-translate-y-2 transition-all duration-300 relative overflow-hidden"
                >
                  <div className={`w-16 h-16 ${action.color} rounded-2xl flex items-center justify-center mb-8 group-hover:scale-110 transition-transform`}>
                    {action.icon}
                  </div>
                  <h3 className="text-xl font-black text-slate-900 mb-3">{action.title}</h3>
                  <p className="text-slate-500 text-sm font-semibold leading-relaxed mb-6">
                    {action.description}
                  </p>
                  <div className="flex items-center text-[#4f46e5] font-black uppercase text-[10px] tracking-widest gap-2">
                    Começar agora <ChevronRight className="w-4 h-4" />
                  </div>
                  <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:opacity-10 transition-opacity">
                    {action.icon}
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-20 p-12 bg-indigo-600 rounded-[3rem] text-white flex flex-col md:flex-row items-center justify-between shadow-2xl shadow-indigo-200">
              <div className="max-w-md mb-8 md:mb-0">
                <h4 className="text-2xl font-black mb-2">Novo: Auditoria Nativa Excel</h4>
                <p className="text-indigo-100 font-semibold opacity-80">Agora a IA gera planilhas com fórmulas reais. Nada de valores estáticos, apenas inteligência aplicada diretamente na célula.</p>
              </div>
              <button 
                onClick={() => selectAction(QUICK_ACTIONS[1])}
                className="bg-white text-indigo-600 px-8 py-4 rounded-2xl font-black text-lg hover:bg-indigo-50 transition-all flex items-center gap-3"
              >
                Testar Fórmulas <Calculator className="w-6 h-6" />
              </button>
            </div>
          </div>
        )}

        {/* PASSO 2: CONFIGURAÇÃO E UPLOAD */}
        {activeStep === 'config' && (
          <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-right-4">
            <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 p-10 md:p-14 mb-10">
              <div className="flex items-center justify-between mb-10">
                <h2 className="text-3xl font-black text-slate-900 tracking-tight">Configure sua Tarefa</h2>
                <div className="px-4 py-2 bg-indigo-50 text-[#4f46e5] rounded-xl text-xs font-black uppercase tracking-widest">
                  {isCompareMode ? 'Modo Comparação' : 'Modo Consolidação'}
                </div>
              </div>

              <div className="border-[3px] border-dashed border-slate-100 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50/40 hover:bg-slate-50 transition-all group mb-10">
                <UploadCloud className="w-16 h-16 text-indigo-200 mb-6 group-hover:scale-110 group-hover:text-[#4f46e5]" />
                <input type="file" id="multi-file" className="hidden" multiple onChange={handleFileChange} accept=".pdf,.xlsx,.xls,.csv,.txt,.png,.jpg,.jpeg,.webp" />
                <label htmlFor="multi-file" className="bg-[#4f46e5] text-white px-10 py-4 rounded-2xl font-bold text-lg cursor-pointer hover:bg-[#4338ca] shadow-xl transition-all mb-4 active:scale-95">Anexar Relatórios</label>
                <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">PDF, Excel ou Fotos de Comprovantes</p>
              </div>

              {files.length > 0 && (
                <div className="space-y-10">
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    {files.map((f, i) => (
                      <div 
                        key={i} 
                        onClick={() => isCompareMode && toggleFileSelection(i)}
                        className={`flex items-center justify-between p-5 rounded-2xl border bg-white shadow-sm transition-all cursor-pointer ${
                          isCompareMode 
                          ? (selectedForCompare.includes(i) ? 'border-indigo-600 ring-4 ring-indigo-50' : 'border-slate-100')
                          : (i === 0 ? 'border-indigo-500 ring-4 ring-indigo-50' : 'border-slate-100')
                        }`}
                      >
                        <div className="flex items-center gap-3 overflow-hidden">
                          {f.type === 'pdf' ? <FileText className="text-red-500 w-6 h-6" /> : <FileSpreadsheet className="text-green-600 w-6 h-6" />}
                          <div className="flex flex-col overflow-hidden">
                            <span className="text-sm font-bold text-slate-700 truncate">{f.name}</span>
                            <span className="text-[10px] text-slate-400 font-black uppercase">
                              {isCompareMode ? (selectedForCompare.includes(i) ? `Auditando: ${selectedForCompare.indexOf(i) === 0 ? 'A' : 'B'}` : 'Clique p/ Comparar') : (i === 0 ? 'Base / Master' : 'Anexo de Dados')}
                            </span>
                          </div>
                        </div>
                        <button onClick={(e) => { e.stopPropagation(); removeFile(i); }} className="p-2 text-slate-300 hover:text-red-500 transition-all"><X className="w-5 h-5" /></button>
                      </div>
                    ))}
                  </div>

                  {!isCompareMode ? (
                    <div className="space-y-6">
                      <div className="flex flex-col gap-2">
                        <label className="text-xs font-black text-slate-400 uppercase tracking-widest px-1">Instruções para a IA</label>
                        <div className="flex flex-wrap gap-2">
                          {COMMON_FIELDS.map(f => (
                            <button key={f.label} onClick={() => setInstruction(i => `${i} ${f.value}`)} className="px-3 py-1.5 bg-slate-50 border border-slate-200 hover:border-[#4f46e5] hover:text-[#4f46e5] rounded-full text-[10px] font-black uppercase transition-all shadow-sm">
                              + {f.label}
                            </button>
                          ))}
                        </div>
                      </div>
                      <textarea 
                        value={instruction} 
                        onChange={e => setInstruction(e.target.value)}
                        className="w-full bg-slate-50 border-2 border-slate-100 rounded-3xl p-6 min-h-[140px] focus:border-[#4f46e5] focus:bg-white outline-none transition-all font-semibold text-slate-700 shadow-inner text-lg"
                        placeholder="Ex: Busque Nome, CPF e Valor de Vendas consolidando com o master..."
                      />
                      <button 
                        onClick={handleProcess}
                        disabled={files.length === 0}
                        className="w-full bg-[#4f46e5] text-white py-5 rounded-2xl font-black text-xl hover:bg-[#4338ca] shadow-2xl flex items-center justify-center gap-3 transition-all active:scale-[0.98] disabled:opacity-50"
                      >
                        Iniciar Processamento <ChevronRight className="w-6 h-6" />
                      </button>
                    </div>
                  ) : (
                    <div className="space-y-6">
                      <div className={`p-8 rounded-3xl border-2 transition-all ${selectedForCompare.length === 2 ? 'border-indigo-100 bg-indigo-50/20' : 'border-slate-100 bg-slate-50/50'}`}>
                        <p className="text-lg font-bold text-slate-700 mb-2">Comparação de Auditoria</p>
                        <p className="text-sm text-slate-400 font-semibold">Selecione exatamente 2 arquivos acima para que a IA possa identificar o que está diferente entre eles.</p>
                      </div>
                      <button 
                        disabled={selectedForCompare.length !== 2}
                        onClick={handleProcess}
                        className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black text-xl hover:bg-indigo-700 shadow-2xl disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-3 transition-all active:scale-[0.98]"
                      >
                        <Split className="w-6 h-6" /> Começar Auditoria
                      </button>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        )}

        {/* PASSO 3: PROCESSANDO */}
        {activeStep === 'processing' && (
          <div className="max-w-2xl mx-auto py-20 text-center space-y-12 animate-in fade-in">
            <div className="relative w-56 h-56 mx-auto">
              <div className="absolute inset-0 border-[16px] border-slate-100 rounded-full"></div>
              <div className="absolute inset-0 border-[16px] border-[#4f46e5] rounded-full border-t-transparent animate-spin"></div>
              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <Loader2 className="w-14 h-14 text-[#4f46e5] animate-pulse" />
                <span className="text-4xl font-black text-slate-900 mt-2">{Math.round((progress.current / progress.total) * 100) || 0}%</span>
              </div>
            </div>
            <div>
              <h3 className="text-3xl font-black text-slate-900 tracking-tight mb-2">{progress.phase}</h3>
              <p className="text-slate-400 font-bold uppercase text-xs tracking-[0.3em]">IA SmartReport Buscando Dados...</p>
            </div>
          </div>
        )}

        {/* PASSO 4: RESULTADO */}
        {activeStep === 'result' && (
          <div className="space-y-10 animate-in fade-in duration-1000">
            {comparisonResult && (
              <div className="space-y-8">
                <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                  <div>
                    <h2 className="text-4xl font-black text-slate-900 tracking-tight">Divergências de Auditoria</h2>
                    <div className="flex items-center gap-3 mt-3">
                      <div className="px-4 py-1.5 bg-red-50 border border-red-100 rounded-xl flex items-center gap-2">
                        <AlertTriangle className="w-4 h-4 text-red-600" />
                        <span className="text-xs font-black text-red-700 uppercase tracking-widest">
                          {comparisonResult.data.filter(d => d.isDifferent).length} Conflitos Identificados
                        </span>
                      </div>
                    </div>
                  </div>
                  <div className="flex gap-3">
                    <button onClick={() => setActiveStep('start')} className="px-6 py-4 bg-white border-2 border-slate-100 font-bold rounded-2xl text-slate-500 transition-all hover:bg-slate-50">Início</button>
                    <button onClick={downloadExcel} className="px-8 py-4 bg-green-600 text-white font-black rounded-2xl hover:bg-green-700 shadow-xl flex items-center gap-3 text-lg transition-all active:scale-95"><Download className="w-6 h-6" /> Exportar Auditoria</button>
                  </div>
                </div>

                <div className="bg-white border-2 border-slate-100 rounded-[3rem] overflow-hidden shadow-2xl">
                  <div className="max-h-[600px] overflow-auto custom-scrollbar">
                    <table className="w-full text-left border-collapse">
                      <thead className="sticky top-0 bg-[#0f172a] text-white z-10 shadow-lg">
                        <tr>
                          <th className="px-10 py-6 text-[10px] font-black uppercase tracking-widest">Identificador</th>
                          <th className="px-10 py-6 text-[10px] font-black uppercase tracking-widest">Campo</th>
                          <th className="px-10 py-6 text-[10px] font-black uppercase tracking-widest">Arquivo A</th>
                          <th className="px-10 py-6 text-[10px] font-black uppercase tracking-widest">Arquivo B</th>
                          <th className="px-10 py-6 text-[10px] font-black uppercase tracking-widest">Status</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                        {comparisonResult.data.map((row, i) => (
                          <tr key={i} className={`hover:bg-slate-50 transition-colors ${row.isDifferent ? 'bg-red-50/30' : 'opacity-40'}`}>
                            <td className="px-10 py-6 text-sm font-bold text-slate-900">{row.key}</td>
                            <td className="px-10 py-6 text-sm font-medium text-slate-500">{row.field}</td>
                            <td className={`px-10 py-6 text-sm font-black ${row.isDifferent ? 'text-red-600' : 'text-slate-600'}`}>{row.valueA || '-'}</td>
                            <td className={`px-10 py-6 text-sm font-black ${row.isDifferent ? 'text-red-600' : 'text-slate-600'}`}>{row.valueB || '-'}</td>
                            <td className="px-10 py-6">
                              {row.isDifferent ? (
                                <span className="px-3 py-1 bg-red-100 text-red-700 text-[10px] font-black rounded-full uppercase">Divergente</span>
                              ) : (
                                <span className="px-3 py-1 bg-green-100 text-green-700 text-[10px] font-black rounded-full uppercase">Ok</span>
                              )}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              </div>
            )}

            {result && (
              <div className="space-y-8">
                <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                  <div>
                    <h2 className="text-4xl font-black text-slate-900 tracking-tight">Consolidação de IA</h2>
                    <div className="flex items-center gap-3 mt-3">
                      <div className="px-4 py-1.5 bg-green-50 border border-green-100 rounded-xl flex items-center gap-2">
                        <CheckCircle className="w-4 h-4 text-green-600" />
                        <span className="text-xs font-black text-green-700 uppercase tracking-widest">{result.data.length} Registros Encontrados</span>
                      </div>
                      {Object.keys(result.formulas || {}).length > 0 && (
                        <div className="px-4 py-1.5 bg-indigo-50 border border-indigo-100 rounded-xl flex items-center gap-2">
                          <Calculator className="w-4 h-4 text-indigo-600" />
                          <span className="text-xs font-black text-indigo-700 uppercase tracking-widest">Excel com Fórmulas</span>
                        </div>
                      )}
                    </div>
                  </div>
                  <div className="flex gap-3">
                    <button onClick={() => setShowColumnSettings(!showColumnSettings)} className="px-6 py-4 border-2 border-slate-100 bg-white font-bold rounded-2xl text-slate-500 hover:bg-slate-50 transition-all"><Settings2 className="w-5 h-5" /></button>
                    <button onClick={downloadExcel} className="px-8 py-4 bg-green-600 text-white font-black rounded-2xl hover:bg-green-700 shadow-xl flex items-center gap-3 text-lg transition-all active:scale-95"><Download className="w-6 h-6" /> Exportar Planilha</button>
                  </div>
                </div>

                {showColumnSettings && (
                  <div className="bg-white p-10 rounded-[2.5rem] border-2 border-indigo-100 shadow-xl animate-in slide-in-from-top-4">
                    <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-6">Colunas Visíveis</h3>
                    <div className="flex flex-wrap gap-3">
                      {result.headers.map(h => (
                        <button
                          key={h}
                          onClick={() => toggleColumn(h)}
                          className={`px-5 py-2.5 rounded-2xl text-[11px] font-black uppercase transition-all flex items-center gap-2 border-2 ${visibleColumns.includes(h) ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'bg-slate-50 border-slate-100 text-slate-300'}`}
                        >
                          {visibleColumns.includes(h) ? <Eye className="w-3 h-3" /> : <EyeOff className="w-3 h-3" />}
                          {h}
                        </button>
                      ))}
                    </div>
                  </div>
                )}

                <div className="bg-white border-2 border-slate-100 rounded-[3rem] overflow-hidden shadow-2xl">
                  <div className="max-h-[600px] overflow-auto custom-scrollbar">
                    <table className="w-full text-left border-collapse">
                      <thead className="sticky top-0 bg-[#0f172a] text-white z-10 shadow-lg">
                        <tr>
                          {result.headers.filter(h => visibleColumns.includes(h)).map(h => (
                            <th key={h} className="px-10 py-6 text-[10px] font-black uppercase tracking-[0.2em] border-r border-white/5 whitespace-nowrap">{h}</th>
                          ))}
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                        {result.data.map((row, i) => (
                          <tr key={i} className="hover:bg-indigo-50/10 group transition-colors">
                            {result.headers.filter(h => visibleColumns.includes(h)).map(h => {
                              const error = getCellError(row, h);
                              return (
                                <td key={`${i}-${h}`} className={`px-10 py-6 text-sm font-bold whitespace-nowrap transition-colors ${error ? 'bg-orange-50 text-orange-700' : 'text-slate-600 group-hover:text-indigo-600'}`}>
                                  <div className="flex items-center gap-2">
                                    {error && <ShieldAlert className="w-3 h-3 text-orange-500 shrink-0" />}
                                    {row[h] || "-"}
                                  </div>
                                </td>
                              );
                            })}
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>

                {result.unmatchedRecords && result.unmatchedRecords.length > 0 && (
                  <div className="space-y-6">
                    <div className="flex items-center gap-4">
                      <div className="p-3 bg-red-50 rounded-2xl"><Ghost className="w-8 h-8 text-red-500" /></div>
                      <div>
                        <h3 className="text-2xl font-black text-slate-900 tracking-tight">Não Conciliados (Órfãos)</h3>
                        <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Indivíduos não encontrados em todos os arquivos</p>
                      </div>
                    </div>
                    <div className="bg-white border-2 border-red-50 rounded-[2.5rem] p-10 shadow-xl">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {result.unmatchedRecords.map((rec, i) => (
                          <div key={i} className="p-6 rounded-[2rem] bg-red-50/30 border border-red-100/50 flex flex-col gap-4">
                            <div className="flex items-center justify-between">
                              <span className="text-lg font-black text-slate-800">{rec.name || "Incompleto"}</span>
                              <span className="text-[10px] font-black uppercase tracking-widest bg-white px-3 py-1 rounded-full text-red-500 shadow-sm">{rec.source}</span>
