                  <button onClick={handleProcess} className="w-full bg-[#4f46e5] text-white py-5 rounded-2xl font-black text-xl hover:bg-[#4338ca] shadow-2xl flex items-center justify-center gap-3">Iniciar Consolidação <ChevronRight className="w-6 h-6" /></button>
