const COMMON_FIELDS = [
  { label: 'Priorizar CPF', value: 'Cruzar dados priorizando o CPF.' },
  { label: 'Fórmula Comissão', value: 'COMISSAO = VALOR_RELATORIO_GERAL - FOLHA - DSR.' },
  { label: 'Registros Órfãos', value: 'Listar separadamente indivíduos não encontrados.' },
  { label: 'Formatar Moeda', value: 'Garantir valores consistentes no Excel.' },
];

const App: React.FC = () => {
  const [activeStep, setActiveStep] = useState<'start' | 'config' | 'processing' | 'result'>('start');
  const [files, setFiles] = useState<FileMetadata[]>([]);
  const [instruction, setInstruction] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, phase: '' });

  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [comparisonResult, setComparisonResult] = useState<ComparisonResult | null>(null);

  const [visibleColumns, setVisibleColumns] = useState<string[]>([]);
  const [error, setError] = useState<string | null>(null);
  const [showColumnSettings, setShowColumnSettings] = useState(false);

  const [isCompareMode, setIsCompareMode] = useState(false);
  const [selectedForCompare, setSelectedForCompare] = useState<number[]>([]);

  useEffect(() => {
    if (result && result.data.length > 0) {
      setVisibleColumns(result.headers);
    }
  }, [result]);

  const selectAction = (action: any) => {
    setIsCompareMode(!!action.isCompare);
    setInstruction(action.instruction || '');
    setActiveStep('config');
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFiles = e.target.files;
    if (selectedFiles) {
      const newFiles: FileMetadata[] = Array.from(selectedFiles).map((f: File) => {
        let detectedType: FileType = 'unknown';
        const name = f.name.toLowerCase();
        if (name.endsWith('.pdf')) detectedType = 'pdf';
        else if (name.endsWith('.xlsx') || name.endsWith('.xls')) detectedType = 'excel';
        else if (f.type.includes('image')) detectedType = 'image';
        return { name: f.name, size: f.size, type: detectedType, raw: f };
      });
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
    setSelectedForCompare(prev => prev.filter(i => i !== index));
  };

  const toggleColumn = (col: string) => {
    setVisibleColumns(prev => prev.includes(col) ? prev.filter(c => c !== col) : [...prev, col]);
  };

  const handleProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setActiveStep('processing');

    try {
      if (isCompareMode && selectedForCompare.length === 2) {
        // Lógica de Comparação
        const fileA = files[selectedForCompare[0]];
        const fileB = files[selectedForCompare[1]];
        const textA = fileA.type === 'pdf' ? (await extractPdfTextInChunks(fileA.raw)).join('\n') : await fileA.raw.text();
        const textB = fileB.type === 'pdf' ? (await extractPdfTextInChunks(fileB.raw)).join('\n') : await fileB.raw.text();
        const res = await compareReports([], [], textA, textB, fileA.name, fileB.name);
        setComparisonResult(res);
      } else {
        // Lógica de Consolidação (Nome, CPF, Valores)
        let allExtractedText = "";
        let imageParts: any[] = [];
        for (let idx = 0; idx < files.length; idx++) {
          const file = files[idx];
          setProgress({ current: idx + 1, total: files.length, phase: `Analisando ${file.name}...` });
          if (file.type === 'pdf') {
            const chunks = await extractPdfTextInChunks(file.raw, 100);
            allExtractedText += `\n[ARQUIVO ${idx+1}]: ${chunks.join("\n")}`;
          } else if (file.type === 'excel') {
            allExtractedText += `\n[ARQUIVO ${idx+1}]: ${await parseExcel(file.raw)}`;
          } else if (file.type === 'image') {
            const b64 = await fileToBase64(file.raw);
            imageParts.push({ inlineData: { data: b64, mimeType: file.raw.type } });
          }
        }
        const res = await extractDataFromReport(instruction, imageParts, allExtractedText);
        setResult(res);
      }
      setActiveStep('result');
    } catch (err: any) {
      setError(err.message || "Erro inesperado.");
      setActiveStep('config');
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadExcel = () => {
    if (!result) return;
    const headers = result.headers;
    const ws_data = [headers];

    // Converte para dados puros
    result.data.forEach(row => {
      ws_data.push(headers.map(h => {
        const val = row[h];
        // Tenta converter para número se parecer um número
        if (typeof val === 'string') {
          const cleanVal = val.replace(',', '.');
          if (!isNaN(Number(cleanVal)) && cleanVal.trim() !== "") return Number(cleanVal);
        }
        return val;
      }));
    });

    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.aoa_to_sheet(ws_data);

    // FIX FÓRMULAS: Mapeia nomes de colunas para letras (A, B, C...)
    if (result.formulas) {
      Object.entries(result.formulas).forEach(([colName, template]) => {
        const targetIdx = headers.indexOf(colName);
        if (targetIdx === -1) return;

        const targetLetter = XLSX.utils.encode_col(targetIdx);
        let formulaBase = template as string;

        // Ordenar cabeçalhos por tamanho para não substituir "Venda" dentro de "Venda Total"
        const sortedHeaders = [...headers].sort((a, b) => b.length - a.length);
        const colMap: Record<string, string> = {};

        sortedHeaders.forEach(h => {
          const hIdx = headers.indexOf(h);
          if (hIdx !== -1) {
            const letter = XLSX.utils.encode_col(hIdx);
            const placeholder = `__${hIdx}__`;
            const regex = new RegExp(`\\b${h.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b`, 'gi');
            if (regex.test(formulaBase)) {
              formulaBase = formulaBase.replace(regex, placeholder);
              colMap[placeholder] = letter;
            }
          }
        });

        // Aplica a fórmula na planilha
        for (let r = 2; r <= result.data.length + 1; r++) {
          let finalF = formulaBase;
          Object.entries(colMap).forEach(([ph, letter]) => {
            finalF = finalF.replace(new RegExp(ph, 'g'), `${letter}${r}`);
          });
          const cell = `${targetLetter}${r}`;
          if (!ws[cell]) ws[cell] = { t: 'n', v: 0 };
          ws[cell].f = finalF;
          delete (ws[cell] as any).v;
        }
      });
    }

    XLSX.utils.book_append_sheet(wb, ws, "Consolidado");
    XLSX.writeFile(wb, `smart_report_${Date.now()}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20 font-sans selection:bg-indigo-100">
      <header className="bg-white border-b border-slate-200 p-4 sticky top-0 z-30 shadow-sm">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setActiveStep('start')}>
            <div className="p-2 bg-[#4f46e5] rounded-xl text-white shadow-lg"><Zap className="w-5 h-5 fill-current" /></div>
            <h1 className="text-xl font-bold tracking-tight">SmartReport <span className="text-[#4f46e5]">Pro</span></h1>
          </div>
          {activeStep !== 'start' && (
            <button onClick={() => setActiveStep('start')} className="flex items-center gap-2 px-4 py-2 text-sm font-bold text-slate-500 hover:text-slate-800 bg-slate-50 rounded-xl">
              <ArrowLeft className="w-4 h-4" /> Início
            </button>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 mt-12">
        {activeStep === 'start' && (
          <div className="animate-in fade-in duration-700 slide-in-from-bottom-4">
            <div className="text-center max-w-2xl mx-auto mb-16">
              <h2 className="text-5xl font-black text-slate-900 mb-6 tracking-tight">
                Tudo o que você precisa para dominar seus <span className="text-[#4f46e5]">relatórios</span>.
              </h2>
              <p className="text-slate-500 text-xl font-medium">Ferramenta online e inteligente para consolidar dados (Nome, CPF, Valores) sem esforço.</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {QUICK_ACTIONS.map(action => (
                <div key={action.id} onClick={() => selectAction(action)} className="group cursor-pointer bg-white border border-slate-100 rounded-[2.5rem] p-8 shadow-sm hover:shadow-2xl hover:-translate-y-2 transition-all">
                  <div className={`w-16 h-16 ${action.color} rounded-2xl flex items-center justify-center mb-8`}>{action.icon}</div>
                  <h3 className="text-xl font-black text-slate-900 mb-3">{action.title}</h3>
                  <p className="text-slate-500 text-sm font-semibold mb-6">{action.description}</p>
                  <div className="text-[#4f46e5] font-black uppercase text-[10px] tracking-widest flex items-center gap-2">Começar agora <ChevronRight className="w-4 h-4" /></div>
                </div>
              ))}
            </div>
            <div className="mt-20 p-12 bg-indigo-600 rounded-[3rem] text-white flex flex-col md:flex-row items-center justify-between shadow-2xl">
              <div className="max-w-md">
                <h4 className="text-2xl font-black mb-2">Novo: Auditoria Nativa Excel</h4>
                <p className="opacity-80">Agora a IA gera planilhas com fórmulas reais. Nada de valores estáticos.</p>
              </div>
              <button onClick={() => selectAction(QUICK_ACTIONS[1])} className="bg-white text-indigo-600 px-8 py-4 rounded-2xl font-black text-lg hover:bg-indigo-50 mt-8 md:mt-0">Testar Fórmulas</button>
            </div>
          </div>
        )}

        {activeStep === 'config' && (
          <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-right-4 bg-white rounded-[2.5rem] shadow-2xl p-10 border border-slate-100">
            <h2 className="text-3xl font-black text-slate-900 mb-10">Configure sua Tarefa</h2>
            <div className="border-[3px] border-dashed border-slate-100 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50/40 hover:bg-slate-50 transition-all group mb-10">
              <UploadCloud className="w-16 h-16 text-indigo-200 mb-6 group-hover:text-[#4f46e5]" />
              <input type="file" id="multi-file" className="hidden" multiple onChange={handleFileChange} />
