import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ExtractedData, ProcessingResult, ComparisonResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const cleanJsonResponse = (text: string): string => {
  let cleaned = text.trim();
  cleaned = cleaned.replace(/^```[a-zA-Z]*\n?/gm, "").replace(/```$/gm, "");
  return cleaned.trim();
};

export const extractDataFromReport = async (
  userInstruction: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  const model = 'gemini-3-pro-preview';

  const systemInstruction = `
    Você é um Especialista em Extração de Dados Financeiros e Auditoria.
    Sua tarefa é extrair e consolidar dados de múltiplos arquivos.

    REGRAS OBRIGATÓRIAS:
    1. CAPTURA DE VALORES: Você deve identificar e extrair TODOS os valores numéricos associados a cada pessoa (como "Vl. Devido", "Venda Total", "Comissão"). Nunca deixe colunas de valores vazias se houver números nos arquivos originais.
    2. CHAVES: Use o CPF (000.000.000-00) ou Nome para cruzar os dados entre os diferentes arquivos.
    3. FORMATO NUMÉRICO: Retorne os valores monetários APENAS como números decimais (ex: 1500.50). Remova "R$", pontos de milhar e use ponto para decimal.
    4. PRECISÃO: Se o "Relatório 1" tem o Nome e o "Relatório 2" tem o "Vl. Devido", o resultado final DEVE unir os dois na mesma linha usando o CPF/Nome como match.

    ESTRUTURA JSON EXATA:
    {
      "data": [{ "Nome": "...", "CPF": "...", "Vl. Devido": 1500.00, "OutroValor": 200.00 }],
      "formulas": { "Total": "Vl. Devido + OutroValor" },
      "headers": ["Nome", "CPF", "Vl. Devido", "OutroValor"],
      "unmatchedRecords": [],
      "summary": "Resumo da extração"
    }
  `;

  const finalPrompt = `
    INSTRUÇÕES DO USUÁRIO: ${userInstruction}

    TAREFA: Extraia Nome, CPF e todos os valores financeiros encontrados. 
    Certifique-se de preencher os valores para cada CPF encontrado nos arquivos. 
    Não retorne colunas de valores vazias se o dado existir no contexto abaixo.

    CONTEÚDO DOS ARQUIVOS:
    ${textContent || 'Analise as imagens anexadas e extraia os dados visíveis.'}
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { parts: [...fileParts, { text: finalPrompt }] },
      config: { systemInstruction, responseMimeType: "application/json", temperature: 0.1 }
    });

    const result = JSON.parse(cleanJsonResponse(response.text || ""));
    return {
      data: result.data || [],
      headers: result.headers || [],
      summary: result.summary,
      unmatchedRecords: result.unmatchedRecords || [],
      formulas: result.formulas || {}
    };
  } catch (error) {
    console.error("Erro API:", error);
    return { data: [], headers: [], summary: "Erro no processamento da IA ao tentar extrair valores." };
  }
};

export const compareReports = async (
  fileAParts: { inlineData: { data: string; mimeType: string } }[],
  fileBParts: { inlineData: { data: string; mimeType: string } }[],
  textA: string,
  textB: string,
  nameA: string,
  nameB: string
): Promise<ComparisonResult> => {
  const model = 'gemini-3-pro-preview';
  const systemInstruction = `Auditor de dados. Compare A e B. Retorne JSON { "data": [...], "summary": "..." }`;
  const prompt = `Compare: ${nameA} vs ${nameB}.\nText A: ${textA}\nText B: ${textB}`;
  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { parts: [...fileAParts, ...fileBParts, { text: prompt }] },
      config: { systemInstruction, responseMimeType: "application/json", temperature: 0.1 }
    });
    const result = JSON.parse(cleanJsonResponse(response.text || ""));
    return { data: result.data || [], headers: ['key', 'field', 'valueA', 'valueB', 'isDifferent'], summary: result.summary };
  } catch (error) {
    return { data: [], headers: [], summary: "Erro na comparação." };
  }
};

