                    {filteredAndSortedData.length === 0 && (
                      <tr>
                        <td colSpan={visibleColumns.length} className="px-10 py-20 text-center text-slate-400 font-bold text-xl bg-slate-50/50">
                          Nenhum registro encontrado para "{searchTerm}"
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>

            {result.summary && (
              <div className="mx-4 p-14 bg-[#0f172a] text-slate-200 rounded-[4rem] shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 right-0 p-10 opacity-5">
                  <Database className="w-64 h-64 text-indigo-400" />
                </div>
                <div className="relative z-10 flex flex-col md:flex-row items-start gap-10">
                  <div className="p-4 bg-indigo-500/20 rounded-3xl"><Info className="w-10 h-10 text-indigo-400" /></div>
                  <div className="space-y-4">
                    <h5 className="text-indigo-400 text-xs font-black uppercase tracking-widest">Resumo de Auditoria</h5>
                    <p className="text-2xl font-semibold leading-relaxed">"{result.summary}"</p>
                  </div>
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 10px; height: 10px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #f8fafc; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 20px; border: 4px solid #f8fafc; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #94a3b8; }
        table { border-spacing: 0; }
        tr:last-child td { border-bottom: 0; }
      `}</style>
    </div>
  );
};

