      <main className={`${activeStep === 'result' ? 'max-w-none' : 'max-w-6xl'} mx-auto px-4 mt-12 transition-all duration-500`}>
        {activeStep === 'start' && (
          <div className="animate-in fade-in duration-700 slide-in-from-bottom-4">
            <div className="text-center max-w-2xl mx-auto mb-16">
              <h2 className="text-5xl font-black text-slate-900 mb-6 tracking-tight">
                Tudo o que você precisa para dominar seus <span className="text-[#4f46e5]">relatórios</span>.
              </h2>
              <p className="text-slate-500 text-xl font-medium">Ferramenta online e inteligente para consolidar dados (Nome, CPF, Valores) sem esforço manual.</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {QUICK_ACTIONS.map(action => (
                <div key={action.id} onClick={() => selectAction(action)} className="group cursor-pointer bg-white border border-slate-100 rounded-[2.5rem] p-8 shadow-sm hover:shadow-2xl hover:-translate-y-2 transition-all">
                  <div className={`w-16 h-16 ${action.color} rounded-2xl flex items-center justify-center mb-8`}>{action.icon}</div>
                  <h3 className="text-xl font-black text-slate-900 mb-3">{action.title}</h3>
                  <p className="text-slate-500 text-sm font-semibold mb-6">{action.description}</p>
                  <div className="text-[#4f46e5] font-black uppercase text-[10px] tracking-widest flex items-center gap-2">Começar agora <ChevronRight className="w-4 h-4" /></div>
                </div>
              ))}
            </div>
            <div className="mt-20 p-12 bg-indigo-600 rounded-[3rem] text-white flex flex-col md:flex-row items-center justify-between shadow-2xl">
              <div className="max-w-md">
                <h4 className="text-2xl font-black mb-2">Novo: Auditoria Nativa Excel</h4>
                <p className="opacity-80">Agora a IA gera planilhas com fórmulas reais. Nada de valores estáticos, apenas inteligência aplicada diretamente na célula.</p>
              </div>
              <button onClick={() => selectAction(QUICK_ACTIONS[1])} className="bg-white text-indigo-600 px-8 py-4 rounded-2xl font-black text-lg hover:bg-indigo-50 mt-8 md:mt-0">Testar Fórmulas <Calculator className="inline-block ml-2 w-5 h-5"/></button>
            </div>
          </div>
        )}

        {activeStep === 'config' && (
          <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-right-4 bg-white rounded-[2.5rem] shadow-2xl p-10 border border-slate-100">
            <h2 className="text-3xl font-black text-slate-900 mb-10">Configuração da Consolidação</h2>
            <div className="border-[3px] border-dashed border-slate-100 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50/40 hover:bg-slate-50 transition-all group mb-10">
              <UploadCloud className="w-16 h-16 text-indigo-200 mb-6 group-hover:text-[#4f46e5]" />
              <input type="file" id="multi-file" className="hidden" multiple onChange={handleFileChange} />
              <label htmlFor="multi-file" className="bg-[#4f46e5] text-white px-10 py-4 rounded-2xl font-bold cursor-pointer hover:bg-[#4338ca] shadow-xl">Anexar Arquivos</label>
              <p className="text-slate-400 text-xs font-bold uppercase mt-4">PDF, Excel ou Fotos</p>
            </div>
            {files.length > 0 && (
              <div className="space-y-8">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {files.map((f, i) => (
                    <div key={i} className="flex items-center justify-between p-5 rounded-2xl border border-slate-100 bg-white shadow-sm">
                      <div className="flex items-center gap-3 overflow-hidden">
                        {f.type === 'pdf' ? <FileText className="text-red-500" /> : <FileSpreadsheet className="text-green-600" />}
                        <span className="text-sm font-bold text-slate-700 truncate">{f.name}</span>
                      </div>
                      <X className="w-5 h-5 text-slate-300 cursor-pointer" onClick={() => setFiles(prev => prev.filter((_, idx) => idx !== i))} />
                    </div>
                  ))}
                </div>
                <div className="space-y-6">
                  <div className="flex flex-wrap gap-2">
                    {COMMON_FIELDS.map(f => (
                      <button key={f.label} onClick={() => setInstruction(i => i + " " + f.value)} className="px-3 py-1.5 bg-slate-50 border border-slate-200 rounded-full text-[10px] font-black uppercase hover:border-indigo-500">+ {f.label}</button>
