                            onClick={() => handleSort(h)}
                            className={`w-full text-left px-10 py-8 text-[11px] font-black uppercase tracking-[0.2em] flex items-center gap-3 hover:bg-white/10 transition-colors ${sortConfig.key === h ? 'text-indigo-400' : ''}`}
