                               <ArrowUpDown className="w-3 h-3" />}
                            </div>
                          </button>
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {filteredAndSortedData.map((row, i) => (
