const COMMON_FIELDS = [
  { label: 'Priorizar CPF', value: 'Cruzar dados priorizando o CPF.' },
  { label: 'Fórmula Comissão', value: 'COMISSAO = VALOR_RELATORIO_GERAL - FOLHA - DSR.' },
  { label: 'Registros Órfãos', value: 'Listar separadamente indivíduos não encontrados.' },
  { label: 'Formatar Moeda', value: 'Garantir valores consistentes no Excel.' },
];

const App: React.FC = () => {
  const [activeStep, setActiveStep] = useState<'start' | 'config' | 'processing' | 'result'>('start');
  const [files, setFiles] = useState<FileMetadata[]>([]);
  const [instruction, setInstruction] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, phase: '' });

  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [visibleColumns, setVisibleColumns] = useState<string[]>([]);
  const [showColumnSettings, setShowColumnSettings] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<{ key: string; direction: 'asc' | 'desc' | null }>({ key: '', direction: null });

  useEffect(() => {
    if (result && result.data.length > 0) {
      setVisibleColumns(result.headers);
    }
  }, [result]);

  const selectAction = (action: any) => {
    setInstruction(action.instruction || '');
    setActiveStep('config');
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFiles = e.target.files;
    if (selectedFiles) {
      const newFiles: FileMetadata[] = Array.from(selectedFiles).map((f: File) => {
        let detectedType: FileType = 'unknown';
        const name = f.name.toLowerCase();
        if (name.endsWith('.pdf')) detectedType = 'pdf';
        else if (name.endsWith('.xlsx') || name.endsWith('.xls')) detectedType = 'excel';
        else if (f.type.includes('image')) detectedType = 'image';
        return { name: f.name, size: f.size, type: detectedType, raw: f };
      });
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const handleProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setActiveStep('processing');

    try {
      let allExtractedText = "";
      let imageParts: any[] = [];
      for (let idx = 0; idx < files.length; idx++) {
        const file = files[idx];
        setProgress({ current: idx + 1, total: files.length, phase: `Processando ${file.name}...` });
        if (file.type === 'pdf') {
          const chunks = await extractPdfTextInChunks(file.raw, 100);
          allExtractedText += `\n[ARQUIVO ${idx+1}]: ${chunks.join("\n")}`;
        } else if (file.type === 'excel') {
          allExtractedText += `\n[ARQUIVO ${idx+1}]: ${await parseExcel(file.raw)}`;
        } else if (file.type === 'image') {
          const b64 = await fileToBase64(file.raw);
          imageParts.push({ inlineData: { data: b64, mimeType: file.raw.type } });
        }
      }
      const res = await extractDataFromReport(instruction, imageParts, allExtractedText);
      setResult(res);
      setActiveStep('result');
    } catch (err: any) {
      console.error(err);
      setActiveStep('config');
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSort = (key: string) => {
    let direction: 'asc' | 'desc' | null = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') direction = 'desc';
    else if (sortConfig.key === key && sortConfig.direction === 'desc') direction = null;
    setSortConfig({ key, direction });
  };

  const toggleColumn = (column: string) => {
    setVisibleColumns(prev => 
      prev.includes(column) ? prev.filter(c => c !== column) : [...prev, column]
    );
  };

  const filteredAndSortedData = useMemo(() => {
    if (!result) return [];
    let data = [...result.data];

    if (searchTerm) {
      const lowerSearch = searchTerm.toLowerCase();
      data = data.filter(row => 
        Object.values(row).some(val => String(val).toLowerCase().includes(lowerSearch))
      );
    }

    if (sortConfig.key && sortConfig.direction) {
      data.sort((a, b) => {
        const valA = a[sortConfig.key];
        const valB = b[sortConfig.key];
        if (typeof valA === 'number' && typeof valB === 'number') {
          return sortConfig.direction === 'asc' ? valA - valB : valB - valA;
        }
        const strA = String(valA || '').toLowerCase();
        const strB = String(valB || '').toLowerCase();
        if (strA < strB) return sortConfig.direction === 'asc' ? -1 : 1;
        if (strA > strB) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
      });
    }

    return data;
  }, [result, searchTerm, sortConfig]);

  const downloadExcel = () => {
    if (!result) return;
    const headers = result.headers;
    const ws_data = [headers];
    result.data.forEach(row => {
      ws_data.push(headers.map(h => {
        const val = row[h];
        if (typeof val === 'string') {
          const cleanVal = val.replace(',', '.');
          if (!isNaN(Number(cleanVal)) && cleanVal.trim() !== "") return Number(cleanVal);
        }
        return val;
      }));
    });
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.aoa_to_sheet(ws_data);
    XLSX.utils.book_append_sheet(wb, ws, "Resultado");
    XLSX.writeFile(wb, `relatorio_extraido_${Date.now()}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20 font-sans">
      <header className="bg-white border-b border-slate-200 p-4 sticky top-0 z-40 shadow-sm">
        <div className="max-w-[100rem] mx-auto flex items-center justify-between px-4">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setActiveStep('start')}>
            <div className="p-2 bg-[#4f46e5] rounded-xl text-white shadow-lg"><Zap className="w-5 h-5 fill-current" /></div>
            <h1 className="text-xl font-bold tracking-tight">SmartReport <span className="text-[#4f46e5]">Pro</span></h1>
          </div>
          {activeStep !== 'start' && (
            <button onClick={() => setActiveStep('start')} className="flex items-center gap-2 px-4 py-2 text-sm font-bold text-slate-500 hover:text-slate-800 bg-slate-50 rounded-xl">
              <ArrowLeft className="w-4 h-4" /> Voltar ao Início
            </button>
          )}
        </div>
      </header>

      <main className={`${activeStep === 'result' ? 'max-w-full px-0' : 'max-w-6xl px-4'} mx-auto mt-12 transition-all duration-300`}>
        {activeStep === 'start' && (
          <div className="animate-in fade-in duration-700 slide-in-from-bottom-4">
            <div className="text-center max-w-2xl mx-auto mb-16">
              <h2 className="text-5xl font-black text-slate-900 mb-6 tracking-tight">
                Organize seus <span className="text-[#4f46e5]">relatórios</span> agora.
              </h2>
              <p className="text-slate-500 text-xl font-medium">Extração inteligente de Nome, CPF e Valores de qualquer documento.</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {QUICK_ACTIONS.map(action => (
                <div key={action.id} onClick={() => selectAction(action)} className="group cursor-pointer bg-white border border-slate-100 rounded-[2.5rem] p-8 shadow-sm hover:shadow-2xl hover:-translate-y-2 transition-all">
                  <div className={`w-16 h-16 ${action.color} rounded-2xl flex items-center justify-center mb-8`}>{action.icon}</div>
                  <h3 className="text-xl font-black text-slate-900 mb-3">{action.title}</h3>
                  <p className="text-slate-500 text-sm font-semibold mb-6">{action.description}</p>
                  <div className="text-[#4f46e5] font-black uppercase text-[10px] tracking-widest flex items-center gap-2">Iniciar <ChevronRight className="w-4 h-4" /></div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeStep === 'config' && (
          <div className="max-w-4xl mx-auto bg-white rounded-[2.5rem] shadow-2xl p-10 border border-slate-100 animate-in fade-in">
            <h2 className="text-3xl font-black text-slate-900 mb-10">Enviar Documentos</h2>
            <div className="border-[3px] border-dashed border-slate-100 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50/40 hover:bg-slate-50 transition-all group mb-10">
              <UploadCloud className="w-16 h-16 text-indigo-200 mb-6 group-hover:text-[#4f46e5]" />
              <input type="file" id="multi-file" className="hidden" multiple onChange={handleFileChange} />
              <label htmlFor="multi-file" className="bg-[#4f46e5] text-white px-10 py-4 rounded-2xl font-bold cursor-pointer hover:bg-[#4338ca] shadow-xl">Anexar Arquivos</label>
            </div>
            {files.length > 0 && (
              <div className="space-y-8">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {files.map((f, i) => (
                    <div key={i} className="flex items-center justify-between p-5 rounded-2xl border border-slate-100 bg-white shadow-sm">
                      <div className="flex items-center gap-3 overflow-hidden">
                        {f.type === 'pdf' ? <FileText className="text-red-500" /> : <FileSpreadsheet className="text-green-600" />}
                        <span className="text-sm font-bold text-slate-700 truncate">{f.name}</span>
                      </div>
                      <X className="w-5 h-5 text-slate-300 cursor-pointer" onClick={() => setFiles(prev => prev.filter((_, idx) => idx !== i))} />
                    </div>
                  ))}
                </div>
                <textarea value={instruction} onChange={e => setInstruction(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-3xl p-6 min-h-[140px] focus:border-[#4f46e5] outline-none transition-all font-semibold" placeholder="Descreva o que deseja extrair..." />
                <button onClick={handleProcess} className="w-full bg-[#4f46e5] text-white py-5 rounded-2xl font-black text-xl hover:bg-[#4338ca] shadow-2xl flex items-center justify-center gap-3">Processar Relatórios</button>
              </div>
            )}
          </div>
        )}

        {activeStep === 'processing' && (
          <div className="max-w-2xl mx-auto py-20 text-center space-y-12">
            <div className="relative w-56 h-56 mx-auto">
              <div className="absolute inset-0 border-[16px] border-slate-100 rounded-full"></div>
              <div className="absolute inset-0 border-[16px] border-[#4f46e5] rounded-full border-t-transparent animate-spin"></div>
              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <Loader2 className="w-14 h-14 text-[#4f46e5] animate-pulse" />
                <span className="text-4xl font-black text-slate-900 mt-2">{Math.round((progress.current / (progress.total || 1)) * 100)}%</span>
              </div>
            </div>
            <h3 className="text-3xl font-black text-slate-900 tracking-tight">{progress.phase}</h3>
          </div>
        )}

        {activeStep === 'result' && result && (
          <div className="w-full animate-in fade-in duration-500">
            {/* Toolbar Full Width */}
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6 px-10 mb-8">
              <div className="space-y-1">
                <h2 className="text-4xl font-black text-slate-900 tracking-tighter">Dados Extraídos</h2>
