              </div>
              <div className="flex flex-wrap items-center gap-4">
                <div className="relative group min-w-[400px]">
                  <Search className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 group-focus-within:text-[#4f46e5]" />
