                    type="text" 
                    placeholder="Filtrar dados na tabela..." 
                    className="w-full bg-white border-2 border-slate-100 rounded-2xl py-4 pl-14 pr-6 font-bold outline-none focus:border-[#4f46e5] shadow-sm focus:shadow-xl transition-all"
