                <button onClick={() => setShowColumnSettings(!showColumnSettings)} className={`p-4 rounded-2xl border-2 transition-all ${showColumnSettings ? 'bg-[#4f46e5] text-white border-[#4f46e5]' : 'bg-white border-slate-100 text-slate-500'}`}><Settings2 /></button>
                <button onClick={downloadExcel} className="px-10 py-5 bg-green-600 text-white font-black rounded-2xl hover:bg-green-700 shadow-2xl flex items-center gap-3 text-lg"><Download /> Exportar Excel</button>
              </div>
