import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ProcessingResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const cleanJsonResponse = (text: string): string => {
  let cleaned = text.trim();
  cleaned = cleaned.replace(/^```[a-zA-Z]*\n?/gm, "").replace(/```$/gm, "");
  return cleaned.trim();
};

export const extractDataFromReport = async (
  userInstruction: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  const model = 'gemini-3-pro-preview';

  const systemInstruction = `
    Você é um Auditor de Dados Sênior. Sua missão é CONSOLIDAR DOIS RELATÓRIOS.

    REGRAS CRÍTICAS DE NEGÓCIO:
    1. RELATÓRIO BASE: O primeiro arquivo/texto fornecido é o seu "Relatório Base". Você deve manter TODOS os registros dele exatamente como estão.
    2. RELATÓRIO DE COMPLEMENTO: O segundo arquivo contém informações que devem ser ADICIONADAS ao primeiro.
    3. CRUZAMENTO (MATCH): Use CPF (prioridade) ou Nome Completo para encontrar a mesma pessoa nos dois arquivos.
    4. DADOS ÓRFÃOS (UNMATCHED): Se houver pessoas no SEGUNDO relatório que NÃO existem no PRIMEIRO, você NÃO deve colocá-las na tabela principal. Coloque-as no array "unmatchedRecords" informando o nome e o motivo (ex: "Registro presente apenas no segundo relatório").
    5. VALORES FINANCEIROS: Capture todos os valores (Vl. Devido, Comissões, etc) e garanta que o valor do segundo relatório seja colocado na coluna correta da linha correspondente do primeiro relatório.

    ESTRUTURA DE RETORNO (JSON):
    {
      "data": [{ "Nome": "...", "CPF": "...", "ColunaBase": "...", "ColunaNovaDoRelatorio2": 150.00 }],
      "headers": ["Nome", "CPF", "ColunaBase", "ColunaNovaDoRelatorio2"],
      "unmatchedRecords": [{ "name": "...", "reason": "Não encontrado no Relatório 1", "source": "Relatório 2" }],
      "summary": "Resumo detalhado de quantos registros foram cruzados e quantos ficaram de fora."
    }
  `;

  const finalPrompt = `
    INSTRUÇÃO ESPECÍFICA DO USUÁRIO: ${userInstruction}

    AJA COMO UM AUDITOR: 
    - Pegue o Relatório 1 como base fixa.
    - Procure os dados dessas mesmas pessoas no Relatório 2.
    - Se achar, preencha as novas colunas de valores.
    - Se não achar a pessoa do Relatório 2 no Relatório 1, liste em 'unmatchedRecords'.

    CONTEÚDO DOS DOCUMENTOS:
    ${textContent || 'Analise os arquivos/imagens enviados.'}
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { parts: [...fileParts, { text: finalPrompt }] },
      config: { 
        systemInstruction, 
        responseMimeType: "application/json", 
        temperature: 0.1 
      }
    });

    const result = JSON.parse(cleanJsonResponse(response.text || ""));
    return {
      data: result.data || [],
      headers: result.headers || [],
      summary: result.summary,
      unmatchedRecords: result.unmatchedRecords || [],
      formulas: result.formulas || {}
    };
  } catch (error) {
    console.error("Erro na extração Gemini:", error);
    return { data: [], headers: [], summary: "Erro técnico ao processar cruzamento de dados." };
  }
};

