            {/* Toolbar Full Width */}
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6 px-10 mb-8">
              <div className="space-y-1">
                <h2 className="text-4xl font-black text-slate-900 tracking-tighter">Relatório Consolidado</h2>
