import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ProcessingResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const cleanJsonResponse = (text: string): string => {
  let cleaned = text.trim();
  cleaned = cleaned.replace(/^```[a-zA-Z]*\n?/gm, "").replace(/```$/gm, "");
  return cleaned.trim();
};

export const extractDataFromReport = async (
  userInstruction: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  const model = 'gemini-3-pro-preview';

  const systemInstruction = `
    Você é um Engenheiro de Dados e Auditor Especialista em Conciliação Bancária e de Folha.
    Sua tarefa é cruzar informações entre dois relatórios com 100% de precisão.

    DIRETRIZES TÉCNICAS:
    1. ARQUIVO ÂNCORA (RELATÓRIO 1): Este é o seu mestre. NADA deste arquivo pode ser removido. Cada linha do Relatório 1 deve existir no resultado final.
    2. BUSCA DE DADOS (RELATÓRIO 2): Você deve localizar os mesmos indivíduos no Relatório 2 usando CPF (limpe pontuação para comparar) ou Nome Completo (ignore maiúsculas/minúsculas).
    3. PRECISÃO NA DESCRIÇÃO: O usuário pedirá campos específicos (ex: "traga o valor de comissão"). Você deve analisar os cabeçalhos do Relatório 2, encontrar o campo que MAIS SE APROXIMA do pedido e extrair o valor numérico.
    4. FORMATAÇÃO DE VALORES: Transforme strings de valores (Ex: "R$ 1.200,50") em números (1200.50).
    5. REGISTROS ÓRFÃOS: Se houver alguém no Relatório 2 que não está no Relatório 1, adicione-os obrigatoriamente no campo "unmatchedRecords".
    6. MANUTENÇÃO DE DADOS: Se um registro da Base não for encontrado no Relatório 2, mantenha os dados da Base e deixe as novas colunas como null ou 0.

    ESTRUTURA JSON OBRIGATÓRIA:
    {
      "data": [
        { 
          "Nome": "...", 
          "CPF": "...", 
          "Campo_Original_Base": "...", 
          "Campo_Solicitado_Relatorio_2": 0.00 
        }
      ],
      "headers": ["Nome", "CPF", "Campo_Original_Base", "Campo_Solicitado_Relatorio_2"],
      "unmatchedRecords": [
        { "name": "...", "reason": "Consta no Relatório 2 mas não na Base", "source": "Relatório 2" }
      ],
      "summary": "Explicação curta do sucesso do cruzamento."
    }
  `;

  const finalPrompt = `
    INSTRUÇÕES DO USUÁRIO: ${userInstruction}

    RELATÓRIOS PARA ANÁLISE:
    ${textContent || 'Analise as imagens e tabelas fornecidas abaixo.'}

    OBSERVAÇÃO: Foque na precisão dos valores. Se o usuário pediu "valor de venda", não traga "valor de desconto". Leia atentamente as descrições das colunas.
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { parts: [...fileParts, { text: finalPrompt }] },
      config: { 
        systemInstruction, 
        responseMimeType: "application/json", 
        temperature: 0, // Zero para máxima precisão e consistência
        thinkingConfig: { thinkingBudget: 4000 } // Permitir que o modelo raciocine sobre o cruzamento
      }
    });

    const text = response.text;
    if (!text) throw new Error("Resposta vazia da IA");

    const result = JSON.parse(cleanJsonResponse(text));
    return {
      data: result.data || [],
      headers: result.headers || [],
      summary: result.summary,
      unmatchedRecords: result.unmatchedRecords || [],
      formulas: result.formulas || {}
    };
  } catch (error) {
    console.error("Erro na extração Gemini:", error);
    return { 
      data: [], 
      headers: [], 
      summary: "Falha crítica no processamento. Verifique se as instruções estão claras." 
    };
  }
};

