  const [progress, setProgress] = useState({ current: 0, total: 0, phase: '' });

  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [visibleColumns, setVisibleColumns] = useState<string[]>([]);
  const [showColumnSettings, setShowColumnSettings] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<{ key: string; direction: 'asc' | 'desc' | null }>({ key: '', direction: null });

  useEffect(() => {
    if (result && result.data.length > 0) {
      setVisibleColumns(result.headers);
    }
  }, [result]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFiles = e.target.files;
    if (selectedFiles) {
      const newFiles: FileMetadata[] = Array.from(selectedFiles).map((f: File) => {
        let detectedType: FileType = 'unknown';
        const name = f.name.toLowerCase();
        if (name.endsWith('.pdf')) detectedType = 'pdf';
        else if (name.endsWith('.xlsx') || name.endsWith('.xls')) detectedType = 'excel';
        else if (f.type.includes('image')) detectedType = 'image';
        return { name: f.name, size: f.size, type: detectedType, raw: f };
      });
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const handleProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setActiveStep('processing');

    try {
      let allExtractedText = "";
      let imageParts: any[] = [];
      for (let idx = 0; idx < files.length; idx++) {
        const file = files[idx];
        setProgress({ current: idx + 1, total: files.length, phase: `Analisando: ${file.name}...` });
        if (file.type === 'pdf') {
          const chunks = await extractPdfTextInChunks(file.raw, 100);
          allExtractedText += `\n[ARQUIVO ${idx+1} - ${idx === 0 ? 'RELATÓRIO BASE' : 'RELATÓRIO DE COMPLEMENTO'}]: ${chunks.join("\n")}`;
        } else if (file.type === 'excel') {
          allExtractedText += `\n[ARQUIVO ${idx+1} - ${idx === 0 ? 'RELATÓRIO BASE' : 'RELATÓRIO DE COMPLEMENTO'}]: ${await parseExcel(file.raw)}`;
        } else if (file.type === 'image') {
          const b64 = await fileToBase64(file.raw);
          imageParts.push({ inlineData: { data: b64, mimeType: file.raw.type } });
        }
      }
      const res = await extractDataFromReport(instruction, imageParts, allExtractedText);
      setResult(res);
      setActiveStep('result');
    } catch (err: any) {
      setActiveStep('config');
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSort = (key: string) => {
    let direction: 'asc' | 'desc' | null = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') direction = 'desc';
    else if (sortConfig.key === key && sortConfig.direction === 'desc') direction = null;
    setSortConfig({ key, direction });
  };

  const toggleColumn = (column: string) => {
    setVisibleColumns(prev => 
      prev.includes(column) ? prev.filter(c => c !== column) : [...prev, column]
    );
  };

  const filteredAndSortedData = useMemo(() => {
    if (!result) return [];
    let data = [...result.data];
    if (searchTerm) {
      const lowerSearch = searchTerm.toLowerCase();
      data = data.filter(row => Object.values(row).some(val => String(val).toLowerCase().includes(lowerSearch)));
    }
    if (sortConfig.key && sortConfig.direction) {
      data.sort((a, b) => {
        const valA = a[sortConfig.key];
        const valB = b[sortConfig.key];
        if (typeof valA === 'number' && typeof valB === 'number') return sortConfig.direction === 'asc' ? valA - valB : valB - valA;
        const strA = String(valA || '').toLowerCase();
        const strB = String(valB || '').toLowerCase();
        return sortConfig.direction === 'asc' ? strA.localeCompare(strB) : strB.localeCompare(strA);
      });
    }
    return data;
  }, [result, searchTerm, sortConfig]);

  const downloadExcel = () => {
    if (!result) return;
    const ws_data = [result.headers, ...result.data.map(row => result.headers.map(h => row[h]))];
    const wb = XLSX.utils.book_new();
    const ws = XLSX.utils.aoa_to_sheet(ws_data);
    XLSX.utils.book_append_sheet(wb, ws, "AuditResult");
    XLSX.writeFile(wb, `auditoria_precisa_${Date.now()}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20 font-sans">
      <header className="bg-white border-b border-slate-200 p-4 sticky top-0 z-40 shadow-sm">
        <div className="max-w-[100rem] mx-auto flex items-center justify-between px-4">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setActiveStep('start')}>
            <div className="p-2 bg-[#4f46e5] rounded-xl text-white shadow-lg"><Zap className="w-5 h-5 fill-current" /></div>
            <h1 className="text-xl font-bold tracking-tight">SmartReport <span className="text-[#4f46e5]">Pro</span></h1>
          </div>
          {activeStep !== 'start' && (
            <button onClick={() => setActiveStep('start')} className="flex items-center gap-2 px-6 py-2.5 text-sm font-bold text-slate-600 hover:text-slate-900 bg-slate-100/50 rounded-xl transition-all">
              <ArrowLeft className="w-4 h-4" /> Voltar
            </button>
          )}
        </div>
      </header>

      <main className={`${activeStep === 'result' ? 'max-w-none px-0' : 'max-w-6xl px-4'} mx-auto mt-12 transition-all duration-300`}>
        {activeStep === 'start' && (
          <div className="animate-in fade-in duration-700 slide-in-from-bottom-4 px-4 text-center">
            <h2 className="text-6xl font-black text-slate-900 mb-8 tracking-tighter">
              Auditoria e <span className="text-[#4f46e5]">Cruzamento</span> Inteligente.
            </h2>
            <p className="text-slate-500 text-xl font-medium max-w-2xl mx-auto mb-16">Organize seus relatórios com precisão absoluta. O primeiro arquivo é sua base, o segundo é o seu alvo de busca.</p>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {QUICK_ACTIONS.map(action => (
                <div key={action.id} onClick={() => { setInstruction(action.instruction); setActiveStep('config'); }} className="group cursor-pointer bg-white border border-slate-200 rounded-[3rem] p-10 shadow-sm hover:shadow-2xl hover:-translate-y-2 transition-all border-b-8 border-b-slate-100 hover:border-b-[#4f46e5]">
                  <div className={`w-20 h-20 ${action.color} rounded-[2rem] flex items-center justify-center mb-8`}>{action.icon}</div>
                  <h3 className="text-2xl font-black text-slate-900 mb-4">{action.title}</h3>
                  <p className="text-slate-500 font-semibold mb-6">{action.description}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeStep === 'config' && (
          <div className="max-w-4xl mx-auto bg-white rounded-[3rem] shadow-2xl p-12 border border-slate-100 animate-in fade-in">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-3xl font-black text-slate-900 tracking-tight">Configurar Cruzamento</h2>
              <div className="flex gap-2">
                <span className="bg-indigo-100 text-indigo-700 text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-wider">Passo 1: Base</span>
                <span className="bg-slate-100 text-slate-400 text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-wider">Passo 2: Busca</span>
              </div>
            </div>

            <div className="border-[4px] border-dashed border-slate-100 rounded-[3rem] p-16 flex flex-col items-center justify-center bg-slate-50/40 hover:bg-slate-50 transition-all group mb-12">
              <UploadCloud className="w-20 h-20 text-indigo-200 mb-8 group-hover:text-[#4f46e5] transition-colors" />
              <input type="file" id="multi-file" className="hidden" multiple onChange={handleFileChange} />
              <label htmlFor="multi-file" className="bg-[#4f46e5] text-white px-12 py-5 rounded-2xl font-black cursor-pointer hover:bg-[#4338ca] shadow-2xl text-lg transition-transform active:scale-95">Anexar Relatórios</label>
              <p className="mt-6 text-slate-400 font-bold text-sm">O primeiro arquivo anexado será sua BASE FIXA.</p>
            </div>

            {files.length > 0 && (
              <div className="space-y-10">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                  {files.map((f, i) => (
                    <div key={i} className={`relative flex items-center justify-between p-6 rounded-[2rem] border-2 ${i === 0 ? 'border-indigo-500 bg-indigo-50/50 shadow-lg' : 'border-slate-100 bg-white'} transition-all`}>
                      <div className="flex items-center gap-4 overflow-hidden">
                        {i === 0 ? (
                          <div className="bg-indigo-500 p-2 rounded-xl text-white shadow-md"><Anchor className="w-5 h-5" /></div>
                        ) : (
                          <div className="bg-slate-100 p-2 rounded-xl text-slate-400"><FileText className="w-5 h-5" /></div>
                        )}
                        <div className="flex flex-col overflow-hidden">
                          <span className="text-[10px] font-black uppercase tracking-widest text-indigo-400">{i === 0 ? 'Base de Dados' : 'Relatório de Busca'}</span>
                          <span className="text-sm font-bold text-slate-800 truncate">{f.name}</span>
                        </div>
                      </div>
                      <button onClick={() => setFiles(prev => prev.filter((_, idx) => idx !== i))} className="p-2 hover:bg-red-50 text-slate-300 hover:text-red-500 rounded-lg transition-colors"><X className="w-5 h-5" /></button>
                    </div>
                  ))}
                </div>

                <div className="space-y-4">
                  <label className="text-xs font-black uppercase text-slate-400 tracking-widest ml-4">Instrução de Auditoria</label>
                  <textarea value={instruction} onChange={e => setInstruction(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] p-8 min-h-[160px] focus:border-[#4f46e5] focus:bg-white outline-none transition-all font-semibold text-lg" placeholder="O que deseja extrair do segundo relatório? Ex: 'Busque o Valor de Comissão e a Data de Pagamento para os CPFs da Base'" />
                </div>

                <button onClick={handleProcess} className="w-full bg-slate-900 text-white py-6 rounded-3xl font-black text-xl hover:bg-black shadow-2xl flex items-center justify-center gap-4 transition-all">
                  Processar com Alta Precisão <ChevronRight className="w-6 h-6" />
                </button>
              </div>
            )}
          </div>
        )}

        {activeStep === 'processing' && (
          <div className="max-w-2xl mx-auto py-24 text-center space-y-12 animate-in fade-in">
            <div className="relative w-64 h-64 mx-auto">
              <div className="absolute inset-0 border-[20px] border-slate-100 rounded-full"></div>
              <div className="absolute inset-0 border-[20px] border-[#4f46e5] rounded-full border-t-transparent animate-spin"></div>
              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <Loader2 className="w-16 h-16 text-[#4f46e5] animate-pulse" />
                <span className="text-5xl font-black text-slate-900 mt-2 tracking-tighter">{Math.round((progress.current / (progress.total || 1)) * 100)}%</span>
              </div>
            </div>
            <div className="space-y-4">
              <h3 className="text-4xl font-black text-slate-900 tracking-tight">Auditando Dados</h3>
              <p className="text-slate-500 text-xl font-medium">{progress.phase}</p>
            </div>
          </div>
        )}

        {activeStep === 'result' && result && (
          <div className="w-full animate-in fade-in duration-700">
            {/* Toolbar Full Width */}
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-8 px-12 mb-12">
              <div className="space-y-2">
                <div className="flex items-center gap-3">
                   <div className="bg-green-100 p-2 rounded-xl text-green-600"><CheckCircle className="w-6 h-6" /></div>
                   <h2 className="text-5xl font-black text-slate-900 tracking-tighter">Resultado Final</h2>
                </div>
                <p className="text-slate-500 text-lg font-bold ml-1">Relatório Base consolidado com informações do secundário.</p>
              </div>
              <div className="flex flex-wrap items-center gap-4">
                <div className="relative group min-w-[500px]">
                  <Search className="absolute left-6 top-1/2 -translate-y-1/2 w-6 h-6 text-slate-400 group-focus-within:text-indigo-600 transition-colors" />
                  <input type="text" placeholder="Filtrar registros na tela inteira..." className="w-full bg-white border-2 border-slate-100 rounded-3xl py-5 pl-16 pr-8 font-bold outline-none focus:border-[#4f46e5] shadow-sm focus:shadow-2xl transition-all text-lg" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                </div>
                <button onClick={() => setShowColumnSettings(!showColumnSettings)} className={`p-5 rounded-3xl border-2 transition-all ${showColumnSettings ? 'bg-slate-900 text-white border-slate-900' : 'bg-white border-slate-100 text-slate-400'}`}><Settings2 className="w-7 h-7" /></button>
                <button onClick={downloadExcel} className="px-12 py-5 bg-green-600 text-white font-black rounded-3xl hover:bg-green-700 shadow-2xl flex items-center gap-3 text-xl transition-transform active:scale-95"><Download className="w-6 h-6" /> Exportar</button>
              </div>
            </div>

            {showColumnSettings && (
              <div className="bg-white p-10 rounded-[3rem] border-2 border-indigo-50 shadow-2xl mx-12 mb-12 animate-in slide-in-from-top-4">
                <h4 className="text-xs font-black uppercase text-slate-400 mb-8 tracking-[0.3em] flex items-center gap-3"><Filter className="w-4 h-4" /> Configurar Visibilidade</h4>
                <div className="flex flex-wrap gap-3">
                  {result.headers.map(h => (
                    <button key={h} onClick={() => toggleColumn(h)} className={`px-6 py-3 rounded-2xl text-sm font-black border-2 transition-all flex items-center gap-3 ${visibleColumns.includes(h) ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'bg-slate-50 border-slate-100 text-slate-300'}`}>
                      {visibleColumns.includes(h) ? <Eye className="w-5 h-5" /> : <EyeOff className="w-5 h-5" />} {h}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {/* Tabela Full Width */}
            <div className="bg-white border-y border-slate-200 shadow-sm overflow-hidden w-full mb-16">
              <div className="max-h-[75vh] overflow-auto custom-scrollbar">
                <table className="w-full text-left border-collapse table-auto">
                  <thead className="sticky top-0 bg-slate-900 text-white z-20">
                    <tr>
                      {result.headers.filter(h => visibleColumns.includes(h)).map(h => (
                        <th key={h} className="p-0">
                          <button onClick={() => handleSort(h)} className={`w-full text-left px-12 py-10 text-[12px] font-black uppercase tracking-[0.25em] flex items-center gap-4 hover:bg-white/10 transition-colors ${sortConfig.key === h ? 'text-indigo-400' : ''}`}>
                            {h} 
                            <div className="flex flex-col">
                              {sortConfig.key === h && sortConfig.direction === 'asc' ? <ArrowUp className="w-4 h-4" /> : 
                               sortConfig.key === h && sortConfig.direction === 'desc' ? <ArrowDown className="w-4 h-4" /> : 
                               <ArrowUpDown className="w-4 h-4 opacity-20" />}
                            </div>
                          </button>
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {filteredAndSortedData.map((row, i) => (
                      <tr key={i} className="hover:bg-indigo-50/30 transition-colors group">
                        {result.headers.filter(h => visibleColumns.includes(h)).map(h => (
                          <td key={`${i}-${h}`} className="px-12 py-8 text-base font-bold text-slate-700 group-hover:text-slate-900 transition-colors">
                            {typeof row[h] === 'number' ? row[h].toLocaleString('pt-BR', { minimumFractionDigits: 2 }) : (row[h] || "-")}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            {/* Registros não cruzados */}
            {result.unmatchedRecords && result.unmatchedRecords.length > 0 && (
              <div className="mx-12 mb-20 space-y-8 animate-in slide-in-from-bottom-8">
                <div className="flex items-center gap-4 text-red-600 bg-red-50 p-6 rounded-[2.5rem] w-fit pr-12 border border-red-100">
                  <AlertTriangle className="w-10 h-10" />
                  <div>
                    <h3 className="text-2xl font-black uppercase tracking-tight">Não Reconciliados</h3>
                    <p className="text-red-600/70 font-bold">Estes registros estão no arquivo de busca, mas não existem na sua base.</p>
                  </div>
                </div>
                <div className="bg-white border-2 border-red-100 rounded-[3rem] overflow-hidden shadow-2xl shadow-red-100/50">
                  <table className="w-full text-left">
                    <thead className="bg-red-50/50 text-red-900 text-[11px] font-black uppercase tracking-[0.2em]">
                      <tr>
                        <th className="px-12 py-6">Entidade / Nome</th>
                        <th className="px-12 py-6">Motivo da Exclusão</th>
                        <th className="px-12 py-6">Origem do Dado</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-red-50">
                      {result.unmatchedRecords.map((rec, i) => (
                        <tr key={i} className="hover:bg-red-50/30">
                          <td className="px-12 py-6 text-base font-black text-red-900">{rec.name || rec.cpf || "Identificador Ausente"}</td>
                          <td className="px-12 py-6 text-sm font-semibold text-red-600/80 italic">{rec.reason}</td>
                          <td className="px-12 py-6 text-[10px] font-black text-red-400 uppercase tracking-widest">{rec.source}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {result.summary && (
              <div className="mx-12 p-16 bg-slate-900 text-slate-200 rounded-[4rem] shadow-2xl relative overflow-hidden mb-20">
                <div className="absolute top-0 right-0 p-12 opacity-5"><Database className="w-64 h-64 text-indigo-400" /></div>
                <div className="relative z-10 flex gap-10 items-start">
                  <div className="p-5 bg-indigo-500/20 rounded-3xl"><Info className="w-10 h-10 text-indigo-400" /></div>
                  <div className="space-y-4 max-w-4xl">
                    <h5 className="text-indigo-400 text-[11px] font-black uppercase tracking-[0.4em]">Relatório de Auditoria IA</h5>
                    <p className="text-2xl font-medium leading-relaxed italic text-white/90">"{result.summary}"</p>
                  </div>
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 12px; height: 12px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #f8fafc; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 20px; border: 4px solid #f8fafc; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #94a3b8; }
        table { border-spacing: 0; }
        .max-w-none { max-width: 100vw !important; width: 100% !important; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  FileText, 
  Search, 
  CheckCircle, 
  Download, 
  ChevronRight, 
  FileSpreadsheet, 
  Loader2, 
  Zap, 
  X, 
  UploadCloud, 
  Info, 
  Settings2, 
  Eye, 
  EyeOff, 
  Database, 
  Calculator, 
  UserCheck, 
  ArrowLeft, 
  ArrowUpDown, 
  ArrowUp, 
  ArrowDown, 
  Filter,
  Split,
  AlertTriangle,
  Anchor
} from 'lucide-react';
import * as XLSX from 'xlsx';

import { FileMetadata, ProcessingResult, FileType } from './types';
import { fileToBase64, parseExcel, extractPdfTextInChunks } from './utils/fileUtils';
import { extractDataFromReport } from './services/geminiService';

const QUICK_ACTIONS = [
  {
    id: 'consolidate',
    title: 'Consolidar Planilhas',
    description: 'Una múltiplos arquivos em uma tabela mestre buscando Nome, CPF e Valores.',
    icon: <FileSpreadsheet className="w-8 h-8 text-green-600" />,
    instruction: 'Pegue o Relatório 1 como base. No Relatório 2, procure por Nome ou CPF e traga os valores adicionais solicitados.',
    color: 'bg-green-50'
  },
  {
    id: 'commission',
    title: 'Cálculo de Comissões',
    description: 'Identifica e aplica fórmulas (V. Geral - Folha - DSR) gerando Excel nativo.',
    icon: <Calculator className="w-8 h-8 text-indigo-600" />,
    instruction: 'Relatório 1 é a base. Calcule a COMISSAO subtraindo FOLHA e DSR do VALOR_GERAL que está no Relatório 2.',
    color: 'bg-indigo-50'
  },
  {
    id: 'compare',
    title: 'Auditoria de Cruzamento',
    description: 'Verifique se os dados do Relatório 2 batem com sua Base oficial.',
    icon: <Split className="w-8 h-8 text-red-600" />,
    instruction: 'Compare os registros. Mantenha a Base (Relatório 1) e aponte divergências de valores encontradas no Relatório 2.',
    color: 'bg-red-50'
  }
];

const App: React.FC = () => {
  const [activeStep, setActiveStep] = useState<'start' | 'config' | 'processing' | 'result'>('start');
  const [files, setFiles] = useState<FileMetadata[]>([]);
  const [instruction, setInstruction] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, phase: '' });

  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [visibleColumns, setVisibleColumns] = useState<string[]>([]);
  const [showColumnSettings, setShowColumnSettings] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<{ key: string; direction: 'asc' | 'desc' | null }>({ key: '', direction: null });

  useEffect(() => {
    if (result && result.data.length > 0) {
      setVisibleColumns(result.headers);
    }
  }, [result]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFiles = e.target.files;
    if (selectedFiles) {
      const newFiles: FileMetadata[] = Array.from(selectedFiles).map((f: File) => {
        let detectedType: FileType = 'unknown';
        const name = f.name.toLowerCase();
        if (name.endsWith('.pdf')) detectedType = 'pdf';
        else if (name.endsWith('.xlsx') || name.endsWith('.xls')) detectedType = 'excel';
        else if (f.type.includes('image')) detectedType = 'image';
        return { name: f.name, size: f.size, type: detectedType, raw: f };
      });
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const handleProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setActiveStep('processing');

    try {
      let allExtractedText = "";
      let imageParts: any[] = [];
      for (let idx = 0; idx < files.length; idx++) {
        const file = files[idx];
        setProgress({ current: idx + 1, total: files.length, phase: `Analisando: ${file.name}...` });
        if (file.type === 'pdf') {
          const chunks = await extractPdfTextInChunks(file.raw, 100);
          allExtractedText += `\n[ARQUIVO ${idx+1} - ${idx === 0 ? 'RELATÓRIO BASE' : 'RELATÓRIO DE COMPLEMENTO'}]: ${chunks.join("\n")}`;
        } else if (file.type === 'excel') {
          allExtractedText += `\n[ARQUIVO ${idx+1} - ${idx === 0 ? 'RELATÓRIO BASE' : 'RELATÓRIO DE COMPLEMENTO'}]: ${await parseExcel(file.raw)}`;
        } else if (file.type === 'image') {
          const b64 = await fileToBase64(file.raw);
          imageParts.push({ inlineData: { data: b64, mimeType: file.raw.type } });
        }
      }
      const res = await extractDataFromReport(instruction, imageParts, allExtractedText);
      setResult(res);
      setActiveStep('result');
    } catch (err: any) {
      setActiveStep('config');
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSort = (key: string) => {
    let direction: 'asc' | 'desc' | null = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') direction = 'desc';
    else if (sortConfig.key === key && sortConfig.direction === 'desc') direction = null;
    setSortConfig({ key, direction });
  };

  const toggleColumn = (column: string) => {
    setVisibleColumns(prev => 
      prev.includes(column) ? prev.filter(c => c !== column) : [...prev, column]
    );
  };

  const filteredAndSortedData = useMemo(() => {
    if (!result) return [];
    let data = [...result.data];
    if (searchTerm) {
      const lowerSearch = searchTerm.toLowerCase();
      data = data.filter(row => Object.values(row).some(val => String(val).toLowerCase().includes(lowerSearch)));
    }
    if (sortConfig.key && sortConfig.direction) {
      data.sort((a, b) => {
        const valA = a[sortConfig.key];
        const valB = b[sortConfig.key];
        if (typeof valA === 'number' && typeof valB === 'number') return sortConfig.direction === 'asc' ? valA - valB : valB - valA;
        const strA = String(valA || '').toLowerCase();
        const strB = String(valB || '').toLowerCase();
        return sortConfig.direction === 'asc' ? strA.localeCompare(strB) : strB.localeCompare(strA);
      });
    }
    return data;
  }, [result, searchTerm, sortConfig]);

  const downloadExcel = () => {
    if (!result) return;

    const wb = XLSX.utils.book_new();

    // Aba 1: Dados Consolidados
    const ws_data = [result.headers, ...result.data.map(row => result.headers.map(h => row[h]))];
    const ws_consolidated = XLSX.utils.aoa_to_sheet(ws_data);
    XLSX.utils.book_append_sheet(wb, ws_consolidated, "Dados Consolidados");

    // Aba 2: Registros Não Encontrados (se houver)
    if (result.unmatchedRecords && result.unmatchedRecords.length > 0) {
      const unmatched_headers = ["Identificador (Nome/CPF)", "Motivo da Exclusão", "Origem do Dado"];
      const unmatched_data = [
        unmatched_headers,
        ...result.unmatchedRecords.map(rec => [
          rec.name || rec.cpf || "N/A",
          rec.reason || "Não encontrado na base",
          rec.source || "Relatório Secundário"
        ])
      ];
      const ws_unmatched = XLSX.utils.aoa_to_sheet(unmatched_data);
      XLSX.utils.book_append_sheet(wb, ws_unmatched, "Não Encontrados");
    }

    XLSX.writeFile(wb, `auditoria_completa_${Date.now()}.xlsx`);
  };

  return (
    <div className="min-h-screen bg-[#f8fafc] pb-20 font-sans">
      <header className="bg-white border-b border-slate-200 p-4 sticky top-0 z-40 shadow-sm">
        <div className="max-w-[100rem] mx-auto flex items-center justify-between px-4">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setActiveStep('start')}>
            <div className="p-2 bg-[#4f46e5] rounded-xl text-white shadow-lg"><Zap className="w-5 h-5 fill-current" /></div>
            <h1 className="text-xl font-bold tracking-tight">SmartReport <span className="text-[#4f46e5]">Pro</span></h1>
          </div>
          {activeStep !== 'start' && (
            <button onClick={() => setActiveStep('start')} className="flex items-center gap-2 px-6 py-2.5 text-sm font-bold text-slate-600 hover:text-slate-900 bg-slate-100/50 rounded-xl transition-all">
              <ArrowLeft className="w-4 h-4" /> Voltar
            </button>
          )}
        </div>
      </header>

      <main className={`${activeStep === 'result' ? 'max-w-none px-0' : 'max-w-6xl px-4'} mx-auto mt-12 transition-all duration-300`}>
        {activeStep === 'start' && (
          <div className="animate-in fade-in duration-700 slide-in-from-bottom-4 px-4 text-center">
            <h2 className="text-6xl font-black text-slate-900 mb-8 tracking-tighter">
              Auditoria e <span className="text-[#4f46e5]">Cruzamento</span> Inteligente.
            </h2>
            <p className="text-slate-500 text-xl font-medium max-w-2xl mx-auto mb-16">Organize seus relatórios com precisão absoluta. O primeiro arquivo é sua base, o segundo é o seu alvo de busca.</p>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {QUICK_ACTIONS.map(action => (
                <div key={action.id} onClick={() => { setInstruction(action.instruction); setActiveStep('config'); }} className="group cursor-pointer bg-white border border-slate-200 rounded-[3rem] p-10 shadow-sm hover:shadow-2xl hover:-translate-y-2 transition-all border-b-8 border-b-slate-100 hover:border-b-[#4f46e5]">
                  <div className={`w-20 h-20 ${action.color} rounded-[2rem] flex items-center justify-center mb-8`}>{action.icon}</div>
                  <h3 className="text-2xl font-black text-slate-900 mb-4">{action.title}</h3>
                  <p className="text-slate-500 font-semibold mb-6">{action.description}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeStep === 'config' && (
          <div className="max-w-4xl mx-auto bg-white rounded-[3rem] shadow-2xl p-12 border border-slate-100 animate-in fade-in">
            <div className="flex items-center justify-between mb-8">
              <h2 className="text-3xl font-black text-slate-900 tracking-tight">Configurar Cruzamento</h2>
              <div className="flex gap-2">
                <span className="bg-indigo-100 text-indigo-700 text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-wider">Passo 1: Base</span>
                <span className="bg-slate-100 text-slate-400 text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-wider">Passo 2: Busca</span>
              </div>
            </div>

            <div className="border-[4px] border-dashed border-slate-100 rounded-[3rem] p-16 flex flex-col items-center justify-center bg-slate-50/40 hover:bg-slate-50 transition-all group mb-12">
              <UploadCloud className="w-20 h-20 text-indigo-200 mb-8 group-hover:text-[#4f46e5] transition-colors" />
              <input type="file" id="multi-file" className="hidden" multiple onChange={handleFileChange} />
              <label htmlFor="multi-file" className="bg-[#4f46e5] text-white px-12 py-5 rounded-2xl font-black cursor-pointer hover:bg-[#4338ca] shadow-xl">Anexar Relatórios</label>
              <p className="mt-6 text-slate-400 font-bold text-sm">O primeiro arquivo anexado será sua BASE FIXA.</p>
            </div>

            {files.length > 0 && (
              <div className="space-y-10">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                  {files.map((f, i) => (
                    <div key={i} className={`relative flex items-center justify-between p-6 rounded-[2rem] border-2 ${i === 0 ? 'border-indigo-500 bg-indigo-50/50 shadow-lg' : 'border-slate-100 bg-white'} transition-all`}>
                      <div className="flex items-center gap-4 overflow-hidden">
                        {i === 0 ? (
                          <div className="bg-indigo-500 p-2 rounded-xl text-white shadow-md"><Anchor className="w-5 h-5" /></div>
                        ) : (
                          <div className="bg-slate-100 p-2 rounded-xl text-slate-400"><FileText className="w-5 h-5" /></div>
                        )}
                        <div className="flex flex-col overflow-hidden">
                          <span className="text-[10px] font-black uppercase tracking-widest text-indigo-400">{i === 0 ? 'Base de Dados' : 'Relatório de Busca'}</span>
                          <span className="text-sm font-bold text-slate-800 truncate">{f.name}</span>
                        </div>
                      </div>
                      <button onClick={() => setFiles(prev => prev.filter((_, idx) => idx !== i))} className="p-2 hover:bg-red-50 text-slate-300 hover:text-red-500 rounded-lg transition-colors"><X className="w-5 h-5" /></button>
                    </div>
                  ))}
                </div>

                <div className="space-y-4">
                  <label className="text-xs font-black uppercase text-slate-400 tracking-widest ml-4">Instrução de Auditoria</label>
                  <textarea value={instruction} onChange={e => setInstruction(e.target.value)} className="w-full bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] p-8 min-h-[160px] focus:border-[#4f46e5] focus:bg-white outline-none transition-all font-semibold text-lg" placeholder="O que deseja extrair do segundo relatório? Ex: 'Busque o Valor de Comissão e a Data de Pagamento para os CPFs da Base'" />
                </div>

                <button onClick={handleProcess} className="w-full bg-slate-900 text-white py-6 rounded-3xl font-black text-xl hover:bg-black shadow-2xl flex items-center justify-center gap-4 transition-all">
                  Processar com Alta Precisão <ChevronRight className="w-6 h-6" />
                </button>
              </div>
            )}
          </div>
        )}

        {activeStep === 'processing' && (
          <div className="max-w-2xl mx-auto py-24 text-center space-y-12 animate-in fade-in">
            <div className="relative w-64 h-64 mx-auto">
              <div className="absolute inset-0 border-[20px] border-slate-100 rounded-full"></div>
              <div className="absolute inset-0 border-[20px] border-[#4f46e5] rounded-full border-t-transparent animate-spin"></div>
              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <Loader2 className="w-16 h-16 text-[#4f46e5] animate-pulse" />
                <span className="text-5xl font-black text-slate-900 mt-2 tracking-tighter">{Math.round((progress.current / (progress.total || 1)) * 100)}%</span>
              </div>
            </div>
            <div className="space-y-4">
              <h3 className="text-4xl font-black text-slate-900 tracking-tight">Auditando Dados</h3>
              <p className="text-slate-500 text-xl font-medium">{progress.phase}</p>
            </div>
          </div>
        )}

        {activeStep === 'result' && result && (
          <div className="w-full animate-in fade-in duration-700">
            {/* Toolbar Full Width */}
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-8 px-12 mb-12">
              <div className="space-y-2">
                <div className="flex items-center gap-3">
                   <div className="bg-green-100 p-2 rounded-xl text-green-600"><CheckCircle className="w-6 h-6" /></div>
                   <h2 className="text-5xl font-black text-slate-900 tracking-tighter">Resultado Final</h2>
                </div>
                <p className="text-slate-500 text-lg font-bold ml-1">Relatório Base consolidado com informações do secundário.</p>
              </div>
              <div className="flex flex-wrap items-center gap-4">
                <div className="relative group min-w-[500px]">
                  <Search className="absolute left-6 top-1/2 -translate-y-1/2 w-6 h-6 text-slate-400 group-focus-within:text-indigo-600 transition-colors" />
                  <input type="text" placeholder="Filtrar registros na tela inteira..." className="w-full bg-white border-2 border-slate-100 rounded-3xl py-5 pl-16 pr-8 font-bold outline-none focus:border-[#4f46e5] shadow-sm focus:shadow-2xl transition-all text-lg" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                </div>
                <button onClick={() => setShowColumnSettings(!showColumnSettings)} className={`p-5 rounded-3xl border-2 transition-all ${showColumnSettings ? 'bg-slate-900 text-white border-slate-900' : 'bg-white border-slate-100 text-slate-400'}`}><Settings2 className="w-7 h-7" /></button>
                <button onClick={downloadExcel} className="px-12 py-5 bg-green-600 text-white font-black rounded-3xl hover:bg-green-700 shadow-2xl flex items-center gap-3 text-xl transition-transform active:scale-95"><Download className="w-6 h-6" /> Exportar</button>
              </div>
            </div>

            {showColumnSettings && (
              <div className="bg-white p-10 rounded-[3rem] border-2 border-indigo-50 shadow-2xl mx-12 mb-12 animate-in slide-in-from-top-4">
                <h4 className="text-xs font-black uppercase text-slate-400 mb-8 tracking-[0.3em] flex items-center gap-3"><Filter className="w-4 h-4" /> Configurar Visibilidade</h4>
                <div className="flex flex-wrap gap-3">
                  {result.headers.map(h => (
                    <button key={h} onClick={() => toggleColumn(h)} className={`px-6 py-3 rounded-2xl text-sm font-black border-2 transition-all flex items-center gap-3 ${visibleColumns.includes(h) ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'bg-slate-50 border-slate-100 text-slate-300'}`}>
                      {visibleColumns.includes(h) ? <Eye className="w-5 h-5" /> : <EyeOff className="w-5 h-5" />} {h}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {/* Tabela Full Width */}
            <div className="bg-white border-y border-slate-200 shadow-sm overflow-hidden w-full mb-16">
              <div className="max-h-[75vh] overflow-auto custom-scrollbar">
                <table className="w-full text-left border-collapse table-auto">
                  <thead className="sticky top-0 bg-slate-900 text-white z-20">
                    <tr>
                      {result.headers.filter(h => visibleColumns.includes(h)).map(h => (
                        <th key={h} className="p-0">
                          <button onClick={() => handleSort(h)} className={`w-full text-left px-12 py-10 text-[12px] font-black uppercase tracking-[0.25em] flex items-center gap-4 hover:bg-white/10 transition-colors ${sortConfig.key === h ? 'text-indigo-400' : ''}`}>
                            {h} 
                            <div className="flex flex-col">
                              {sortConfig.key === h && sortConfig.direction === 'asc' ? <ArrowUp className="w-4 h-4" /> : 
                               sortConfig.key === h && sortConfig.direction === 'desc' ? <ArrowDown className="w-4 h-4" /> : 
                               <ArrowUpDown className="w-4 h-4 opacity-20" />}
                            </div>
                          </button>
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {filteredAndSortedData.map((row, i) => (
                      <tr key={i} className="hover:bg-indigo-50/30 transition-colors group">
                        {result.headers.filter(h => visibleColumns.includes(h)).map(h => (
                          <td key={`${i}-${h}`} className="px-12 py-8 text-base font-bold text-slate-700 group-hover:text-slate-900 transition-colors">
                            {typeof row[h] === 'number' ? row[h].toLocaleString('pt-BR', { minimumFractionDigits: 2 }) : (row[h] || "-")}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            {/* Registros não cruzados */}
            {result.unmatchedRecords && result.unmatchedRecords.length > 0 && (
              <div className="mx-12 mb-20 space-y-8 animate-in slide-in-from-bottom-8">
                <div className="flex items-center gap-4 text-red-600 bg-red-50 p-6 rounded-[2.5rem] w-fit pr-12 border border-red-100">
                  <AlertTriangle className="w-10 h-10" />
                  <div>
                    <h3 className="text-2xl font-black uppercase tracking-tight">Não Reconciliados</h3>
                    <p className="text-red-600/70 font-bold">Estes registros estão no arquivo de busca, mas não existem na sua base.</p>
                  </div>
                </div>
                <div className="bg-white border-2 border-red-100 rounded-[3rem] overflow-hidden shadow-2xl shadow-red-100/50">
                  <table className="w-full text-left">
                    <thead className="bg-red-50/50 text-red-900 text-[11px] font-black uppercase tracking-[0.2em]">
                      <tr>
                        <th className="px-12 py-6">Entidade / Nome</th>
                        <th className="px-12 py-6">Motivo da Exclusão</th>
                        <th className="px-12 py-6">Origem do Dado</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-red-50">
                      {result.unmatchedRecords.map((rec, i) => (
                        <tr key={i} className="hover:bg-red-50/30">
                          <td className="px-12 py-6 text-base font-black text-red-900">{rec.name || rec.cpf || "Identificador Ausente"}</td>
                          <td className="px-12 py-6 text-sm font-semibold text-red-600/80 italic">{rec.reason}</td>
                          <td className="px-12 py-6 text-[10px] font-black text-red-400 uppercase tracking-widest">{rec.source}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {result.summary && (
              <div className="mx-12 p-16 bg-slate-900 text-slate-200 rounded-[4rem] shadow-2xl relative overflow-hidden mb-20">
                <div className="absolute top-0 right-0 p-12 opacity-5"><Database className="w-64 h-64 text-indigo-400" /></div>
                <div className="relative z-10 flex gap-10 items-start">
                  <div className="p-5 bg-indigo-500/20 rounded-3xl"><Info className="w-10 h-10 text-indigo-400" /></div>
                  <div className="space-y-4 max-w-4xl">
                    <h5 className="text-indigo-400 text-[11px] font-black uppercase tracking-[0.4em]">Relatório de Auditoria IA</h5>
                    <p className="text-2xl font-medium leading-relaxed italic text-white/90">"{result.summary}"</p>
                  </div>
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 12px; height: 12px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #f8fafc; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 20px; border: 4px solid #f8fafc; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #94a3b8; }
        table { border-spacing: 0; }
        .max-w-none { max-width: 100vw !important; width: 100% !important; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  FileText, 
  Search, 
  CheckCircle, 
  Download, 
  ChevronRight, 
  FileSpreadsheet, 
  Loader2, 
  Zap, 
  X, 
  UploadCloud, 
  Info, 
  Settings2, 
  Eye, 
  EyeOff, 
  Database, 
  Calculator, 
  UserCheck, 
  ArrowLeft, 
  ArrowUpDown, 
  ArrowUp, 
  ArrowDown, 
  Filter,
  Split,
  AlertTriangle,
  Anchor,
  Wand2
} from 'lucide-react';
import * as XLSX from 'xlsx';

import { FileMetadata, ProcessingResult, FileType } from './types';
import { fileToBase64, parseExcel, extractPdfTextInChunks } from './utils/fileUtils';
import { extractDataFromReport } from './services/geminiService';

const QUICK_ACTIONS = [
  {
    id: 'consolidate',
    title: 'Consolidar Planilhas',
    description: 'Una múltiplos arquivos em uma tabela mestre buscando Nome, CPF e Valores.',
    icon: <FileSpreadsheet className="w-8 h-8 text-green-600" />,
    instruction: 'Pegue o Relatório 1 como base. No Relatório 2, procure por Nome ou CPF e traga os valores adicionais solicitados.',
    color: 'bg-green-50'
  },
  {
    id: 'commission',
    title: 'Cálculo de Comissões',
    description: 'Identifica e aplica fórmulas (V. Geral - Folha - DSR) gerando Excel nativo.',
    icon: <Calculator className="w-8 h-8 text-indigo-600" />,
    instruction: 'Relatório 1 é a base. Calcule a COMISSAO subtraindo FOLHA e DSR do VALOR_GERAL que está no Relatório 2.',
    color: 'bg-indigo-50'
  },
  {
    id: 'compare',
    title: 'Auditoria de Cruzamento',
    description: 'Verifique se os dados do Relatório 2 batem com sua Base oficial.',
    icon: <Split className="w-8 h-8 text-red-600" />,
    instruction: 'Compare os registros. Mantenha a Base (Relatório 1) e aponte divergências de valores encontradas no Relatório 2.',
    color: 'bg-red-50'
  },
  {
    id: 'adjust',
    title: 'Ajustar Excel',
    description: 'Filtre, limpe ou reorganize colunas e informações conforme sua necessidade.',
    icon: <Wand2 className="w-8 h-8 text-amber-600" />,
    instruction: 'Analise o arquivo e ajuste conforme o seguinte critério: [DESCREVA AQUI O QUE DESEJA MANTER OU MUDAR]',
    color: 'bg-amber-50'
  }
];

const App: React.FC = () => {
  const [activeStep, setActiveStep] = useState<'start' | 'config' | 'processing' | 'result'>('start');
  const [files, setFiles] = useState<FileMetadata[]>([]);
  const [instruction, setInstruction] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, phase: '' });

  const [result, setResult] = useState<ProcessingResult | null>(null);
  const [visibleColumns, setVisibleColumns] = useState<string[]>([]);
  const [showColumnSettings, setShowColumnSettings] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState<{ key: string; direction: 'asc' | 'desc' | null }>({ key: '', direction: null });

  useEffect(() => {
    if (result && result.data.length > 0) {
      setVisibleColumns(result.headers);
    }
  }, [result]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFiles = e.target.files;
    if (selectedFiles) {
      const newFiles: FileMetadata[] = Array.from(selectedFiles).map((f: File) => {
        let detectedType: FileType = 'unknown';
        const name = f.name.toLowerCase();
        if (name.endsWith('.pdf')) detectedType = 'pdf';
        else if (name.endsWith('.xlsx') || name.endsWith('.xls')) detectedType = 'excel';
        else if (f.type.includes('image')) detectedType = 'image';
        return { name: f.name, size: f.size, type: detectedType, raw: f };
      });
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const handleProcess = async () => {
    if (files.length === 0) return;
    setIsProcessing(true);
    setActiveStep('processing');

    try {
      let allExtractedText = "";
      let imageParts: any[] = [];
      for (let idx = 0; idx < files.length; idx++) {
        const file = files[idx];
        setProgress({ current: idx + 1, total: files.length, phase: `Analisando: ${file.name}...` });
        if (file.type === 'pdf') {
          const chunks = await extractPdfTextInChunks(file.raw, 100);
          allExtractedText += `\n[ARQUIVO ${idx+1} - ${idx === 0 ? 'RELATÓRIO BASE' : 'RELATÓRIO ADICIONAL'}]: ${chunks.join("\n")}`;
        } else if (file.type === 'excel') {
          allExtractedText += `\n[ARQUIVO ${idx+1} - ${idx === 0 ? 'RELATÓRIO BASE' : 'RELATÓRIO ADICIONAL'}]: ${await parseExcel(file.raw)}`;
        } else if (file.type === 'image') {
          const b64 = await fileToBase64(file.raw);
          imageParts.push({ inlineData: { data: b64, mimeType: file.raw.type } });
        }
      }
      const res = await extractDataFromReport(instruction, imageParts, allExtractedText);
      setResult(res);
      setActiveStep('result');
    } catch (err: any) {
      setActiveStep('config');
    } finally {
      setIsProcessing(false);
    }
  };

  const handleSort = (key: string) => {
    let direction: 'asc' | 'desc' | null = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') direction = 'desc';
    else if (sortConfig.key === key && sortConfig.direction === 'desc') direction = null;
    setSortConfig({ key, direction });
  };

  const toggleColumn = (column: string) => {
    setVisibleColumns(prev => 
      prev.includes(column) ? prev.filter(c => c !== column) : [...prev, column]
    );
  };

  const filteredAndSortedData = useMemo(() => {
    if (!result) return [];
    let data = [...result.data];
    if (searchTerm) {
      const lowerSearch = searchTerm.toLowerCase();
      data = data.filter(row => Object.values(row).some(val => String(val).toLowerCase().includes(lowerSearch)));
    }
    if (sortConfig.key && sortConfig.direction) {
      data.sort((a, b) => {
        const valA = a[sortConfig.key];
        const valB = b[sortConfig.key];
        if (typeof valA === 'number' && typeof valB === 'number') return sortConfig.direction === 'asc' ? valA - valB : valB - valA;
        const strA = String(valA || '').toLowerCase();
        const strB = String(valB || '').toLowerCase();
        return sortConfig.direction === 'asc' ? strA.localeCompare(strB) : strB.localeCompare(strA);
      });
    }
    return data;
  }, [result, searchTerm, sortConfig]);

  const downloadExcel = () => {
    if (!result) return;

    const wb = XLSX.utils.book_new();

    // Aba 1: Dados Consolidados / Ajustados
    const ws_data = [result.headers, ...result.data.map(row => result.headers.map(h => row[h]))];
    const ws_consolidated = XLSX.utils.aoa_to_sheet(ws_data);
    XLSX.utils.book_append_sheet(wb, ws_consolidated, "Relatório Processado");

    // Aba 2: Registros Não Encontrados (se houver)
    if (result.unmatchedRecords && result.unmatchedRecords.length > 0) {
      const unmatched_headers = ["Identificador (Nome/CPF)", "Motivo da Exclusão", "Origem do Dado"];
      const unmatched_data = [
        unmatched_headers,
        ...result.unmatchedRecords.map(rec => [
          rec.name || rec.cpf || "N/A",
          rec.reason || "Não encontrado na base ou excluído por regra",
          rec.source || "Relatório Secundário"
        ])
      ];
      const ws_unmatched = XLSX.utils.aoa_to_sheet(unmatched_data);
      XLSX.utils.book_append_sheet(wb, ws_unmatched, "Itens Fora da Tabela");
    }

    XLSX.writeFile(wb, `relatorio_smart_${Date.now()}.xlsx`);
  };

