export default App;

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ProcessingResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const cleanJsonResponse = (text: string): string => {
  let cleaned = text.trim();
  cleaned = cleaned.replace(/^```[a-zA-Z]*\n?/gm, "").replace(/```$/gm, "");
  return cleaned.trim();
};

export const extractDataFromReport = async (
  userInstruction: string,
  fileParts: { inlineData: { data: string; mimeType: string } }[],
  textContent?: string
): Promise<ProcessingResult> => {
  const model = 'gemini-3-pro-preview';

  const systemInstruction = `
    Você é um Engenheiro de Dados e Auditor Especialista em Conciliação e Transformação de Dados.
    Sua missão é processar relatórios com precisão cirúrgica, seguindo as regras abaixo:

    CENÁRIO 1: AJUSTE DE UM ÚNICO RELATÓRIO
    - Se apenas um arquivo for fornecido ou o usuário quiser "ajustar", você deve reorganizar, filtrar ou limpar os dados conforme a instrução.
    - Mantenha a fidelidade aos dados numéricos.

    CENÁRIO 2: CRUZAMENTO/CONSOLIDAÇÃO (DOIS OU MAIS RELATÓRIOS)
    1. ARQUIVO ÂNCORA (RELATÓRIO 1): Este é o seu mestre. Toda linha deste arquivo deve estar presente no resultado final.
    2. BUSCA DE DADOS: Localize os mesmos indivíduos no Relatório 2 usando CPF ou Nome Completo.
    3. PRECISÃO: Extraia os campos que o usuário solicitar (ex: "comissão", "vendas") mapeando corretamente as colunas do Relatório 2.
    4. REGISTROS ÓRFÃOS: Se houver alguém no Relatório 2 que NÃO está no Relatório 1, adicione-os obrigatoriamente no campo "unmatchedRecords".
    5. VALORES: Transforme textos de moeda em números (Ex: "R$ 10,00" -> 10.00).

    ESTRUTURA JSON OBRIGATÓRIA:
    {
      "data": [
        { "Campo1": "...", "Campo2": 0.00 }
      ],
      "headers": ["Campo1", "Campo2"],
      "unmatchedRecords": [
        { "name": "...", "reason": "Motivo da exclusão ou não cruzamento", "source": "Relatório de origem" }
      ],
      "summary": "Resumo curto do que foi feito."
    }
  `;

  const finalPrompt = `
    INSTRUÇÕES DO USUÁRIO: ${userInstruction}

    RELATÓRIOS PARA ANÁLISE:
    ${textContent || 'Analise as imagens e tabelas fornecidas abaixo.'}

    IMPORTANTE: Se o usuário pediu para "ajustar", "filtrar" ou "limpar", siga exatamente a descrição dele sobre quais colunas manter.
  `;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model,
      contents: { parts: [...fileParts, { text: finalPrompt }] },
      config: { 
        systemInstruction, 
        responseMimeType: "application/json", 
        temperature: 0,
        thinkingConfig: { thinkingBudget: 4000 }
      }
    });

    const text = response.text;
    if (!text) throw new Error("Resposta vazia da IA");

    const result = JSON.parse(cleanJsonResponse(text));
    return {
      data: result.data || [],
      headers: result.headers || [],
      summary: result.summary,
      unmatchedRecords: result.unmatchedRecords || [],
      formulas: result.formulas || {}
    };
  } catch (error) {
    console.error("Erro na extração Gemini:", error);
    return { 
      data: [], 
      headers: [], 
      summary: "Não foi possível processar. Verifique se as instruções estão claras." 
    };
  }
};
